import{_ as a,o as e,c as s,a2 as r}from"./chunks/framework.BS3ZfcoS.js";const q=JSON.parse('{"title":"心理","description":"","frontmatter":{"title":"心理","author":"","collection":"中国智慧","series_order":3,"total_chars":90743},"headers":[],"relativePath":"wisdom/psychology.md","filePath":"wisdom/psychology.md"}'),h={name:"wisdom/psychology.md"};function o(t,p,i,l,d,n){return e(),s("div",null,[...p[0]||(p[0]=[r('<h2 id="s-558" tabindex="-1">第三篇 心理与修行 <a class="header-anchor" href="#s-558" aria-label="Permalink to &quot;第三篇 心理与修行 {#s-558}&quot;">​</a></h2><p><em>情绪管理、精神内耗、修行修心、改命方法等</em></p><h3 id="s-559" tabindex="-1">第一次调风水之境煞（术） <a class="header-anchor" href="#s-559" aria-label="Permalink to &quot;第一次调风水之境煞（术） {#s-559}&quot;">​</a></h3><p>《金刚经》说，‘无法相，亦无非法相’，‘所谓佛法者，即非佛法’，‘实相者，即是非相’等等，反复强调不要着于相</p><p>除了一些摆放方面小的不足之外，最大的问题在于客厅的装饰</p><p>我给蔡总一一的指出了问题所在，以及背后的逻辑，并建议了化解的办法</p><p>艺术来源于生活，镜子在风水上来讲，确实禁忌比较多</p><p>甚至这种瞬间的恐惧只是在潜意识里一晃而过，快到大脑都没意识到，伤害就已经造成了</p><p>同时，心肾相交，肾受损直接影响心神，包括心脏和精神两方面，比如心血管类疾病，以及神经衰弱等情况</p><p>尤其是如果有光照到镜子上，再反射出来，形成刀光剑影，还容易在潜意识里接收到有血光之灾的心理暗示</p><p>家里最好不要有大面积的镜子，小镜子用完也尽量收起来，避免反光成煞</p><p>二是因为他还没验证出效果，无功不受禄</p><p>第一，之所以请你帮我看，是因为我相信自己看人的眼光</p><p>第二，无论如何，也不能让师父白忙活，就当是讨个彩头儿</p><p>蔡总一再的推让，他说</p><p>不如这样，彩头我收下，等一个月之后，你的身体确实有改善了，你再还谢礼</p><p>不论是因为 还是因为，我以后一直没再缺过钱</p><h3 id="s-560" tabindex="-1">被家暴（术） <a class="header-anchor" href="#s-560" aria-label="Permalink to &quot;被家暴（术） {#s-560}&quot;">​</a></h3><p>这是根据相学，多层面做出的推理</p><p>相学，除了咱们常说的面相和手相，还包括身相，声相，动相等等</p><p>细分的话，动相还分为站相，坐相，行相，睡相，吃相等</p><p>白志高在面相上，最大的特点就是皮肤很薄，薄到能看到很多的细纹</p><p>道家和佛家，以及各灵修门派，都注重呼吸，一方面是因为养生，一方面也是可以调整气运</p><p>气沉丹田，上虚下实，声沉，行稳，气运通达</p><p>（胜是承担的意思）</p><p>多年以后，我再次见到白志高时，他从头到脚都是福相，这个以后再细说</p><p>大哥，你可真行，又被你算准啦</p><p>我也泛起了熊熊的八卦之心</p><p>我心里并没有可怜她，也没有幸灾乐祸的想法</p><p>从我搬走那一刻，就把所有的恩恩怨怨，都割舍了</p><h3 id="s-561" tabindex="-1">创业危险，打工安全？（术） <a class="header-anchor" href="#s-561" aria-label="Permalink to &quot;创业危险，打工安全？（术） {#s-561}&quot;">​</a></h3><p>好不好吃的，也算是开了眼了</p><p>你抓紧时间抹一点酱油在烫伤部位，就不会起泡了</p><p>看在钱的面子上，你以后别再为这事儿难过了呗</p><p>她的这个心结打开了，我们今天就算没白来</p><p>据说90%以上的创业者，最后都失败了</p><p>创业失败了，也可以再注册一家公司重新创业呀</p><p>那如果不创业，工作到四五十岁时，万一公司倒闭了，自己曾经引以为傲的技术，又被时代给淘汰了，找不到新的工作，那赔进去的，可能就是自己的半辈子啦</p><h3 id="s-562" tabindex="-1">人人都是神经病（术） <a class="header-anchor" href="#s-562" aria-label="Permalink to &quot;人人都是神经病（术） {#s-562}&quot;">​</a></h3><p>这个古拉，看起来除了阳气弱一点，并没有什么大问题</p><p>又盯了很久，好像在纠结要不要说</p><p>她用哀怨的眼神瞅着我，可能连让我滚的力气都没有了</p><p>你没病，就是想的太多了，最多算是有点心理疾病</p><p>这些病有一个共同的特征，就是大脑不受自己的控制</p><p>也就是俗话说的，想太多</p><p>很多人会轻飘飘的说，不要想那么多就行了呗</p><p>安静的打坐3分钟，就会发现，大脑根本不受自己控制的，会不断冒出来各种的想法，比自己平时能意识到的，多的多的多</p><p>你这话说得好，听起来很有道理</p><h3 id="s-563" tabindex="-1">洗心养神功（术） <a class="header-anchor" href="#s-563" aria-label="Permalink to &quot;洗心养神功（术） {#s-563}&quot;">​</a></h3><p>这种天才型思维的人，我可不敢妄自揣测</p><p>再夹盘子里的菜的时候，他的口水就会沾到菜上</p><p>也就是说，除了洁癖，你没什么其他症状是吗</p><p>在溜达的过程中，你把所有的注意力放在你依次看到的颜色或形状上，比如，红色，黄色，灰色……或者三角形，正方形，五角形，多边形……选择其一就行</p><p>只需要把注意力，放在物质世界里就行</p><p>世界上，最快乐的人，就是小宝宝</p><p>那种发自内心的笑意，会带着治愈的光</p><p>注意力，就是神魂</p><p>我们说一个人走神儿了，魂飘万里，就是指注意力不在了</p><p>注意力，就是生命力</p><p>越具有生命力的人，注意力越集中</p><p>反之，生命力散失的人，注意力也随之消散</p><p>注意力，也是钱财</p><p>你的注意力在漂亮衣服上，那你的钱就跟着注意力一起，被漂亮衣服收割走</p><p>你的注意力在美食上，你的钱财就会被美食消灭</p><p>所有的商家，不论是做魔性的洗脑式广告，还是请明星代言，无非也就是为了吸引更多的注意力</p><p>注意力在哪，钱就在哪儿，生命力就在哪儿</p><p>能长期吸引注意力的企业，是充满了活力和生命力的企业</p><h3 id="s-564" tabindex="-1">注意力就是生命力（道） <a class="header-anchor" href="#s-564" aria-label="Permalink to &quot;注意力就是生命力（道） {#s-564}&quot;">​</a></h3><p>把注意力放在自己身上，我们会感觉充满力量</p><p>把注意力放在无聊的小视频上，我们会感觉空虚疲惫</p><p>把注意力放在实实在在的物体上，我们会感觉真切踏实</p><p>把注意力放在虚无缥缈的想法上，我们会感觉陷入梦魇</p><p>她说的都对，但人不能活在真空里</p><p>问题本身，就是答案</p><p>就好像，除非你亲自去闻一下栀子花的香味，否则，再多华丽的语言，也无法表达出那份清甜又纯净，还带着一点儿小倔强的香味</p><p>古拉在前面慢慢的走着，越走越沉静，在拐角的小花园边上，她停了下来，似乎被美景吸引到流连忘返</p><p>需要的话，我再带你两天，巩固一下也行</p><p>她被我宠坏了，三合先生，您多包涵</p><p>三合先生，请问古拉是哪方面的原因</p><h3 id="s-565" tabindex="-1">咱俩不是同一个物种 <a class="header-anchor" href="#s-565" aria-label="Permalink to &quot;咱俩不是同一个物种 {#s-565}&quot;">​</a></h3><p>我再陪她一起，多练习两天也行，把这种行为方式，变成一种习惯</p><p>我们愉快的约好了时间，第二天，定的上午</p><p>再往后一天是周一，定在我下班之后</p><p>第二天见面时，她已经会主动挑起话题了</p><p>她这个称呼，多少带着戏谑的意思</p><p>只要开始做，这就是注入了阳，力量就产生了</p><p>任何时候，都要阴阳平衡</p><p>钱，光进不出，那就成个储钱罐了，早晚都是给别人留着的</p><p>第三天，我和古拉出门的时候，陈太太小心翼翼的问</p><p>陈太太不可思议的问</p><p>可能是见了太久古拉孤僻冷酷的样子，一下子不适应</p><p>古拉小时候，就是这样无忧无虑的</p><p>六根指的是，眼耳鼻舌身意</p><p>不，就要，拜师算什么，嫁给你都行</p><p>……你是小仙女，我就是个俗人</p><h3 id="s-566" tabindex="-1">修行的本质（道） <a class="header-anchor" href="#s-566" aria-label="Permalink to &quot;修行的本质（道） {#s-566}&quot;">​</a></h3><p>我前面的大哥鼓掌尤为热烈，仿佛要将全身的力量都倾注其中，恨不得要站起来的样子</p><p>无优禅师唱诵结束许久，大家仍沉浸在这美妙的禅境中</p><p>很多人以为，修行，就是打坐念佛</p><p>修的，就是我们日常的行为</p><p>无优禅师用简简单单的语言，就把高深的道理，讲的深入浅出</p><p>无优禅师的每一句话，都如同甘露般滋润着我们的心田，让我们对修行，有了更深刻的理解</p><p>这一刻的平和与极乐并不是终点，而是我们修行路上的一个新起点</p><h3 id="s-567" tabindex="-1">佛医断食治病（道/术） <a class="header-anchor" href="#s-567" aria-label="Permalink to &quot;佛医断食治病（道/术） {#s-567}&quot;">​</a></h3><p>佛医将病分为两种，一种是四大不调，一种是业力得病</p><p>与催吐法结合，效果更甚，可有效的消除体内的积滞</p><p>特别需要注意的是，断食结束不要立即吃饭，先喝几天米汤</p><p>如果是业报病，最有效的两个办法，一个是忏悔，一个是布施</p><p>布施又分为：财布施，法布施，无畏布施</p><p>财布施，比较简单，就是不贪</p><p>法布施，传播智慧</p><p>无畏布施，解除恐惧，给人信心和希望</p><p>这三种布施，功德最大的是法布施，把离苦得乐、解脱根本痛苦的道理，传播给大家</p><p>我们脚踏实地，先把当下做好，不要总想着神儿了鬼儿了的</p><p>很可能是你先惹火了人家，骂了人家或打了人家，这都是现世报，扯什么前世</p><p>这段时间，我一直很自责，不明白我虔诚修行这么多年，为什么连婚姻都保不住</p><p>我一直觉得，我不论是婚姻还是修行，都是个失败者，在自我否定中走不出来</p><p>一激动，就没控制好情绪</p><p>蔡总此刻似乎还沉浸在某种情绪中</p><p>蔡总不可思议的问</p><p>现在也有很多修行人，喜欢用音乐疗法来调理身体</p><p>顾名思义，就是声音形成的煞气，对人体的健康和运势造成的影响</p><p>在选择房屋住址时，看风水，除了看形之外，还要非常注意对声音的考量</p><h3 id="s-568" tabindex="-1">《地藏菩萨本愿经》改命 <a class="header-anchor" href="#s-568" aria-label="Permalink to &quot;《地藏菩萨本愿经》改命 {#s-568}&quot;">​</a></h3><p>我点点头，目光缓缓扫过在场的众人，再次确认这是大家共同认可的最终决定</p><p>我示意阿茵先净手静心，随后恭敬的抽取了一张签文</p><p>翻开师父的笔记，我找到了对应的签词</p><p>这就是报恩宝宝的故事吗</p><p>万法皆空，因果不空</p><p>因与果，相辅相成，互为因果</p><p>我们无法改变过去的因，但我们可以通过调整现在的果，来影响未来的因，从而改善未来的果</p><p>佛、医、道，存在了几千年，必然有其存在的道理</p><p>我们可以从这三个方面，进行调整</p><p>首先，注意基本的养生习惯</p><p>也就是说，晚上和中午的12点前后，这两个时间段，尽量保持休息，闭目养神</p><p>这个我们以后会特别注意调整的</p><p>消除业障，积累善德，开启智慧</p><p>我们之前最多就是遇见寺庙进去拜拜，对经和咒了解的不多，不知道该读哪些内容</p><p>我建议你们每天诵读《地藏菩萨本愿经》，并将诵经的功德回向给孩子，以及十方法界的一切众生</p><p>平时念念佛号，比如地藏菩萨，观世音菩萨，释迦牟尼佛等</p><p>对于初学者来说，念佛菩萨名号是一个很好的开始</p><p>念经看起来很简单，但改变自己的习气，对治懈怠和业障，并不容易</p><p>佛经的力量难以估量，但刚开始诵读时，不太熟练，会有一点不容易，需要强大的愿力，才能坚持下去</p><p>《地藏菩萨本愿经》是一部包含深邃义理的经书，体现了佛菩萨的慈悲，以及对众生的护念</p><p>熟练读诵的话，一般也需要一个多小时</p><p>既然你们如此坚定，那我也跟你们一起，每日为宝宝念经祈福，直到他平安出生</p><h3 id="s-569" tabindex="-1">念头会影响基因的表达（道） <a class="header-anchor" href="#s-569" aria-label="Permalink to &quot;念头会影响基因的表达（道） {#s-569}&quot;">​</a></h3><p>三合先生，我代表我们全家人谢谢你</p><p>陈先生大概是没想到我会有此举，他声音略带哽咽道</p><p>初来时的压抑气氛，被大家这种齐心协力的信念冲淡了不少</p><p>我们暂且先不讲消业障积福报那么玄的方面，单从科学的角度来说，生物学家已经证实了，人的念头，会影响基因的表达</p><p>所有的物质，最后都分解到夸克，变成光的时候，是不是就是刚刚说的，万法皆空</p><p>她的心态真的是太好了</p><p>很多时候，人的怒气是源于把自己看的太重，认为自己对，别人不对</p><p>佛家讲十方法界，有情众生，是大的层面</p><p>接下来，我们谈谈小的层面儿的调整</p><p>家里的风水，有几个地方，最好能调整一下</p><p>事物都是相互感应的，什么样的命理，对应什么样的运势，对应着相匹配的风水</p><p>你或许会疑惑，他为什么会买这样的房子</p><p>因此，在调整的时候，有些人会感觉怪怪的，不如原来看着顺眼，不愿意调整</p><p>这就是每个人选择的人生路</p><h3 id="s-570" tabindex="-1">快乐的本质（道） <a class="header-anchor" href="#s-570" aria-label="Permalink to &quot;快乐的本质（道） {#s-570}&quot;">​</a></h3><p>没有人会一帆风顺，哪怕是命再好的人</p><p>人生快乐的根源，就是克服了困难，提升了对环境的掌控权</p><p>走两步，一个小屁墩儿坐下来，再摇摇晃晃的站起来，又乐的屁颠屁颠的</p><p>快乐的本质，就是：变成更优秀的自己</p><p>可以选择穿着脏衣服见客户，或者跟客户再约一个时间</p><p>陈总最先反映过来</p><p>很多人第一反应是指责外界</p><p>也就是说，除了穿着脏衣服去见客户，或者约客户改时间，还有其他选择</p><p>也就是说，是我，有意识或者无意识的，选择了这个结果</p><p>嫌麻烦，决定出门不带备用衣服，这也是自己的选择</p><p>他不能接受这种突发状况，最终导致合作没谈成</p><p>但安安静静的什么也不干，只听着彼此的呼吸，就感觉到很幸福，那确定就是真爱了</p><h3 id="s-571" tabindex="-1">记忆是可以遗传的（术） <a class="header-anchor" href="#s-571" aria-label="Permalink to &quot;记忆是可以遗传的（术） {#s-571}&quot;">​</a></h3><p>不知道我们，是不是因为祖先遗传的原因，现在也受影响</p><p>我很赞赏陈总这种严谨的科学思维</p><p>修行到一定程度，感知力会不一样</p><p>对于未修行的人来说，不太容易理解，我便没有深入解释，只是讲了一下需要用到的常识</p><p>南方，在八卦里用离卦来表示，五行为火</p><p>在风水上，南方适合低平开阔，或者有水</p><p>火，代表心脏，心情，火气，炎症</p><p>家宅火旺，对应头部疾步</p><p>同一栋楼，每个人的八字命理不一样，流年大运不一样，对应的具体事件不一样</p><p>但都没躲得开，离为火，所代表的这些事</p><p>针对阿茵一家人的命理特征，我给她们做了离火的化解</p><p>见他们有客人来，我这边也基本都安排好了，就打算跟大家告辞</p><p>这位是我们请来的师父，三合先生</p><p>本来阿隆可能没打算介绍，既然问到了，他只好说道</p><p>这句话翻译过来就是：说话很难听</p><p>大飞刚来，我如果现在走，他不走，难免会没头没脑说一些负面的言论，万一再动摇大家的信念</p><h3 id="s-572" tabindex="-1">走火入魔的修行者 <a class="header-anchor" href="#s-572" aria-label="Permalink to &quot;走火入魔的修行者 {#s-572}&quot;">​</a></h3><p>也就是说，你所谓的明天可能会死，不是身体有具体的问题，对吧</p><p>她飘了一个慈悲的眼神儿给我，好像在说：朽木不可雕也</p><p>于老板，我先不占用你的时间了，我单独跟她聊一聊</p><p>明天和意外，谁先到来</p><p>我听说修行人，讲求法布施</p><p>法布施，比财布施的功德还大，是吗</p><p>我就是在做法布施</p><p>人家是修行者，哪里会有男女之分</p><p>法布施，首先，得有人听你说，是吧</p><p>你要是老说死呀死的，把于老板吓着了，他都不敢用你，你还怎么布施</p><p>你这么超然物外的一个人，就算于老板不敢用你，你肯定也不怕，大不了回国嘛</p><p>她刚准备说话，我赶紧抢先开口</p><p>对，我就是这么想的，随缘嘛</p><p>是，但你回国的话，就不能给于老板法布施了，是不是</p><p>你如果先好好工作，先不着急布施，以后可能还有机会</p><p>再说了，如果拔太高，别人不理解你还不要紧</p><p>是是是，我先不讲法，我先好好工作</p><p>等以后再讲法，对吗</p><p>……一定要注意方式方法，宁可不讲，也千万不能让他人误解了佛法</p><p>我怕她过几天又给我惹麻烦，必须得一次性给她聊透了</p><p>比如，家里来客人了，他们临走时，我们会说：路上注意安全</p><p>但不能说：路上千万别被车撞死</p><p>可能想表达的都是，路上平安的意思</p><p>就算以后时机成熟了，你要布法，咱也别句句提死字</p><p>有道理，凡夫众生，要根据每个人的慧根深浅，酌情考虑</p><p>老板，我就是小地方来的，不会说话</p><p>老板，你再给我个机会试试</p><p>她就是修行修偏了，坏心眼儿倒没有</p><h3 id="s-573" tabindex="-1">意念联系 <a class="header-anchor" href="#s-573" aria-label="Permalink to &quot;意念联系 {#s-573}&quot;">​</a></h3><p>再问下去，肯定还有第三种</p><p>新加坡这么多人，每15年就要刨出来一遍，也太麻烦了吧</p><p>你的命理机缘，适合多接触一些不同的门派，融会贯通，才有大成</p><p>泰国一位大修行者，很多人称他为秉烛大师，最近在新加坡，你可以去拜访一下</p><p>龙婆，是 luang poh的音译，luang是指皇家、国家，por是父亲、长辈的意思</p><p>我对他的初始印象慢慢改观了：这个师兄，还是挺靠谱的</p><p>算了，刚刚的改观，草率了……</p><h3 id="s-574" tabindex="-1">能量引导术（道/术） <a class="header-anchor" href="#s-574" aria-label="Permalink to &quot;能量引导术（道/术） {#s-574}&quot;">​</a></h3><p>蜡烛油慢慢流淌，凝固在水面</p><p>心理学有个案例说，你越不要想粉红色的大象，就越容易想到</p><p>演员，越是提醒自己不要笑场的地方，他越容易笑场</p><p>不受压制的笑够了之后，下次就不容易再笑场了</p><p>比如，不要企图用意志力去做任何事</p><p>这就是能量引导术</p><p>因为强制改变，意味着不接纳</p><p>反抗，就是能量的消耗</p><p>再次感受一下自己的状态</p><p>再次感受一下，直到回归了宁静</p><p>每个人有每个人的苦恼</p><p>师父，我男朋友劈腿了，请您帮我做法，把他弄回来吧</p><h3 id="s-575" tabindex="-1">免费的小姐（术） <a class="header-anchor" href="#s-575" aria-label="Permalink to &quot;免费的小姐（术） {#s-575}&quot;">​</a></h3><p>我也不知道最后，星辰有没有解释清楚</p><p>她再也不用天天顶着红鼻子头儿了</p><p>吃饭时，我们先到了，坐在一起聊着天儿</p><p>额头窄小，还有褶皱</p><p>面相上，额头称为上庭，亦称天庭</p><p>代表着祖先，长辈，少年时期</p><p>也代表着智商和情商</p><p>（还有人将额头细分为天中，天庭，司空，中正</p><p>若凹凸狭窄，代表少年运差，不受双亲疼爱，智商低，性格老实，情商低，还很固执</p><p>我晚上还约了其他朋友喝酒，时间差不多了，我就先走了</p><p>她一马当先的走了出去</p><p>阿强一点儿没脾气，跟着星辰一起，走在最后面</p><p>我也不着痕迹的慢走了两步，悄悄竖起了八卦的耳朵</p><p>我没敢再回头，心中跑过了一大片的动物</p><p>星辰再也不敢找话题了，虽然，还是没走到地铁站</p><p>除了，再多说一个字，都怕惹出什么危险</p><h3 id="s-576" tabindex="-1">三元九运～抑郁/虚假（术） <a class="header-anchor" href="#s-576" aria-label="Permalink to &quot;三元九运～抑郁/虚假（术） {#s-576}&quot;">​</a></h3><p>你讲的道理是很清晰，就是……在措辞上，感觉有点儿……绕</p><p>我之前还以为你是算命大师呢</p><p>算命 ，基本都是骗钱的</p><p>在我师父眼中，算命更像是个贬义词</p><p>我只知道自己不要做什么，还没太想明白自己要做什么</p><p>从2024年开始，将正式进入三元九运的第九个运——离火运</p><p>先天运，从2017年开始就已经进入了</p><p>心理赋能，心灵倾听，情绪疗愈，这是大势所趋</p><p>大不了，你事后再收钱呗</p><p>等人家见效了，你再收钱</p><p>虽然我知道那种希望，是饮鸩止渴，但就是有期待</p><p>就是你说的那种感觉，心中空落落的</p><p>我感觉自己不再需要那种虚假的希望了</p><p>我希望，我再次被黑暗吞噬的时候，可以在你这里，买到光</p><p>你有空的话，跟我聊聊算命吧</p><p>算命是可以算准的，对吗</p><h3 id="s-577" tabindex="-1">算命心理学 <a class="header-anchor" href="#s-577" aria-label="Permalink to &quot;算命心理学 {#s-577}&quot;">​</a></h3><p>时间倒是有，但是我聊的算命，跟你说的那个算命，不一定是一件事儿哦</p><p>她很精准的收到了我的意思</p><p>那你能答应我，以后不要再去算命了吗</p><p>算命不是能算准吗</p><p>不，是不是骗子，都能算准</p><p>算命心理学，有人来问事儿</p><p>来捣乱的也没问题，不准是你心不诚，不诚不占</p><p>所以，算命没有不准的</p><p>听着是有道理，但是真的会有人冒充大师，这么干吗</p><p>那我是不是得再给你转个红包呀，前面那个红包转早了</p><p>红包就不用再转一个了，我以后打算写本书，你记得帮我点个五星好评就行</p><p>等我学完《英耀篇》，再回来跟你聊算命的事儿</p><p>业务一旦转起来，每天都有很多的事情忙</p><p>一看就是老实朴素、吃苦耐劳的人</p><h3 id="s-578" tabindex="-1">三个月的薪水（术） <a class="header-anchor" href="#s-578" aria-label="Permalink to &quot;三个月的薪水（术） {#s-578}&quot;">​</a></h3><p>吴昊业绩好不无道理，能在这么短的时间内，迅速调整一个人的时候心理状态，这除了努力，还有一半是靠天赋</p><p>我每天迷迷糊糊的，脑子里空空的</p><p>每天不论睡多久，总感觉很累</p><p>只要能治好，我以后一辈子都念着师父的好</p><p>这一下午的静思，还是有效果的</p><p>我跟钟雨订好了三个月之内，找时间和契机帮他调整</p><p>无条件的给予，只会助长他人的贪心和抱怨</p><p>从一开始就划出底线，不要期望有人有义务无条件的给予，反而会让彼此都感觉有边界感</p><p>抑郁症，情绪问题，也跟水有关</p><p>是五行的气场属性</p><p>也就是说，在风水上，正北见水了</p><p>但细节调整，不知道还有没有摆放其他犯煞的物品，要综合考虑</p><p>图片看不准方向，只能粗略的看</p><p>包括室外环境，比如路为水</p><h3 id="s-579" tabindex="-1">心理学的100不等于100（术） <a class="header-anchor" href="#s-579" aria-label="Permalink to &quot;心理学的100不等于100（术） {#s-579}&quot;">​</a></h3><p>……不用不用……那好吧……知道啦知道啦，我们在学习，晚一些再说哈</p><p>就是就是，大家一起玩，你给他发红包，我们不也得给呀</p><p>本来我也是说不用的，我姐说她有受益，理应给钱，这是个因果</p><p>行啦行啦，咱们开始讲大拇指吧</p><p>是的嘛，你别为难星辰了，再磨叽她们又该说咱娘们唧唧的了</p><p>行了，开始整大拇指吧</p><p>我收下了，这可就是我的了</p><p>再说了，跟你学了这么多，只要有一条好用，这点儿小钱，当学费也不吃亏</p><p>如果她们后悔了，你再退回去就是了，等于没给而已</p><p>人来到这世上，本来就是空着手来的</p><p>人的思维模式有欺骗性</p><p>然，此刻的牵挂，已经是一束成形的执念了</p><p>这算是人类心理上的一个bug吧</p><p>你把产品试用了，就会产生一种占有的心理，这个东西是我的，不想再退回去</p><p>再比如，很多人交男女朋友，即使不太合适，也不愿意分手</p><p>心理上有一种潜在的认知：这个人是我的，我就算不用，也不想让给别人</p><p>大多数人，宁可再多花70</p><p>刷单被骗的人，在第一次第二次，对方找各种借口不返钱的时候，就算心里有怀疑，但也不愿意接受这个损失</p><p>然后继续给对方汇钱，一直到拿不出钱来，不得不面对现实为止</p><p>刚刚不是说要讲大拇指吗</p><p>大拇指，上次海哥讲过的，直的性格刚硬，向后弯的为人随和，咱就不多重复了</p><p>我们聊聊，大拇指的长短</p><p>大拇指是五根手指中，最粗最壮的，代表人一生的福禄</p><p>难怪海哥第一次见到你的大拇指，就恋恋不舍的</p><p>大拇指代表祖先、长辈</p><p>大拇指修长的人，深得祖荫庇护，受长辈的偏爱，事业运旺，头脑聪明，学习能力强，做事很认真，富有行动力</p><p>我的大拇指，这不长的也挺完美的吗</p><p>我家虽然是农村，但我父母重女轻男，从小家里有好吃的，都先紧着我，我吃不了的才给我弟弟</p><p>琪儿的大拇指，不算特别长，但相对于她娇嫩的小手儿来说，也算得上是偏长</p><p>唯一的不足就是，后弯特别夸张，缺乏原则性</p><p>大拇指直，性格刚硬，是因为变通性差，有坚持想要维护的原则</p><p>一般五指并拢，大拇指指尖超过食指第三关节的一半，为长，不过线为短</p><h3 id="s-580" tabindex="-1">心理学的光环效应（术） <a class="header-anchor" href="#s-580" aria-label="Permalink to &quot;心理学的光环效应（术） {#s-580}&quot;">​</a></h3><p>我放慢语速，慢慢解释道：有些人，学预测，是为了去给人算命</p><p>而我们学预测，是为了看清未来的路</p><p>要想说的准，就需要花费很多的精力去计算</p><p>还要去背诵很多装点门面的东西，以此来显得自己学富五车</p><p>杜乐犹豫着：呃……好像有道理</p><p>道理我是懂了，但我为什么还是会觉得，算的精细的人，化解也更厉害呢</p><p>这也是心理学上的一个bug，叫光环效应，指以点概面的主观看法</p><p>真正优秀的大厨，可能就只会说：放油，倒酱油，注意火候</p><p>人会被骗，其实很多时候是光听他说了啥，没注意他做了啥</p><p>所以很多命理学家，预测的很准，但自己的日子却过得还不如一般人</p><p>要么就是，只擅长预测，但不擅长化解</p><p>遇到仙人的概率……如果不是爽文的主角，最好不要去博</p><p>我扶了扶额头：孔子说：巧言令色者，鲜矣仁</p><p>我忍不住给他点了个赞，总结太到位了：好多修行的人，都不怎么在意表面的东西，比如穿着打扮，比如花言巧语</p><p>修行的人，更看重内在</p><p>人如果太贪心，里外都想要，那心就太累了</p><p>咱们学易也是，花里胡哨的酷炫的东西，可以往边上放一放，把道理弄懂了，更实用</p><p>现在，大五婚的属相相害我也记住了，咱们接着说道小五婚吧</p><h3 id="s-581" tabindex="-1">光环效应的正面应用（术） <a class="header-anchor" href="#s-581" aria-label="Permalink to &quot;光环效应的正面应用（术） {#s-581}&quot;">​</a></h3><p>那先天八卦的数，先说到这儿</p><p>我们接着来说说后天八卦</p><p>后天八卦，是老爹老妈护着小女儿，躲在一边，在右边627的位置</p><p>中间是二哥二姐的主场，1和9的位置</p><p>大哥大嫂带着小弟占据左边青龙位，348</p><p>这样先天八卦和后天八卦的位置，对应的数字，对应的五行，对应的人物关系，都记住了吧</p><p>我把九宫图画了一条线，分为上下两部分：（评论见图）</p><p>……这个为什么，跟实用没关系，只跟原理有关系，还听吗</p><p>后天八卦讲的是生命的规律</p><p>生命产生的前提，是阴阳交合</p><p>这个跟地天泰的道理差不多，阴阳交媾（gou）万物生</p><p>这个行为的逻辑性太差，直男理解不了</p><p>前面聊到光环效应，大家会卷在面子工程里</p><p>那这个光环效应，我们能不能把它用在正向的方面</p><p>我一边暗自观察着，一边说道：任何事情，都有阴阳两面</p><p>光环效应也是，就看自己怎么用</p><p>再比如说我，你们会攻击我不会做饭吗</p><h3 id="s-582" tabindex="-1">识人之术（下） <a class="header-anchor" href="#s-582" aria-label="Permalink to &quot;识人之术（下） {#s-582}&quot;">​</a></h3><p>要看清一个人，更重要的是观神，也可以称为观气</p><p>老周，你到底算是哪门哪派的啊</p><p>他微不可见的轻轻摇了摇头：你又狭隘了哈</p><p>《说文解字》说：道，就是人们所走的路</p><p>指的是，好好看路</p><p>我们不要听他说了什么，更要看他做了什么</p><p>做同样的事，动机不一样，代表的是不一样的意思</p><p>喜怒不形于色的人，如果不是经过专业训练的，可以辅助微表情判断</p><p>这个时候，我会无意识的、微不可见的咬咬嘴唇</p><p>我很无语，我竟然又听懂了他要表达的意思</p><p>不用他翻译，我也知道，孔子这句话的意思是：嘴巴笨笨的人，木讷、迟钝，不会说大话，办事就比较靠谱</p><p>他也没有颠倒黑白、捏造事实的诋毁我，好像我也算不上吃亏</p><h3 id="s-583" tabindex="-1">靠山（术） <a class="header-anchor" href="#s-583" aria-label="Permalink to &quot;靠山（术） {#s-583}&quot;">​</a></h3><p>我猜，那大概就是青牛师父，跟老周挺熟的样子</p><p>背后有靠山，为好</p><p>但绝对不能死搬硬套</p><p>那么在风水理论中，有四个方位，是适合见山的</p><p>首先，第一个方位，就是正东方</p><p>正东方，在八卦中，代表震卦</p><p>正东方见山，为贵人山，代表贵人多</p><p>我们也有一句俗话，叫做东山再起</p><p>没有贵人相助，我们怎么东山再起呢</p><p>而震卦，又代表肝胆，那么东方的山，气势大，也代表什么呢</p><p>那第二个喜欢见山的方位，就是西南方</p><p>西南方，在八卦中，对应坤卦</p><p>坤，代表大地，包容万物</p><p>大地中有山，代表地气旺盛</p><p>而坤卦，又代表母亲，气势旺盛，也代表说治家有方啊</p><p>那第三个喜欢山的方位，是正北方</p><p>那最后一个喜欢见山的方位，就是东南方</p><p>东南方为先天文昌位，见山，气势大的话，肯定是有利于学业学习的</p><p>所以我们总结一下，如果想找个风水好的地方，四个方位有山为吉：分别是正东方、西南方、正北方和东南方</p><p>上午的课，我们就先讲到这里，大家看看有没有哪里不清晰的地方</p><p>古代说的背有靠，不单单是我们现在理解的背面有靠山</p><p>古代说的背有靠，主要是指北面有山，为吉</p><p>毕竟是他带我来的，话能不能说，我拿捏不准</p><p>青牛师父人看起来挺实在，对自己讲的内容也很自信，不能容忍我不走心的夸奖</p><p>就是，把简单的事情，说的太复杂了</p><p>如果是哗众取宠的风水师，他巴不得你听不懂，记不住，显得自己高深莫测，会的内容多</p><p>他压制了一下自己的情绪，尽可能语气平稳的问我</p><p>青牛师父乐不可支道</p><h3 id="s-584" tabindex="-1">经济危机是破圈的机会 <a class="header-anchor" href="#s-584" aria-label="Permalink to &quot;经济危机是破圈的机会 {#s-584}&quot;">​</a></h3><p>瑞克对破圈这件事，有着很强的执念</p><p>我已不再仅仅将他，看作是一个美发师</p><p>或许，就是跑到了像瑞克一样有准备的人手中了吧</p><p>是的，反正，就算收二三十也不赚钱，那我就不打算赚这一部分的钱了</p><p>我的第二个店正在装修，马上要开张了，帮我储备好人才哈</p><p>第二次给他送完人，安排好之后，我趁机向他请教</p><p>但同时，我又很好奇另一个问题：你第一个店开业，到现在也才一个多月</p><p>就算生意很火爆，这一个多月赚的钱，就能开一家新的店了吗</p><p>我好奇他的第一桶金，是从哪里来的</p><p>我自己当然没有那么多钱，去开第二家店</p><p>更不能指望，这么短的时间，我就能赚出开一家新店的钱</p><p>第二家店，用的是客户的钱</p><p>客户办卡的钱，就是他们存在我们店里，未来要来消费的钱</p><p>我不禁怀疑，这是一个成精了的美发师吗</p><p>用第一家店收的会员费，开了第二家店</p><p>用前两家店收的会员费，开了第三家店</p><h3 id="s-585" tabindex="-1">介入他人因果的后果 <a class="header-anchor" href="#s-585" aria-label="Permalink to &quot;介入他人因果的后果 {#s-585}&quot;">​</a></h3><p>中年男士施完礼后，提出了自己的疑问：请教老神仙</p><p>我师父曾经跟我说过：道士，就是有道之士</p><p>但，有时也会有疑惑</p><p>济世，算不算介入他人因果呢</p><p>是否要介入他人因果，这确实是个好问题</p><p>什么算介入，什么算不介入呢</p><p>躲到山里，一个人过，才算不介入吗</p><p>他们介入了他人的因果吗</p><p>老神仙笑道：你们刚刚讲过：初筮告，再三渎，渎则不告</p><p>但如果他听不懂，反复问，那就是他没有认真</p><p>别人能求到你这里，算不算他的因缘</p><p>如果你不出手，介没介入他的因果</p><p>中年男士有些不可思议</p><p>是呀，怎么才算，求到了</p><p>首先就是……得有诚心吧</p><p>老神仙笑意晏晏，轻轻摇了摇头：修行者，不要随意介入，别人的因果</p><p>是因为，因果难解</p><p>他被追杀的因，是什么</p><p>我感觉还差的那一点儿，就是这个因果难解</p><p>中年男士毕恭毕敬，再次施礼道</p><p>张三害怕遭受血光之灾，便找人帮忙化解</p><p>这下，可算是心理平衡了</p><p>能消除一切的负能量</p><p>都是因为介入了因果</p><h3 id="s-586" tabindex="-1">财布施得财富 <a class="header-anchor" href="#s-586" aria-label="Permalink to &quot;财布施得财富 {#s-586}&quot;">​</a></h3><p>财布施得财富，肯定是假的</p><p>海哥有些纳闷的看着我，不明白我为什么会觉得琪儿说的有道理</p><p>你认为，有道理吗</p><p>星辰这会儿也慢慢的点着头，附和道：我觉得琪儿姐说得对，钱是靠自己努力得来的</p><p>光靠布施，然后啥也不干，就在家躺着等着发财，那肯定是不行</p><p>财布施，得财富，还是有些道理的吧</p><p>你们会认为他的意思是：不用施肥，不用除草，不用努力，就等着一颗种子，变成一本万利的意思吗</p><p>除了努力之外，还有一个法门，叫财布施得财富</p><p>海哥清了清嗓子，再次提醒道</p><p>认可了，财布施得财富的观点</p><p>第一次讲的时候，可能会绕很久，才能讲明白</p><p>这就是法布施，得智慧</p><p>法布施，不单单能得到智慧，还能得到更多的心灵层面的能量</p><p>不好的一面就是，我没经历过生活的毒打，我一直到现在，脑子都还是很单纯</p><p>经常也会有其他人，说我身上的书生气很重</p><h3 id="s-587" tabindex="-1">心想事成长高（术） <a class="header-anchor" href="#s-587" aria-label="Permalink to &quot;心想事成长高（术） {#s-587}&quot;">​</a></h3><p>星辰好奇的问我：三合，你说法布施得智慧</p><p>然后他听人说，摸高能长高，他想起来就会跳几下，后来真的长高了不少</p><p>这里是有什么原理吗</p><p>再好的道理，也不如事实有说服力啊</p><p>琪儿姐说的这种情况，算是心想事成吗</p><p>我只好调整了态度，一本正经的跟他们解释道：这是心理学家布利斯提出的一个理论，叫布利斯定理，或者是布利斯效应</p><p>第二组，天天不练</p><p>第三组，天天在脑子里练，每天20分钟</p><p>结果是，第一组提升24%，第二组不变，第三组提升26%</p><p>布鲁斯效应，主要表述的，就是人的主观性，对结果影响很大</p><p>《孙子兵法》也讲：多算胜，少算不胜，而况无算乎</p><p>跟这个布利斯效应，说的都差不多</p><p>就是在心里，多模拟演练</p><p>吸引力法则，是想象的结果</p><p>而布利斯效应，是想象的是过程</p><p>首先说锻炼，肌肉通过锻炼，练到发酸之后，是不是肌肉也能生长，越长越壮实</p><p>不是法布施得智慧吗</p><h3 id="s-588" tabindex="-1">离9宫（术） <a class="header-anchor" href="#s-588" aria-label="Permalink to &quot;离9宫（术） {#s-588}&quot;">​</a></h3><p>离9位，五行为火，在九宫图里，是头的位置</p><p>离9在内脏方面，代表的是心脏</p><p>而且，还是开饭店的，五行属火，能量又高</p><p>紧接着，青牛师父又想到了一件很重要的事情，他慎重的叮嘱道：大家的亲朋好友的家，方便的话，也都可以去验证</p><p>一定要注意，只能默默的验证学术，不要对别人的家，指手画脚</p><p>不要显摆，不要乱动，不要随意介入他人的因果</p><p>验证对了，回去把自己的家调整好了就好</p><p>提问的人还是迷迷瞪瞪的，想不起来在什么时候，还讲过了化解</p><p>我不会固执的认为，我的就是对的，别人的都是错的</p><p>我来的目的，就是想找青牛师父聊聊安神祖窍的事情</p><p>所以自然留到了最后</p><p>福祸相依，阴阳相随啊</p><p>你看它是不好的，那它就是不好的</p><p>你看它是好的，那它就是好的</p><p>没那么复杂，我说的，就是阴阳而已</p><p>说完了，又转过头看向我：理性情绪疗法是什么</p><h3 id="s-589" tabindex="-1">理性情绪疗法 <a class="header-anchor" href="#s-589" aria-label="Permalink to &quot;理性情绪疗法 {#s-589}&quot;">​</a></h3><p>那是不是可以理解为，不生气就不生病</p><p>而且生气，直接能引起人体内‘炁（音qi）’机的紊乱</p><p>也就是说，只能练练胳膊腿儿的</p><p>改变内脏运动节奏，最快的方法，就是生气</p><p>最容易扰乱我们神魂的，就是情绪</p><p>多了解一下情绪方面的原理，用以寻求内在的平静与安宁</p><p>来，一起聊聊刚刚你提到的那个……理性情绪疗法</p><p>基本原理是，以理性控制非理性</p><p>该理论认为，人受到情绪的困扰，不是源于外在的事件本身</p><p>而是，人们对这些事情的看法，才是情绪起伏的根源</p><p>他们通过帮助病人改变认知，以减少情绪困扰和行为上的异常</p><p>也就是说，同样一件事，不同的人有不同的理解，就会导致不同的情绪和结果</p><p>开心，还是不开心，与事情无关，只跟自己的想法有关，对吗</p><p>理性情绪疗法，也被称为：拿回情绪的主动权</p><p>我详细解释了一下，他细分为AbcdE五个步骤</p><p>b（believes）信念</p><p>即导致的情绪和行为结果</p><p>d（disputing）质疑</p><p>即与原本的信念辩论，重新解读</p><p>即通过疏通，产生积极的情绪和行为</p><p>青牛师父很认真的听我讲完，想了想，总结道：这不还是阴阳嘛</p><p>再从阳面，重新解读一遍，就完事儿了呗</p><p>说说很简单，真的能放下自己的原有理念，重新解读，还是有点儿难度的</p><p>青牛师父细想再三，很认真的回答道：术业有专攻</p><p>哪怕就算是在风水方面，他们比我水平还高，这也是好事儿啊</p><p>出现我认知之外的事情，我就可以得到提升，多好啊</p><p>没有精神内耗的人，看什么事都是好事儿</p><h3 id="s-590" tabindex="-1">儒释道三教合一 <a class="header-anchor" href="#s-590" aria-label="Permalink to &quot;儒释道三教合一 {#s-590}&quot;">​</a></h3><p>我怕她痴迷于地利，忽略了人和</p><p>她也不是一个，愿意占小便宜的人</p><p>估计她也坐不住了</p><p>我被他的巨大反应，吓了一跳，脑子也迅速回归正位了，连忙摇头笑道：哈哈，不算数</p><p>青牛师父嗔了我一眼，泄气般的坐回了座位上</p><p>他倒也没再多说什么</p><p>真正有大格局的修行者，是没有教派之别的</p><p>儒家和皇家，又有哪一个，不是顺应天地规律的呢</p><p>这是说的，万法同宗，殊途同归的意思吗</p><p>全真教，又被称为新道教，新就新在，三教合一</p><p>不论哪家的经典，最终修的，无非就是心中的清净</p><p>哪怕是不读经书，通过打坐或练气，只要心中有了清净二字，也都算是修有所成</p><p>天地人，不能三合的话，又到哪里，去寻得大道呢</p><p>哪怕学员愿意掏钱辅导，他也不愿意去做，大概就是这个原因</p><p>青牛师父疑惑的看向我</p><h3 id="s-591" tabindex="-1">借福气 <a class="header-anchor" href="#s-591" aria-label="Permalink to &quot;借福气 {#s-591}&quot;">​</a></h3><p>被骗这件事，我不想去计较，不意味着，我愿意被骗啊</p><p>青牛师父想了一下，道：改变一种思维模式，有点难</p><p>然后，才有你后来遇到的这些际遇</p><p>我不骂她，都算我素质高好吧</p><p>青牛师父，企图唤醒我的觉知</p><p>但我还是不能接受这种观点，便问道：也有的人，被骗了之后，更倒霉呢</p><p>我此时，并不能理解这句话的意思</p><p>但轮到自己身上，就很难与情绪和解，说话不算数的人，是道德败坏的人，我很难谢谢她</p><p>但在被骗这件事情上，我不知道，怎么才算接纳</p><p>不追究，不理会，算不算放下</p><p>哪怕懂得再多的道理，都不耽误一次又一次的掉进坑里</p><p>原来，不理不睬，还算不上是接纳</p><p>青牛师父也看出来了，我这脑子，一时半会儿不容易转弯，便也不再强求</p><h3 id="s-592" tabindex="-1">灵力 <a class="header-anchor" href="#s-592" aria-label="Permalink to &quot;灵力 {#s-592}&quot;">​</a></h3><p>星辰接着讲述道：我同学，特别相信她的师父</p><p>然后他师父有空时，就会给她传递一下灵力</p><p>一方面，是为了引导琪儿，不要波及无辜</p><p>另一方面，我也是真的很好奇，灵力到底是什么</p><p>灵力，就是一个凭空的概念，没有根基，没有依据，没有传承</p><p>我最近也加入了一个灵力算命的群，可准啦</p><p>她同学要不要接收灵力，跟我八竿子打不着</p><p>灵力都能算什么啊</p><p>群里的内容，大概意思就是，灵力大师什么都不需要问，直接就给人断事儿</p><p>我扒拉了几屏，看了个大概，便抬头来，先看了一眼琪儿</p><p>这不是灵力算命，这是个心理学</p><p>我看着星辰一脸神往的样子，先给她泼了一盆冷水，让她醒醒脑</p><h3 id="s-593" tabindex="-1">知识的诅咒 <a class="header-anchor" href="#s-593" aria-label="Permalink to &quot;知识的诅咒 {#s-593}&quot;">​</a></h3><p>为了便于她理解，我放慢了语速道：人在认知上，会产生很多偏差</p><p>是指，人类在归因系统上，会习惯性的，把成功归因于自己，把失败归因于外在</p><p>我说完，停了一会儿，让她慢慢理解</p><p>她想了想，不太确定的问：这就是说，运气好的时候，会觉得是因为自己厉害，根本就不会去找师父指点</p><p>有啊，上次说的光环效应，也属于认知偏差</p><p>还有什么认知偏差</p><p>知识的诅咒是指，误认为别人跟自己，有同样的知识背景</p><p>因为在我的认知里，这是个常识，是个人人都懂的知识点</p><p>她犯迷糊的起因，就是因为情绪上受到了创伤</p><p>而开心，就是心开</p><p>指的是，跟自己有相同经历的受害者，我们更能共情，会更严厉的抨击施暴者</p><p>这种指责，称为完美受害者概念</p><p>比如，他们会指责受害者自己愚蠢，可怜人必有可恨之处等等</p><p>理工思维的人，要想搞笑，不太容易</p><p>星辰果然感兴趣，立马被转移了注意力，好奇的问</p><h3 id="s-594" tabindex="-1">星相效应 <a class="header-anchor" href="#s-594" aria-label="Permalink to &quot;星相效应 {#s-594}&quot;">​</a></h3><p>这个叫富勒效应，也叫星相效应</p><p>很多算命看起来特别准的大师，都是利用的这个偏差</p><p>是指人类，很容易将自己的个性，归因于一些模糊的陈述</p><p>我给你一组测试题吧，你测测看，自己准几条</p><p>星辰很开心的去测试了</p><p>对于第一次接触这方面的人，会觉得很神奇</p><p>就是说，第一次见到陌生人，什么都不用说</p><p>下面附50道测试题，大家可以对号入座</p><h4 id="s-595" tabindex="-1">1.你外表看起来，好像很有自信，但内心，有烦躁不安的一面 <a class="header-anchor" href="#s-595" aria-label="Permalink to &quot;1.你外表看起来，好像很有自信，但内心，有烦躁不安的一面 {#s-595}&quot;">​</a></h4><h4 id="s-596" tabindex="-1">4.你有时，会有不务实的想法 <a class="header-anchor" href="#s-596" aria-label="Permalink to &quot;4.你有时，会有不务实的想法 {#s-596}&quot;">​</a></h4><h4 id="s-597" tabindex="-1">5.你曾经喜欢上一个人，现在还把他藏在心底，念念不忘 <a class="header-anchor" href="#s-597" aria-label="Permalink to &quot;5.你曾经喜欢上一个人，现在还把他藏在心底，念念不忘 {#s-597}&quot;">​</a></h4><h4 id="s-598" tabindex="-1">9.你因为怕麻烦，做事有一点拖延的倾向 <a class="header-anchor" href="#s-598" aria-label="Permalink to &quot;9.你因为怕麻烦，做事有一点拖延的倾向 {#s-598}&quot;">​</a></h4><h4 id="s-599" tabindex="-1">13.你不会完全的信任别人，你认为，怀疑是必要的 <a class="header-anchor" href="#s-599" aria-label="Permalink to &quot;13.你不会完全的信任别人，你认为，怀疑是必要的 {#s-599}&quot;">​</a></h4><h4 id="s-600" tabindex="-1">15.你遇到不顺心的事情，能够自己调整自己，可以自己忘记悲伤 <a class="header-anchor" href="#s-600" aria-label="Permalink to &quot;15.你遇到不顺心的事情，能够自己调整自己，可以自己忘记悲伤 {#s-600}&quot;">​</a></h4><h4 id="s-601" tabindex="-1">18.你是个直觉敏锐的人，即使才第一次见面，你也能大概掌握那个人的性格 <a class="header-anchor" href="#s-601" aria-label="Permalink to &quot;18.你是个直觉敏锐的人，即使才第一次见面，你也能大概掌握那个人的性格 {#s-601}&quot;">​</a></h4><h4 id="s-602" tabindex="-1">24.最近你期待的事，不能称心如意的进行，以致有点沮丧 <a class="header-anchor" href="#s-602" aria-label="Permalink to &quot;24.最近你期待的事，不能称心如意的进行，以致有点沮丧 {#s-602}&quot;">​</a></h4><h4 id="s-603" tabindex="-1">38.很多事情，你都明白，但有时会被情绪影响，导致自己说出来的话，就变质了 <a class="header-anchor" href="#s-603" aria-label="Permalink to &quot;38.很多事情，你都明白，但有时会被情绪影响，导致自己说出来的话，就变质了 {#s-603}&quot;">​</a></h4><h4 id="s-604" tabindex="-1">41.有时会怀疑，自己以往的人生选择和行动，是否真的正确 <a class="header-anchor" href="#s-604" aria-label="Permalink to &quot;41.有时会怀疑，自己以往的人生选择和行动，是否真的正确 {#s-604}&quot;">​</a></h4><p>你是一个有很多想法的人</p><p>番外1－2 象数疗法肠胃</p><p>胃痛：640·380 或 370</p><p>胃痛，腹胀：40·70 （速愈）</p><p>胃痛，（气滞郁热）胃腕胀满，灼痛吞酸，或易怒便干：400·700 或 070·40</p><p>胃痛，（脾胃虚寒）胃痛隐隐，喜按喜暖，食后痛减，神疲肢冷：80·260 或 60·50·80</p><p>胃痛吐酸水：70·80 （几分钟好）</p><p>病毒性胃炎，胃和食管交接处形成了肿块，严重影响到心脏功能：2000.6500.700 （持续念十天，愈</p><p>逆，（胃气上逆）呃逆频作，不能控制，或过食生冷，或过劳伤气：40·3820·60 或 2000·640</p><p>腹部胀痛： （念几分钟即愈）</p><p>腹痛，上吐下泻：650·30·820（李老师给的方）</p><p>右下腹痛：80·50·160（两分钟好了）</p><p>腹痛急性，吃雪糕后又吐又发烧：·7000·4000（念了10分钟疼痛减轻，第二天痊愈）</p><p>腹部痛夏天：70·820·60 （第二天不痛了）</p><p>剧烈腹痛：8000 或 780·60</p><p>腹痛难受，受寒呕吐：40·70·650·3820 速愈</p><p>腹痛拉肚子：50·80</p><p>腹泻，（脾肾阳虚）多有五更泄，或腹痛畏冷，泻后痛减：650·40 或 820·650</p><p>腹泻，（饮食内伤）腹痛泄泻，泻下恶臭，或腕腹胀满，嗳腐吞酸：40·70 或 820·60</p><p>腹泻：870·10</p><p>急性腹泻不止，后来泻水沫：·（很快止泻）</p><p>拉肚子： 40·70（小孩）</p><p>常年拉肚子: 20·650·30·80 （第二天拉一次，一周后完全好了）</p><p>五更泻：1650·3820 （温肾健脾，固涩止泻）</p><p>小儿洞泻，七个月的婴儿，泻水好几天了，严重脱水：650·380·010 （抱念五小时好转，再念六小时每天泻4-5次了，到第四天痊愈）</p><p>治愈肠炎：20·650 （马上见效）</p><p>结肠炎，常年腹泻：820·650 （念几天立见奇效）</p><p>结肠炎溃疡性：010·260·40 （念两个月没再犯）</p><p>阑尾炎：820·650·4300 （念了几天，加上贴，就好了）</p><p>阑尾炎，肠粘连：2600·00500·780 （夫妻手握手念一晚上，第二天完全好了）</p><p>结肠癌：120·720 （三天肚子不痛了，持续念一段后恢复健康）</p><p>直肠癌: 000100·720·440 （默念八小时以上，疼痛减轻，精神状态好多了</p><p>肛病处开始发痒和串走感，这是生新肌的好转现象，但也要调方止痒， 又说双腿麻木，此为配方中金旺克巽木所致，巽为股为腿，当即与谢老师共拟方加650泄金生木化解</p><h3 id="s-605" tabindex="-1">断卦要给人希望 <a class="header-anchor" href="#s-605" aria-label="Permalink to &quot;断卦要给人希望 {#s-605}&quot;">​</a></h3><p>她现在，运势确实非常低，但弱极必反，最后的结果，还是不错的</p><p>不管他再怎么告诉我，没问题</p><p>因为，他讲的，毫无逻辑</p><p>我不能仅仅就凭着两个字，给我同学瞎说呀</p><p>我皱着眉，还在迟疑着，不知道该怎么回答</p><p>你认识的这个大师，算的是很准的吧</p><p>你先想办法去找书，认真准备吧</p><p>但，问也问不出个什么来，无非就是一个字：悟</p><p>算卦，无论测出什么结果，你都要给人，留下希望</p><p>我大概已经可以确定，他就是个大忽悠了</p><p>五行为木，木生火</p><p>算命，要接触各行各业的人</p><p>要想把命算准了，你不但要掌握，基础的五行八卦</p><p>你还得掌握，卦主所处行业的相关信息，包括曾经的历史和当下的时事</p><p>一旦考虑不周全，算出来的结果，就可能是个反的</p><p>你以为算准，很简单</p><p>他不急不恼的反问我</p><h3 id="s-606" tabindex="-1">心安，神才定 <a class="header-anchor" href="#s-606" aria-label="Permalink to &quot;心安，神才定 {#s-606}&quot;">​</a></h3><p>他们大概就是，天天的闭着眼瞎忙活</p><p>却没有去想过，用哪种方法是可行的</p><p>意思是说，人要先静下来</p><p>真正要修行的人，没有人会去做违背良心的事</p><p>人在浮躁的状态下，即使头脑里有想法，一般也是胡思乱想</p><p>群里这会儿静下来了，我才给他们提出了建议：先把心静下来</p><p>我把洗心养神功的做法，发到了群里</p><p>我缓了一下无语的情绪，才回复道：滋养心神，只是为了让我们的言行举止，充满灵性</p><p>看样子，得让他们适应几天先</p><p>短暂的安静之后，有人回复道：嗯……听着貌似有道理，但是，很虚啊</p><p>我不熟悉他们的圈子，没反应过来是什么意思</p><p>算命的进来，卖姻缘符啊</p><p>提前澄清一下，也避免了以后，万一有人加我，我不接受，再有什么误会</p><h3 id="s-607" tabindex="-1">婚配和坎宫的化解 <a class="header-anchor" href="#s-607" aria-label="Permalink to &quot;婚配和坎宫的化解 {#s-607}&quot;">​</a></h3><p>你是不是应该，先多去验证一些</p><p>对这个理论，有了比较清晰的认知之后，再考虑怎么化解的事情</p><p>我就是为了验证啊</p><p>如果知道怎么化解的话，验证的时候，如何有不符的，我也好知道，是不是无意间，被化解了啊</p><p>我被他说服了，便解释道：化解的原理，其实也很简单</p><p>一个化解方向是，减少不利气场的产生</p><p>另一个化解方向是，增强自身的抗伤害能力</p><p>先说第一个，减少不利气场的产生</p><p>所以，第一种化解办法，就是减少两种气场的接触</p><p>也可以特意的改变某一种气场的属性，让它不能发挥作用</p><p>举个例子，属马与属牛的在一起，是什么关系</p><p>愣了一下，连忙伸出手，开始数掌中诀，找到了两者的位置，抬头道</p><p>所以化解，一般是合住其中的一方</p><p>这个化解的属相，也叫贵人属相</p><p>一边扒拉，一边念叨：寅，戌，能合住午马</p><p>戌当中间人去化解，就不太合适了</p><p>从属相这个层面的化解来说，解到这里，就算是到位了</p><p>吴昊有点儿沮丧道：那不得个有个电脑处理器那样的脑子，来计算哈</p><p>背了这么多，这么算，那么算的，才只是一个字啊</p><p>等学会了乘除法，能算的过来账了，就可以去做个小买卖了</p><p>总不能说，我加减乘除都学完了，就要去考大学</p><p>也就是个简单的属相关系而已</p><p>三合局=第一个季节的驿马+第二个季节的正位+第三个季节的墓库</p><p>三会局，是东南西北四个方向，每个方向为一个局</p><p>每个季节的最后一个，是墓库，为土</p><p>这点儿东西，多算几次，就熟练了</p><p>这个第二种，是不是更厉害</p><p>所以你说的相刑有方向，在化解的时候能用上</p><p>两种都可以，第一种是更根本的解决办法</p><p>找到了能把它们合起来的贵人属相之后，再怎么使用</p><p>所有的改运调整，不外乎时间和空间</p><p>结婚日子的选择，伴郎伴娘的属相，生的孩子的属相，家里的摆设，佩戴的手链等等</p><p>处处都可以，用贵人属相去调整</p><p>我也查了一些资料，只是没看明白，怎么化解</p><p>不论她信不信，只要我帮她把家调整了，她都会受益的</p><p>你把地利给她调整了，她本人排斥和反感，也不一定是好的结果啊</p><p>比如，一个身体很正常的人，天天怀疑自己得病了</p><p>天天疑神疑鬼的，身体真的会生病的</p><p>简单来说，怀疑自己有病，这种消极的想法是阴性</p><p>阴性重了，阳气不足，气血循环减慢，免疫力就会下降</p><p>这就是常说的，好的不灵，坏的灵</p><p>他又犹豫了一会儿，试探着问：师父，你可不可以教我，坎1宫受伤的化解办法</p><p>我到时候看情况，再酌情处理</p><p>看到他如此执着，我便也不再阻拦，直言道：风水的化解，跟婚配的化解，思路是一样的</p><p>坎1，五行属水，在人物上，代表二男</p><p>如果要调整的话，首先要注意，不论是大太极，还是每个房间的小太极，坎1宫里，都不要见水</p><p>包括水龙头，厕所，鱼缸，洗衣机下水口等等</p><p>黑色物品，五行也为水</p><p>也包括风水画上的水</p><p>草本植物等等，也算水</p><p>第一件事，就是把五行属水的物品，都挪走</p><p>有前后门的话，后门就不要走了</p><p>化解的时候，除了室内，也要看室外，都不要有水，也不要有煞</p><p>煞包括：凶兽，刀剑，带刺的植物，光煞，风煞等等</p><p>尤其是室外，不要有路，不要有坑</p><p>坎1在正北，也是四象里的玄武位</p><p>这里宜静，宜有靠山</p><p>或者有坑，有河，有池塘，都跟靠山相反，为凶</p><p>大概他查资料时，没注意到这些细节</p><p>通过指南针，靠着墙，校准一下方向</p><p>画的时候，可以根据地砖数量，算一下长宽比例</p><p>然后把这个户型图，从南到北，从东到西，分三等份</p><p>也就是说，太小太极的坎1宫，都不能有水</p><p>哪怕厨房在大太极的坎1宫，但是洗菜盆在厨房正北，就属于小太极坎1宫见水了</p><p>他长时间的愁眉紧锁，就意味着，事情不好办，有些位置，他不好调整</p><p>就是那两个办法呀</p><p>如果不能想办法把刀挪走，就多穿几件厚棉袄，让刀扎过来的时候，扎的浅一点儿</p><p>所以说，命运难改</p><p>不是说不好改，而是说，想改的人，要下定决心，把原来对自己有伤害的刀挪走，然后再考虑，如何给自己助运</p><p>不能期望，学个加减法，就想进清华</p><p>化解的时候，能挪走多少，就挪走多少吧</p><p>别说是表哥表嫂家，就算是你父母家，也不能乱动</p><p>其他煞还好说，就是风煞要多注意</p><p>风煞，分为很多种</p><p>看样子，他查资料的时候，只看了坎1宫，没注意到煞的问题</p><h3 id="s-608" tabindex="-1">改命的四种方法 <a class="header-anchor" href="#s-608" aria-label="Permalink to &quot;改命的四种方法 {#s-608}&quot;">​</a></h3><p>对于不修行的人，他们不懂人生的地图</p><p>但对于修行的人，或者积德行善的人，会有变量在里面，结果就是不固定的</p><p>八字，预测不出来，最终掉没掉坑里</p><p>曾经有位大师，给了凡算过命，算了他的一生</p><p>算县考，府考等，每次考试分别考得第几名，以及哪年会到哪里去任什么官职，寿命长短，一生无子等等</p><p>他认为，这句话的意思是，有些事是可以求得的</p><p>如果只是向外追求，那就是凭命了</p><p>不修内在，就算靠命得到的，最终也会失去</p><p>改命之法，有四点</p><p>了凡明白了禅师的意思，叩谢之后，谨遵教诲，积德行善</p><p>本来大师预测的第三名，实际考了第一名</p><p>之前测算的事情，开始一一不应验了</p><p>吴昊对命理学，有着一种偏执，他怀疑的问：袁了凡，真的有这个人吗</p><p>积德，真的可以改命，连八字都算不准了吗</p><p>再者，哪怕故事是假的</p><p>《三命通会》里，作者有清楚讲到，同年同月同日生的人，命运并不相同，并且举了对应的案例</p><p>运行的气，就是运气</p><p>就说双生子，他们从肚子里到肚子外，他们的位置，也是不可能完全相同的，所以，他们的气，也是不同的</p><p>因为，就算同一个房间，不同位置的气，也并不相同</p><h3 id="s-609" tabindex="-1">精神内耗 <a class="header-anchor" href="#s-609" aria-label="Permalink to &quot;精神内耗 {#s-609}&quot;">​</a></h3><p>虽然吴昊的业绩，开始超过我了，但我对钱的观念是，够花就行</p><p>每天的小日子，过的轻松又自在</p><p>闻道有先后，术业有专攻，如是而已</p><p>吴昊既然转不过这个理儿，我又有了大把的公司客户加持，他心里也舒服了，我便没再跟他做过多的解释</p><p>有些客户，我对接起来，不太适应了</p><p>你们本来就是独立工作的，我在不在，都一样的啦</p><p>他既然话都说到这儿了，不论适不适应，我也不能再开口，把客户还给他了</p><p>艾伦选择把客户交给我了，无论如何，我都不能给公司丢脸</p><p>我慢慢的进入到了一种焦躁和倍感压力的状态</p><p>我可以不在乎钱，我可以选择躺平，我可以避开所有卷的行业和客户，但我不能辜负艾伦对我的托付</p><p>我再也不能，心无牵挂的自在喜乐了</p><p>我以前走路，慢悠悠的</p><p>脑子里只剩下一个念头：怎么办，怎么办，怎么办</p><p>我也不能去找艾伦求助</p><p>不想做的客户，扔了就是了</p><p>艾伦都已经拿下的客户，他们都已经合作过了，到我这儿，我再给扔了</p><p>他是可以无所谓，但我，绝对不能原谅自己</p><p>我只有一个念头儿，一定要完美的解决这个问题</p><p>人在压力大的时候，呼吸就会急促，短浅</p><h3 id="s-610" tabindex="-1">杀死精神内耗 <a class="header-anchor" href="#s-610" aria-label="Permalink to &quot;杀死精神内耗 {#s-610}&quot;">​</a></h3><p>这是新加坡人的思维模式，跟咱们不太一样，她们更偏西方化</p><p>她们就会很注意尊重彼此的隐私，不会再继续接着问了</p><p>她是个神仙一样自由自在的人，大概是没有烦恼的</p><p>华语是她的第二语言</p><p>首先，以我对艾伦的了解，我确定，他真不会把这个当个事儿</p><p>也就是说，不是艾伦逼我，一定要做好</p><p>而是我自己，主动把自己限制在那种思维模式里</p><p>退一万步讲，就算是艾伦放不下那些客户，我就是没有能力做好，那又怎样</p><p>我本来就打算，早晚要自己开公司的</p><h3 id="s-611" tabindex="-1">佛家是无神论 <a class="header-anchor" href="#s-611" aria-label="Permalink to &quot;佛家是无神论 {#s-611}&quot;">​</a></h3><p>佛家有六度核心：布施、持戒、忍辱、精进、禅定和般若</p><p>也就是说，六个修行法门，到达觉悟的彼岸</p><p>再待几年，你且看他</p><p>比如第一百六十八：若人侵谤汝，汝但当自启白大道，不得忧怖，以损精神</p><p>《圣经》中多次强调：神就是爱</p><p>心中没有爱，体会不到极乐，上不了天堂，如果这是个因果关系，我还是比较容易接受的</p><p>不论我信不信神，我都希望，神代表的是爱和希望，而不是残暴的主宰者</p><p>人本身就是神的殿，不要再去跪拜假神</p><p>《金刚经》里也有说过：若以色见我，以音声求我，是人行邪道，不能见如来</p><p>也就是说，烧香拜佛，是见不到如来的</p><p>见他没打算开口，我便继续解释道：道法自然</p><p>道家讲的，是顺应天地的自然规律</p><h3 id="s-612" tabindex="-1">神阻挡骄傲的人 <a class="header-anchor" href="#s-612" aria-label="Permalink to &quot;神阻挡骄傲的人 {#s-612}&quot;">​</a></h3><p>比利牧师看大家有所感悟，便又轻轻的念诵着一段又一段的经文，道：知识，是叫人自高自大，唯有爱心能造就人</p><p>当听到自卑这个词时，有人疑惑的小声嘀咕道</p><p>被这质疑的声音打断，比利牧师笑了笑，却没有辩解</p><p>神阻挡傲慢的人……虚心的人有福了，因为天国是他们的</p><p>humble可以翻译为自卑，也有贬低，谦逊，虚心的意思</p><p>一边让人谦卑，一边让人捐钱，这算不算是精神控制</p><p>有疑惑，确实是很正常</p><h3 id="s-613" tabindex="-1">财多伤人 <a class="header-anchor" href="#s-613" aria-label="Permalink to &quot;财多伤人 {#s-613}&quot;">​</a></h3><p>比利牧师轻轻念诵道：不杀生，讲的是慈悲</p><p>慈悲，是爱的第二个名字</p><p>比利牧师，时而念经，讲他想讲的，时而用经文，回答大家提问的</p><p>在临走的时候，有人又聊回了布施的问题</p><p>如果奉献，或者说布施，能够得到更多的财富，那为什么，只有犹太人最有钱</p><p>佛教和道教，不也讲布施吗</p><p>《太平广记》里，也记录过不少点石成金的故事，一旦贪心，就成了祸事</p><p>比利牧师这时，又轻轻的念诵起了一段段的经文，道：向穷人施舍，是借贷于上主</p><p>不要为自己积攒财宝在地上，地上有虫子咬，能锈坏，也有贼挖窟窿来偷</p><p>我心中冒出了很多的想法</p><p>我急要找个安静的地方，慢慢的再理顺一下脑海中新涌入的内容</p><p>比利牧师用他那柔和的嗓音念诵出来的经文，一直萦绕在我的耳边</p><h3 id="s-614" tabindex="-1">天地之主 <a class="header-anchor" href="#s-614" aria-label="Permalink to &quot;天地之主 {#s-614}&quot;">​</a></h3><p>如果这个善术者，能预测未来，一切都说的通</p><p>擅长骑马的人说出这种不合逻辑的话，听起来像不像精神不正常</p><p>用的就是，王阳明说的那颗心——天地万物之主</p><p>心理学上，有个现象叫焦点效应</p><p>是指人们往往把自己看作一切的中心，高估周围人对自己的关注程度</p><p>还有个词，叫聚光灯效应</p><p>是指当人在面对一些尴尬境遇的时候，总会将自己的问题放到无限大</p><p>这种非理性的恐惧，就是潜意识</p><p>大概就是，当习惯了</p><h3 id="s-615" tabindex="-1">心的维度 <a class="header-anchor" href="#s-615" aria-label="Permalink to &quot;心的维度 {#s-615}&quot;">​</a></h3><p>能被人记恨的，多半是嚣张狠戾的人</p><p>越臣服，越把自己放在低的位置上，就越会引导能量和运势，流向自己</p><p>外卦为顺，代表外在柔弱</p><p>内卦为止，代表内心要适可而止，知足才能长乐</p><p>我们不能太把自己当回事儿，我们要臣服，才能顺应天道</p><p>我们也不能不把自己当回事儿，还住在我们里面呢</p><p>只可惜，这是我通过脑子，推理分析出来的结论</p><p>很多效应，都说的是脑子</p><p>先标个高价，划掉，再写个低价在旁边，让人感觉占便宜了</p><p>这也是大脑的推理</p><p>归纳推理，是人类最高级的思维方式</p><p>不生生不可说，生生亦不可说，生不生亦不可说，不生不生亦不可说，生亦不可说，不生亦不可说</p><p>修行，靠的是行，而不是嘴</p><p>说的再多，没亲自践行，也体会不深</p><h3 id="s-616" tabindex="-1">无脑才能爽 <a class="header-anchor" href="#s-616" aria-label="Permalink to &quot;无脑才能爽 {#s-616}&quot;">​</a></h3><p>这里面的霸总，天天都不用干正事儿，光争风吃醋，就能事业有成了</p><p>也就是说，要爽，得无脑</p><p>这跟修行，倒还挺像的</p><p>男一认为霸主的位置本该是属于他的，要报仇</p><p>男二被男一逼得，让出了霸主的位置</p><p>女主夹在两人中间，左右为难</p><p>最后，男二承认是自己卑鄙无耻，抢了本该属于男一的霸主位置</p><p>爽文的爽，只在于放下大脑的逻辑，但是，没有放下情绪</p><p>情绪是跟着故事情节，跌宕起伏的</p><p>你以为这是悬疑小说呐</p><p>当人的情绪，被外在事物主宰的时候，快乐的决定权，是不在自己手里的</p><p>所以修行讲，放空大脑，才能臣服</p><p>这个放空，既包括逻辑思维，也包括情绪起伏、执念等等，所有需要动脑的念头，都要放下</p><p>我慢慢的在体会着，放空大脑的感觉</p><p>特意发信息，问我方便吗，难道就是为了跟我说这个</p><p>吴昊声音轻快的道，师父，其实，我是有两件事儿要麻烦你</p><p>一个是，我女朋友皮肤敏感，不能碰金属，比如说不能带金属首饰，或者金属材质的眼镜等等</p><p>这是什么原因造成的</p><h3 id="s-617" tabindex="-1">每个人都知道答案 <a class="header-anchor" href="#s-617" aria-label="Permalink to &quot;每个人都知道答案 {#s-617}&quot;">​</a></h3><p>比如一个亿的小目标，对于有那个格局的人，那就是个小目标，这就叫能驾驭</p><p>对于驾驭不了的人来说，那就是个笑话</p><p>但对于有的人来说，这个数字，是需要仰望的，那就是说，他驾驭起来有难度</p><p>比如说，你去见客户的时候，或者你去找某个领导办事儿的时候，或者你去解决某个工人的问题的时候，在开口之前，你大概心里是有数的，这个事儿能不能成</p><p>对对对，就是这个意思</p><p>就是你一打眼，你心里就会知道，这是不是自己可以驾驭的</p><p>只要不贪得无厌，不被猪油蒙了心，都会知道的</p><p>能不能搞定一个人，可以感觉到</p><p>能不能搞定一定数目的钱，大概心里也有数</p><p>房子能不能驾驭，是指的什么意思呢，我还是不太明白</p><p>万事万物，你能不能搞定，其实自己心里都是有数的</p><p>自己能不能跳过去，心提前就知道了</p><p>你能驾驭的就是好的</p><p>再好的房子，你驾驭不了，那就会被反噬</p><p>没有外物要伤害我们，是我们自己的贪念，伤害了我们自己</p><p>这就是《华严经》讲的：一切唯心造</p><p>不贪心的话，我们自然会知道答案</p><p>一旦起了贪念和攀比心：别人能跳过去的沟，我一定也可以</p><p>注意力，就是生命力</p><p>把注意力，放在自己身上</p><p>这笔钱，我能不能赚到</p><p>这个房子，我能不能担的起来</p><p>这个沟，我能不能跳的过去</p><h3 id="s-618" tabindex="-1">法不责众吗 <a class="header-anchor" href="#s-618" aria-label="Permalink to &quot;法不责众吗 {#s-618}&quot;">​</a></h3><p>姑奶奶赞许道：有道理</p><p>很简单，大概率事件，代表着规律的方向</p><p>西北角，是乾宫，代表财库</p><p>就算是有钱人，也是一屁股的债</p><p>我个人认为，法，并没有因为人多，就更改了天道规律</p><p>以前计划生育的时候，堕胎的也不算少</p><p>第一个是，艮宫受伤伤子嗣，不一定是要缺角</p><p>住平房的话，虽然不缺角，但东北角有可能是厨房，或者大小太极的艮宫有镜煞等其他伤害</p><p>第二个原因是，风水对我们的影响，不只是阳宅</p><p>第三个原因，风水只是地运</p><p>不可能几十万人的八字，都在同一天致命</p><p>我犹豫了一下，道：乾位，五行属金</p><p>我喜欢跟别人分享五行八卦的理论和应用，但却不太喜欢直接给人看风水</p><h3 id="s-619" tabindex="-1">最好的化解办法 <a class="header-anchor" href="#s-619" aria-label="Permalink to &quot;最好的化解办法 {#s-619}&quot;">​</a></h3><p>但如果老老实实的说别人这儿不好那儿不好的，那不成了上赶着去招人烦吗</p><p>所以，我便折中了一下，讲讲原理</p><p>让大家自己明白了道理，再决定要不要化解，以及，要化解到什么程度</p><p>模棱两可、没有绝对把握的答案，尽量不要改</p><p>蒙题的话，第一直觉准的概率更大</p><p>但这种情况下，就要把期望值调整到，能提高一分算一分</p><p>姑奶奶听完之后，不但没生气，反而在电话那边儿笑得哈哈的</p><p>最好的办法，就是换个好的房子呗</p><p>最好的办法，就是避开伤害</p><p>请这个盾牌化解，有什么说法和要求吗</p><p>这样，就去除了贪念</p><h3 id="s-620" tabindex="-1">生命的觉醒 <a class="header-anchor" href="#s-620" aria-label="Permalink to &quot;生命的觉醒 {#s-620}&quot;">​</a></h3><p>她总怀疑是医院过度治疗导致的</p><p>她常常悔恨，如果当时没去医院就好了</p><p>他想告诉我们，孩子要走，就是要走了</p><p>为往生者诵经、助印，都是功德</p><p>世上又能有几个人，笑到了生命的最后一天</p><p>这次，为了心中的这份不舍，我特意占了一卦</p><p>我就在这种不舍、祝福、自责的情绪中，不断的修，一点点的悟</p><h3 id="s-621" tabindex="-1">从迷茫中走出来 <a class="header-anchor" href="#s-621" aria-label="Permalink to &quot;从迷茫中走出来 {#s-621}&quot;">​</a></h3><p>情绪投射，是典型的对人不对事儿</p><p>还有一种投射，叫愿望投射</p><p>是指把自己的主观愿望，强加给对方</p><p>再比如，一个人抱怨另一个人小气的要死，一分钱都能看的比脸盆子还大，跟他在一起简直要被逼疯了</p><p>这个抱怨者本身，就不会是个大气的人</p><p>投射效应就像一面镜子，反射着我们生命的内在历程和自我价值</p><p>小月看似是通过不讲道理的方式在否定我，但其实，她内心不接纳的是她自己</p><p>当一个人开始忽略自己的情绪状态与内心感受时，迷茫的感知就会模糊自己与他人之间的界限，分不清什么是自己想要的，什么是他人想要的</p><p>每天找一个时间问问自己</p><p>如果感觉，那就是明显的陷入了投射的镜子里</p><p>仔细的找到自己的感觉之后，再做第二步</p><p>问问自己：为什么会有某种情绪</p><p>我应该有什么样的情绪</p><p>注意力就是生命力</p><p>当把注意力放在了自己的内心时，就会给心增加了生命的力量</p><p>意思是，他没有发愤苦想、不悱恻忧思，就不要主动去启发他</p><p>小月这人很有趣，她不断的说我被封建迷信洗脑了，但就是不换话题</p><p>我用最简短的话回应她，避免再次被她当成镜子里的靶子</p><p>她这个推理能力，颇带幽默感</p><p>五行和八卦，代表了万事万物</p><p>但土代表的症状，不一定一样</p><p>这还没算上每个人的流年大运、四柱八字</p><h3 id="s-622" tabindex="-1">附佛法外道 <a class="header-anchor" href="#s-622" aria-label="Permalink to &quot;附佛法外道 {#s-622}&quot;">​</a></h3><p>你朋友既然相信风水，那他所谓的相信因果和乐于助人，就是狭隘的</p><p>你不要被他这种小利益给诱惑了</p><p>于是我反问道：佛家讲因果，讲善恶有报</p><p>道家也讲因果，讲尊重生命，讲包容谦让，讲存好心办好事儿</p><p>大家同样都是相信因果，都是劝人向善，都讲慈悲为怀，我们怎么就狭隘了</p><p>善树师父这才认真的看向我，一字一顿的说道：佛家的因果，讲的是累生累世因果相连</p><p>道家的因果，讲的是现世的因果</p><p>尤其是你说话的时候，不要提因果两个字</p><p>不要披着佛法的外衣，去做一些旁门左道的事儿</p><p>我之前还以为，佛家和道家都讲因果，都劝人善，都打坐修行，都有法号，都有信众，都讲布施，都一样有乐于助人的发心</p><p>听完善树师父的话我才知道，不是佛家子弟，都不配提因果</p><p>必须累生累世，才配得上因果两个字</p><p>你打别人一耳光，别人啪一巴掌还回来，这就不算是因果了吗</p><p>怎么就是附佛法外道了</p><p>难道我信因果，还沾你的光了呗</p><p>我希望大家尊重天道规律，不要被风水伤害，我还成旁门左道了</p><p>善树师父大概是看出了我的不服气，也有可能是怕君君被我带到里，于是，她苦口婆心的给我们做法布施</p><h3 id="s-623" tabindex="-1">跳出五行之外 <a class="header-anchor" href="#s-623" aria-label="Permalink to &quot;跳出五行之外 {#s-623}&quot;">​</a></h3><p>不是佛菩萨要克谁，而是五行火克了金</p><p>天地跟圣人，也不是不慈悲，他们只是尊重天道规律而已</p><p>累生累世的因果，我也看不透</p><p>我也不知道是不是业力</p><p>也可能既是业力，又是风水，是双重叠加</p><p>也可能如果没有业力的牵引，她也不会住到这样的风水里</p><p>业力一般是指因果关系</p><p>我表达能力有限，她既然听不懂，那我就只能再举个不太恰当的例子：张三揍了李四一棍子，李四要报复回来</p><p>业力解释的是，张三为什么挨揍</p><p>风水，对应的是那根棒子，解释张三为什么会受伤</p><p>反正累生累世我也看不到，这就是我个人的理解而已，不一定是对的哦</p><p>那修行好的人，可以不受风水影响吗</p><p>但可能要修行到相当的高度，才可以跳出五行之外</p><p>我们本来是打算就来这一个地方的</p><h3 id="s-624" tabindex="-1">佛学院的执念 <a class="header-anchor" href="#s-624" aria-label="Permalink to &quot;佛学院的执念 {#s-624}&quot;">​</a></h3><p>她情绪又低落了一些</p><p>我也知道人的情绪，是会受风水的影响的</p><p>在跟君君聊天的过程中，其实也是我自己的情绪梳理过程</p><p>但你刚刚分析的有理有据，都能对应上，但善树师父又很排斥风水，这不是无解了吗</p><p>君君先给我和妙渡师父做了一下介绍，又介绍了其他几个人，大概君君经常来，跟她们都挺熟的</p><p>君君悠悠的叹了口气，大概还没从路上低落的情绪里走出来</p><p>妙渡师父再次笑起来，道：所以啊，他经常被人方丈师父点化</p><p>大自然的规律，谁不得遵守，这算什么外道</p><p>我再次仔细的观察他</p><p>大家有时聊聊茶，有时聊几句武馆，有时我还会好奇的问问他在嵩山修行的一些事情</p><p>妙渡师父在大法王寺修行期间，主要就是跟随在释延佛大师身边</p><p>我因为行程安排的原因，还要留时间见一下家里亲戚，只能再约见一位师父</p><p>我们商定第二天上午，去拜见奇门遁甲派的师父</p><p>时间所限，我优先选择的，是我认为能学到东西的师父</p><p>第二天在去的路上，君君给我介绍了一下师父的情况：一会儿要见的这位师父，是智策师父，佛道双修</p><p>四位数起步，我也不知道这算不算贵</p><p>有价位，那我心里大概就有概念了</p><p>一个小伙子说着就伸出手来，打算跟我们握手</p><p>于师父在推算方面，也颇有研究</p><p>君君接着智策师父的话，在旁边替我介绍道</p><p>于师父跟智策师父很熟，她笑着解释道：智策师父比较严谨，不动不占</p><p>我在心里简单算了一下运势，道</p><p>破是运势极差的意思</p><p>五行属金，像一把刀</p><p>于师父在那边写写算算，轻声念叨道：但我这边看，他去年的运势破不了啊</p><h3 id="s-625" tabindex="-1">对抗催眠和洗脑 <a class="header-anchor" href="#s-625" aria-label="Permalink to &quot;对抗催眠和洗脑 {#s-625}&quot;">​</a></h3><p>钱差不多就得了，再多了也不一定是替谁赚的</p><p>人的思维灵活程度，跟情绪是直接挂钩的</p><p>情绪低落的时候，脑子都不会转了</p><p>回想一下，最近一次很开心的时候是什么时候</p><p>也跟风水有关，后面找机会再讲</p><p>君君一从情绪的低谷里走出来，脑子里就又不断的能想到好多的问题，开始叽叽喳喳的聊起来</p><p>信风水，和迷信风水，是什么区别</p><p>我按照我的理解，解释道：相信风水，是指借助于天地之力</p><p>利用规律，为我所用</p><p>我们跟宇宙间的交流被切断了，意识流向失去了阴阳平衡</p><p>单方向的给我们灌输一种观点</p><p>&#39;pUA精神控制，也是差不多的原理</p><p>如果孩子不反抗，就容易被精神控制，陷入内耗和自我否定中，失去了爱自己的能力</p><h3 id="s-626" tabindex="-1">心诚则灵 <a class="header-anchor" href="#s-626" aria-label="Permalink to &quot;心诚则灵 {#s-626}&quot;">​</a></h3><p>它可以代表各种物件</p><p>西院邻居又道：但我家厕所就算是拆了，也不值那个钱啊</p><p>最好的解决办法，就是把厕所拆了挪走</p><p>有的门派，就是选择的大破大立的化解办法</p><p>我是怕你们嫌麻烦，才建议你们放东西化解的</p><p>没啥好办法，我只能扯出了一面大旗，道：有句老话儿说，道不轻传，法不贱卖，师不顺路，医不叩门</p><p>虽然这是我的托词，但心诚则灵，也不是完全没有道理</p><p>所以道不轻传，法不贱卖，师不顺路，医不叩门</p><p>各人有各人的因果</p><p>修自己坚定的心，修自己的正念</p><p>不要被消极的念力和情绪，拉到麻木和无助的沼泽里去</p><p>我总不可能上赶着送他个化解法器吧</p><p>对于心思不正的人，哪怕我就算是送了，无非也就是激起他更多负面的怀疑和揣测罢了</p><h3 id="s-627" tabindex="-1">脚踏实地的赚钱 <a class="header-anchor" href="#s-627" aria-label="Permalink to &quot;脚踏实地的赚钱 {#s-627}&quot;">​</a></h3><p>这就是自助者天助吧</p><p>注意力，就是生命力</p><p>当我们把注意力放在关注的事情上，又能从零开始着手做的时候，这件事情就被注入了生命力</p><p>我爸的第一感觉是，新加坡真好，四季如春</p><p>他的第二感觉是，新加坡做餐饮，真是暴富的机会</p><p>新加坡的人口密度，全球排第二</p><p>但又总不能交着昂贵的店租，早早的就收档了吧</p><p>目前没工作的朋友，先解决温饱，再考虑发展</p><p>最近有体内热但体表又怕冷的感冒症状，大家可以试一下象数20?60?050?070</p><h3 id="s-628" tabindex="-1">有问题吗 <a class="header-anchor" href="#s-628" aria-label="Permalink to &quot;有问题吗 {#s-628}&quot;">​</a></h3><p>在回去的路上，丘书妍再次用她那清澈又单纯的眼神儿看着我，正式的问道</p><p>她完整的表现了自己各方面的能力之后，再用她那水汪汪的眼睛看着我，轻轻的问一句：有问题吗</p><p>智策师父说过，预测只是预测，但到底会不会遵从，是个人的因果</p><p>我并不质疑预测的结果，但我更想全力以赴的去试一下</p><p>试试我能不能去改变那个结果</p><p>我也很清晰的知道自己的想法</p><p>在当时的我看来，只要确认了她是那个要用生命去守护的人，未来出现任何情况我都不可能会放手</p><p>确认关系之后，我带丘书妍见的第一个人是师兄</p><p>改命从根本上来说，只能靠自己</p><p>改命的办法很简单，就是去帮助更多的人，乐善好施，积德行善</p><p>看似是给出去的，其实都是给自己积攒下的因果福报</p><p>福泽深厚了，就能化解很多沟坎儿</p><h3 id="s-629" tabindex="-1">我长的很有实力 <a class="header-anchor" href="#s-629" aria-label="Permalink to &quot;我长的很有实力 {#s-629}&quot;">​</a></h3><p>当我认识到这个问题时，我第一时间就跟我妈道歉，感谢她给我生了个这么靠谱的模样</p><p>（不过当时情绪有些激动，我妈一时没能分辨出来我说的是正话还是反话</p><p>她不能看，不能听，不会说</p><p>如果她平庸，那她就是个可怜的盲人，但如果她强大，那所有人都会因为她的缺陷而崇拜和敬佩她</p><p>能努力的努力，不能努力的就放下</p><p>你要不要去拜拜呀</p><p>经历过那次考驾照的事情之后，我再也不敢傲慢的说我不需要了</p><p>我们顺着队伍，慢慢的绕来绕去，好容易才摩肩擦踵的挤了进去</p><p>在礼拜菩萨的时候，看到身边熙熙攘攘的人，诚心的叩拜祈求，我就想，我也要像菩萨一样去帮助更多的人</p><p>当时我们的公司成立不久，我心想，如果公司以后赚了钱，我也要像基督教一样做十一奉献，拿出10%的收入做慈善，让布施成为我的习惯</p><p>是，就是太有钱了，超乎我们想象的有钱</p><p>他不能理解，为什么要因为对方太有钱而分手</p><h3 id="s-630" tabindex="-1">慈善拍卖会 <a class="header-anchor" href="#s-630" aria-label="Permalink to &quot;慈善拍卖会 {#s-630}&quot;">​</a></h3><p>为了纪念你在新加坡学会了打麻将，要不咱们把那副麻将给拍下来吧</p><p>我第一次参加这种慈善拍卖会时，丘书妍跟我商量道</p><p>我对拍卖的认知，来源于电视剧</p><p>虽然我在理智上明白，事事皆分阴阳，事事都是好事儿</p><p>慢慢的从内在，自己疗愈自己</p><h3 id="s-631" tabindex="-1">快乐 <a class="header-anchor" href="#s-631" aria-label="Permalink to &quot;快乐 {#s-631}&quot;">​</a></h3><p>我们第一次去的时候，在大门口外面，就有人小声提醒我们，进去之后不要拍照</p><p>我们是来做慈善的，一切以对方的权益为先，避免任何可能会伤害他们自尊心的言行</p><p>有一次在残障院，我负责照顾一位生活不能自理的人</p><p>他全身的关节错位，以一种奇怪的姿势拧成固定的麻花，不能活动</p><p>但因为他不能交流，我只能自己猜他想吃什么，然后找一些便于吞咽的食物，放到他嘴里</p><p>我这时突然发现，我照顾的那个人，正在随着音乐的节拍，以微不可见的幅度在</p><p>他依然保持着微不可见的律动</p><p>虽然他做不出什么表情，但在他的眼里，我就是明显的看到了喜悦</p><p>一个吃喝都不能自主的人，只能给什么吃什么、给什么喝什么的人，他们仍旧会感受到快乐</p><p>我再一次感受到了布施的力量</p><p>表面上看起来，是我们在做布施，但实际上是他们在启迪我们的心灵</p><h3 id="s-632" tabindex="-1">糖尿病并发症 <a class="header-anchor" href="#s-632" aria-label="Permalink to &quot;糖尿病并发症 {#s-632}&quot;">​</a></h3><p>在这方面，我的心态远不如丘书妍</p><p>她就能很放松的接纳一切：你谢与不谢，只是你的选择，并不能扰乱我的心态</p><p>但在隋巧花的观念里，就没有中介主动对工人好的</p><p>为了避免隋巧花的感激不断升级，我们最后只能选择被动的接受，一直到她那滔滔不绝的感激之情平静下来为止</p><p>心安理得的接受别人的谢意，对我来说，也是一门需要精进的修行</p><p>曾经有个工人跟我吐槽，说刚到新加坡，第一次过年收到老板给发的红包很兴奋</p><p>时间久了才知道，新加坡就这么个习俗，红包就是个意思</p><p>反正那会儿，三位数的红包就是大的了</p><p>丘书妍的心态比我好得多，她紧张的时候可不多</p><p>那是我第一次看到她紧张</p><p>平时都是她在照顾我的情绪，她紧张的时候，我反而不知道该说什么，只是默默的陪着她</p><p>这是她的第一句话</p><p>血糖升高，血流缓慢，一些毒素和垃圾不能快速排出体外，损伤血管内皮结构</p><h3 id="s-633" tabindex="-1">坎1宫的调整 <a class="header-anchor" href="#s-633" aria-label="Permalink to &quot;坎1宫的调整 {#s-633}&quot;">​</a></h3><p>这样，他家就不是村儿里面的最后面一排房子了</p><p>北边房子是玄武位，比自家高，玄武位有了靠山</p><p>这样，既增加了靠山，阻挡了阴气</p><p>再次抬高了坎1宫的能量</p><p>要不要我送一本风水书给你，让你看看你有多幸运</p><p>坎1宫的化解，你家碰巧全部都做到位了</p><p>我如果让你把打谷场盖上房子，屋后种上树，正北加上冰柜，再放尊菩萨，你肯定觉得劳师动众的嫌麻烦吧</p><p>我只知道隔壁村去洗肾的人，后来因为并发症去世了，而我叔叔吃满两年的药，一直没有再复发</p><p>他家的布局也一直没有再变过，屋后的树和房子也都很稳定</p><p>丘书妍的爸爸我本来也想问他要不要去吃中药的，但一想到他的暴脾气，估计不太行得通</p><p>他从住到那个房子里，就一直念叨着活着没意思</p><p>哪怕妍爸大声的呵斥她，她也跟听不到一样，就是笑嘻嘻的围着妍爸转</p><p>最多是在妍爸暴躁的时候，她避免烦到妍爸，静悄悄的从卧室躲到客厅，但是也绝不出门</p><p>我见过很多脾气很好的人，妍妈绝对能排的上第一</p><p>而妍妈是压根儿就不起情绪，看破红尘的超然</p><p>见到妍妈我才知道，不起情绪的境界更高</p><h3 id="s-634" tabindex="-1">爱的解读 <a class="header-anchor" href="#s-634" aria-label="Permalink to &quot;爱的解读 {#s-634}&quot;">​</a></h3><p>妍爸愤怒的大喊大叫道：我不要出去丢人现眼</p><p>那种宽度五六十厘米的小车，比一般的轮椅还窄，还带车把手的，方向调整灵活，又可以折叠</p><p>又是电动的，既能前进、又能后退，简直不要太方便哦</p><p>按照妍爸的性格，不骂人就是态度很友好了</p><p>小车儿是不贵，但带电池的物品物流要求很严格，尤其是车的电池还不算小</p><p>海运最便宜，但是速度太慢了</p><p>问的人还都是四肢齐全的人，就是懒得走路，看到坐着就能逛超市的小车，很眼馋</p><p>两个老小孩儿共享一个大玩具，再也不用担心妍爸想不开了</p><p>你就算被大声的呵斥，也从来不会生气的吗</p><p>这么解读的话，真是不会生气</p><p>当考虑问题时，不考虑自己，只考虑对方，你好就是我好的时候，大概就吵不起来了吧</p><p>道理是很懂了，但是一落地，我还是容易翻车</p><p>大概每个人，都有自己情绪的爆发点吧</p><p>我平时情绪基本稳定，但一遇到睁眼说瞎话、居心叵测、颠倒黑白的人，我就容易炸毛</p><p>命理师：人生下来就带着业力和习气，这是因果的能量</p><p>亲爱的友友们，下章再怼，先跟你们聊聊天儿</p><p>qq群里的图片都放在一起，不好对应</p><p>前面说过，打算把书里的图片，按照章节整理到微信朋友圈</p><p>另外也打算开公众号，发一些与本书相关的内容</p><p>今天有人提议，可以邀请感兴趣的粉丝参与到义工群，这样大家既能有一个法布施的机会，又能再学习巩固一遍</p><p>抖音或qq私聊我也可以，到时候看看报名的人数，再做统一安排</p><h3 id="s-635" tabindex="-1">被骗一辈子 <a class="header-anchor" href="#s-635" aria-label="Permalink to &quot;被骗一辈子 {#s-635}&quot;">​</a></h3><p>太好了，要保持好这颗心，那你修行的层次才会越来越高</p><p>对于仙家，我不太了解，于是便问道：仙家，不就是出马仙的意思吗</p><p>出马仙，一般是指有道行的动物附体，对人进行捆窍，仙家上身会有明显的感觉</p><p>出马仙什么人都敢帮，经常会因为不注重因果或贪财，看几年就看不了事儿了</p><p>我们大部分人都是佛道双修的，没有太多的形式，以修心为主</p><p>出道仙，更注重自身的修行</p><p>上方派的任务，是指什么类型的</p><p>修行人，哪能事事讲钱</p><p>有了本事还能保持正心正念的人，就没有那么多了</p><p>人的位置高了，就容易忘了本心，升起贪念</p><p>我不太理解，问道：只要有真本事，能为别人解决问题，贪一点也无所谓吧</p><p>最多被骗个三次两次，不会被骗一辈子</p><p>但有真本事的人起了贪念，他们可以骗人一辈子的</p><h3 id="s-636" tabindex="-1">没话找话说 <a class="header-anchor" href="#s-636" aria-label="Permalink to &quot;没话找话说 {#s-636}&quot;">​</a></h3><p>如果遇到正心正念的师父，冤亲债主一次就能化解完吗</p><p>那要看你惹下的是什么样的债</p><p>还是先好好的修自己吧</p><p>修行自己是根本，没有捷径可走</p><p>他性格很温和，就是刚到新地方，有点儿紧张</p><p>为了缓解他的紧张情绪，我没话找话儿的跟他说</p><p>但露在外面的臂膀上，长了满满的肥胖纹，就是那种皮肤上一条一条的白色裂纹</p><p>我本来就是没话找话而已，他原来胖不胖，跟我也没啥关系</p><p>就是随便聊聊天儿嘛，你不用那么紧张</p><p>赵前看起来是心思很单纯的人，临时编个说辞的话，估计他都编不出来，最后只能实话实说道</p><p>需要瞒着的事情，一般都是大事儿，而且还不会是什么好事儿</p><p>我这本想随口聊聊天儿，缓解一下气氛，无意间却挖出猫腻儿来了</p><p>他这次没有再犹豫，放弃抵抗了似的直接说了出来，不过他又补充了一句</p><p>他这次没有再犹豫，放弃抵抗了似的直接说了出来，不过他又补充了一句，不过现在已经全好了</p><h3 id="s-637" tabindex="-1">【拓展的知识点】 <a class="header-anchor" href="#s-637" aria-label="Permalink to &quot;【拓展的知识点】 {#s-637}&quot;">​</a></h3><p>如果看到了3个点及以上，就算理解的很到位了</p><p>那个头像都那么不好了，我们再点评他，是不是很不慈悲</p><p>天道会赋予我们生命，又早晚会把这些生命都收回去</p><p>如果天道只生不死，阴阳失衡，最终的结果是地球不负重荷，我们全部都不复存在</p><p>只要自己的出发点是正心正念，可以舍小情，存大义</p><p>如果讲清楚了，他本人能虚心的看进去，他就能摆脱业力的习气</p><p>如果他还是看不进去，那说明缘分还没到，再继续慢慢修</p><p>所以这章，打算就着头像，给大家展开讲点儿零散的知识点</p><p>看头像，首先看太极，就是整体的感觉</p><p>黑白画面，配红色眼睛，是什么样的感觉</p><p>一般我们形容一个人红了眼，是指哪种人生状态</p><p>其次，整个画面，眼睛颜色最突出，除了代表状态，也代表眼睛本身不舒服</p><p>大家常听说鬼压床，但很少听说有人在跑步的时候，跑着跑着突然被鬼压住不能动了吧</p><p>运动本身就是阳，阳性强的时候不容易被干扰</p><p>这就是《黄帝内经》讲的：正气足，外邪不侵</p><p>能被干扰的人，是正气不足的人</p><p>能被干扰的时间，是阳气不足的时间</p><p>所以，卧室是睡觉的地方，尤其是晚上，阴气盛，人又静卧睡着时，卧室里放招阴的物品不太好</p><p>往外拓展一下，不但是黑白照片不宜放在卧室，其他的容易招阴的物品，也都不宜放在卧室里</p><p>比如采光不好，窗户太小或者窗户上挂了很多东西，常年的阳气进不来</p><p>道理懂了，招阴的情况都不好，大家自行可以推理出无数情况</p><p>它的窗户虽然也可能不小，但扛不住房间南北太长，阳光不足以照射，这种房子也容易阴气重</p><p>再比如，又深又窄的胡同，也是容易藏匿阴邪的地方，都尽量避开</p><p>能避开最好，不能避开也无所谓</p><p>改变能改变的，接受不能改变的</p><p>能避开的避开，不能避开的就提升自己的阳气</p><p>正能量的想法，本身就是能提升阳气</p><p>正气足的人，是不受外邪影响的</p><p>阴阳是相对的，也不是绝对的不用黑白色</p><p>而书房和客厅，就适合清亮干净的风格</p><p>乾6位，代表脑子</p><p>如果家里风水乾6位受伤，容易脑子迷糊，有健忘症，甚至老年痴呆等各种脑部问题</p><p>我回复的，一般是有代表性的问题</p><p>有人给了善意的回复还被恶语相向，屡教不改的人就算了</p><p>头像暂时先说这几个点</p><p>如果你睡了别人的床，或者别人睡过你的床之后，你再睡，感觉身体发沉或凉飕飕的阴冷，可能牵扯到业力，在心里多忏悔或祷告</p><p>仙鬼是灵体，它们会感知到我们的想法</p><p>先说这些，下一章接着说正文</p><h3 id="s-638" tabindex="-1">业力是内因风水是外因 <a class="header-anchor" href="#s-638" aria-label="Permalink to &quot;业力是内因风水是外因 {#s-638}&quot;">​</a></h3><p>最后还是用的针灸，通了经络才好的</p><p>从那以后，我再也不敢依赖推背了</p><p>哪怕是再懒，该动一下还是得动的</p><p>最根本的原因还是因果的问题</p><p>或者说是业力原因</p><p>没有那样的因果，就不会产生那样的业力</p><p>没有那样的业力，就不会有这样的运势</p><p>所以，业力是通过风水发生作用的</p><p>哪怕我了解一些风水，但走到了某些时运上，脑子一热，傲慢心一起，根本就不在乎风水那点儿事儿</p><p>之前丘书妍的房间，因为镜子面积太大被盖住了，每次用都得拉帘子，后来她嫌麻烦，把帘子收了起来</p><p>我们办公室的档案柜子，没其他位置放，就放在我的侧手边，形成了角煞</p><p>这就是心理学上的自利性偏差</p><p>当事业顺利到一定程度的时候，我跟丘书妍也难免的升起了傲慢之心</p><p>但生活，早晚会教会我们做人的道理</p><p>自修，修的就是自己的谦卑之心，利他之心</p><p>谦虚的人，利他的人，不容易被业力左右</p><p>业力是种子，风水是环境</p><p>种子能不能发芽，跟环境有关</p><p>我们既要重视环境，避免业力的种子长出恶果</p><p>我们也要重视化解种子本身</p><p>风水调整，可以避免这一时，甚至这一世，让业力一直没有条件结出果子</p><p>业力是我们自己带的，要我们自己内在发心去修去改</p><h3 id="s-639" tabindex="-1">慈善与赚钱 <a class="header-anchor" href="#s-639" aria-label="Permalink to &quot;慈善与赚钱 {#s-639}&quot;">​</a></h3><p>君君问完了正北开门，又问了关于修行和慈善的事情</p><p>慈悲的人不能做这种事情</p><p>所以修行的人不能赚钱</p><p>君君前面问正北门，估计就是帮朋友问的，所以我说的尽量详细</p><p>赚钱也确实是很多修行人的卡点</p><p>修行讲的戒贪，但并没有讲戒钱</p><p>如果赚钱就是侵犯了别人的利益，那化缘给菩萨塑金身，怎么论</p><p>富人也有很多的人生苦恼，也会遇到很多困境</p><p>自己的人生困苦不堪、没有意义，所以再延续一个没有意义的人生</p><p>法华经云：诸苦所因，贪欲为本，若灭贪欲，无所依止</p><p>戒贪与赚不赚钱，没有必然的联系</p><p>穷苦的人，也可能贪</p><p>有钱的人，也可能贪</p><p>贪与不贪，与钱无关</p><p>我跟君君讲了一个修行的小故事</p><p>有两个和尚，一个叫悟空、一个叫悟了，他们都在一个寺庙出家修行</p><p>一开始他们每天都出去化缘</p><p>悟空就劝悟了，让他不要这样虚度时光，应该走到更远的地方去化缘</p><p>悟了听了很烦，反驳道</p><h3 id="s-640" tabindex="-1">天地万物都在循环 <a class="header-anchor" href="#s-640" aria-label="Permalink to &quot;天地万物都在循环 {#s-640}&quot;">​</a></h3><p>你这布袋里装满了私欲贪婪，拿出去，是化不来最好的缘的</p><p>他们继续前行，除了温饱外，他们一路化了就舍，舍了再化</p><p>光知道缘来之福的人，那只是片刻的欢愉，时间久了，就是一池死水</p><p>我们之间的区别就是，你把化来之物，放在了充满私欲贪婪的布袋里</p><p>然后才回复道：同样都是化缘，存在布袋里为自己所用，为贪</p><p>财来财去，帮助众生，为不贪</p><p>如果为了戒贪，不化缘，不接触钱财，也就没有参与到循环当中，帮人都无能为力</p><p>君君道：道理上是明白了</p><p>但对于修行者来说，从别人兜里掏钱，可能会于心不忍</p><p>我问君君：如果是你感冒了，感冒发烧流鼻涕</p><h3 id="s-641" tabindex="-1">头眼清亮 <a class="header-anchor" href="#s-641" aria-label="Permalink to &quot;头眼清亮 {#s-641}&quot;">​</a></h3><p>我是生发的阶段，是怒，是向上突破</p><p>我也知道适可而止，没有继续再胡说八道，而是转过头去批评丘书妍：你怎么能跟小青说不用当真呢</p><p>我天天跟着你大半夜的不是去钓虾，就是去喝酒，咱俩身体咋样，你心里没数吗</p><p>就算咱俩没做到，那道理还是道理嘛</p><p>道理还是没有错的，能做到的话，还是尽量做到比较好的嘛</p><p>但她竟然把我们赶了出来，她这行为，哪里像个修行的人啊</p><p>小青点出来之后，我第一反应是愣了一下，随后想了想，好像还真的是，说话太冲</p><p>我们定的是第二天上午，从上海飞青岛的机票，为了避免迟到，晚上早早的我们就跟小青散了</p><p>本来，火阿姨说我们没什么可清理的，我也就没抱什么希望，几十块钱看一看，至少知道之前的师父清理的效果不错，也算是收获</p><p>虽然我们避免第二天迟到，但对于两个胖子来说，也不能早到哪里去</p><p>算出来的阴债的十万贯，大概只需要几千个元宝</p><p>算出来的只是公债，还没算私债，也没算利息</p><p>自己还的话，大概就是这些费用，记得带书文</p><p>元宝的费用比较透明，但师父做法事的费用差别却很大</p><p>做法事也看师父道行，不一定烧了都能还上</p><p>第一次用这个软件，平台说咱的人太多了，回放没有录制成功</p><h3 id="s-642" tabindex="-1">谁来救他们 <a class="header-anchor" href="#s-642" aria-label="Permalink to &quot;谁来救他们 {#s-642}&quot;">​</a></h3><p>她师父和师兄师姐们的身份在这儿摆着，我就算好意思说，也不敢瞎说呀</p><p>不说归不说，但本来还是报着朝圣的心态来的，一看大家长这样儿，我就真的歇了所有的心思，就当是纯粹的出来玩就好了</p><p>我这个人不会隐藏想法，很多人一看我的表情，就知道我在想什么</p><p>师父就算看透我了，我也不奇怪，我本来就是透明的</p><p>现在很多修行的人，穿着僧袍、道袍，拍个视频就能装大师了</p><p>也有的，外面看着是个正常人，但内在严重的精神内耗，一肚子苦无处诉说的</p><p>虽然面相上，我没有疑问了，但修行人气色，怎么会那么差呢</p><p>我不可能直接问出来</p><p>我情商再低，也没低到那个程度</p><p>再说了，哪怕我不是很信，我也没有证据证明他们不可信</p><h3 id="s-643" tabindex="-1">索求 <a class="header-anchor" href="#s-643" aria-label="Permalink to &quot;索求 {#s-643}&quot;">​</a></h3><p>我记得之前一直想请吉月姐姐站出来，出一本书给大家讲讲修行，或者站在明面上帮助大家做做法事，拯救在苦海中挣扎的众生，但是她都很明确的拒绝了</p><p>她只帮助有缘分的人，有些人就算遇到了但德行不够的，哪怕出钱再高，她也不帮</p><p>我现在才理解了她说的意思，众生都在自私自利的索求，怎么救</p><p>就算众生很苦，菩萨想救，但能咋救啊</p><p>不讲仙家，不讲法事，只讲修行</p><p>要不咱研究一下这个灯牌，看看能不能设置观看时间的门槛</p><p>认真听你讲修行、确实是想自修的人，如果在自修的过程中，遇到了一些虚的问题，他们的发心又很正，不是无止境的贪念的那种，你是不是就可以出手帮一把呢</p><p>之前有粉丝留言想找仙家师父的，可算是有途径了</p><p>跟大家说两个注意的点</p><p>第一，虽然吉月姐姐跟仙家有关，但是还真不是普通的仙家，我后面还会写到</p><p>大家不要一上来就问仙家的事情，好好跟着修行修心就好</p><p>之前好多友友留言问我怎么修心，终于有渠道了</p><p>如果大家在修行上遇到问题，都可以在直播间问她</p><p>姐姐还有很多任务，也不一定能很快哈，她只要愿意做，早晚的事儿</p><p>第二，不要一上来就请吉月姐姐帮你办什么事儿</p><p>心走上了修行的路，心正了，再说</p><p>不要无止境的从外索求</p><p>如果她看到大家只想索求，不想自修，朽木不可雕的话，她可能就不会再继续对牛弹琴了</p><p>真正想修行的人，我们肯定能筛选出来的</p><p>我们本来是想做内部直播的，只帮助那些已经站出来的发心正的人，但是考虑到没有站出来的人里，肯定也有想正心正念修行的人</p><p>如果贪念重的人太多，我们就会改成内部直播</p><p>这事儿大家心里有数就行，在直播间里就不要提了，免得直播间被封了</p><h3 id="s-644" tabindex="-1">自助者天助 <a class="header-anchor" href="#s-644" aria-label="Permalink to &quot;自助者天助 {#s-644}&quot;">​</a></h3><p>当你自己很正心正念的努力向上的时候，如果遇到了坎坷，有德行的高人也是愿意帮助你的</p><p>但如果你一心外求，不修自己，无休无止的贪念让菩萨给你这个给你那个的，喂不饱的人，菩萨也不愿意搭理的</p><p>你见过哪位佛菩萨，是靠着天天念经，最终修成的</p><p>我甚至也有很长一段时间，天天在家念经</p><p>不念够几个小时，坚决不睡觉</p><p>意思是：佛说的这些道理，就像过河的船一样</p><p>而天天痴迷于读经的行为，无异于过了河，还背着船在负重前行</p><p>我在心里，慢慢的对师父生发出敬佩之情</p><p>佛告阿难：吾涅盘后，法欲灭时，五逆浊世，魔道兴盛，魔作沙门，坏乱吾道，着俗衣裳，乐好袈裟，五色之服，饮酒啖肉，杀生贪味，无有慈心，更相憎嫉</p><p>魔是披着法的外衣，伪装成佛家（或者道家、仙家），来迷惑人心，诱发人无穷的贪念和嗔恨憎恶之心</p><p>甚至有的师父直接就开口索要：‘你对佛菩萨要舍得再舍得</p><p>快去给菩萨再多添点儿，不要让菩萨怪罪</p><p>遇到这种情况，我是绝对不会再添的</p><p>要是佛菩萨眼里都是钱，给少了就生气怪罪，那她的境界比不如我呢</p><h3 id="s-645" tabindex="-1">贩卖老仙儿 <a class="header-anchor" href="#s-645" aria-label="Permalink to &quot;贩卖老仙儿 {#s-645}&quot;">​</a></h3><p>吉月姐姐道：是的，不要出去乱拜</p><p>我这个人主打一个听劝，有可能犯毛病的话，那不去就是了</p><p>只要你心不正，起了贪念，对他有所求，他满足了你的同时，就可以控制你</p><p>是不是就是抓了这些人的仙家，拿网上卖的</p><p>安静了好一会儿，她才感叹道：唉，人心的贪念，得有多么多啊</p><p>只要有贪念，那就是邪魔害人的切入点</p><p>（篇外话：抖音上就有很多卖老仙儿的，大家不要被骗了</p><p>刚刚元神出窍那位，就是五姐</p><p>现在再看，不但气色恢复了，五官都变得更立体了，已经完全看不出来原来的样子了</p><p>是换身衣服的功夫，再出来就大变活人了</p><p>我的认知再次被颠覆</p><p>第一，吉月姐姐在哪里直播</p><p>第二，读《地藏经》感觉不舒服，什么人适合读</p><p>第三，头像的问题</p><p>第九，怎么修行，从哪里开始</p><h3 id="s-646" tabindex="-1">正气不是软柿子 <a class="header-anchor" href="#s-646" aria-label="Permalink to &quot;正气不是软柿子 {#s-646}&quot;">​</a></h3><p>吉月姐姐直播，会选快手或微信，测试好了我在书里告诉大家</p><p>这种情况下，就先不要读</p><p>先去多读读《金刚经》或者《道德经》</p><p>为什么先读这两本，新书的开篇里会讲到</p><p>适不适合读《地藏经》，很容易辨别</p><p>这种情况，就先去读《金刚经》和《道德经》破相</p><p>大家都在说的是同一个道理</p><p>后人走了极端，有人以为去人欲就不能讲风水</p><p>去人欲去的是贪念，回归天真的本性，也就是咱们说的修真</p><p>尤其是前两天大批粉丝让我联系火阿姨，一家人一家人一起做，这也算是了</p><p>你风水上不招阴邪，你自身正气养的很足，就不会一家人全都中招</p><p>一切有个度，风水方面留意，但是也不要过于执迷</p><p>另一个是，修自身的正气，修自己的脾性</p><p>有些人以为，不发脾气就是正气</p><p>大家要记住，正气不是软柿子</p><p>有个成语叫正气凛然，大家慢慢体会一下</p><p>这是修行的重要标准</p><p>吓的我都不敢看第二眼</p><p>邪气重的地方，容易有黑猫出现</p><p>倒不能说是黑猫招来的，而是它喜欢那种氛围</p><p>我们尽量不要用猫做头像</p><p>大家做多练习，慢慢就找到感觉了</p><p>看到问题了，再对应家里的风水慢慢清理</p><h3 id="s-647" tabindex="-1">写给抑郁的人 <a class="header-anchor" href="#s-647" aria-label="Permalink to &quot;写给抑郁的人 {#s-647}&quot;">​</a></h3><p>也许在您看来，可能不是多大的事情，但是关于这件事，我还是有很大的疑惑，想向您请教</p><p>为什么我从小到大就在还债欠钱，是不是真的是业力</p><p>所以我其实大学期间想考研，当时的认知就是觉得有个985，211能找个稳定点的工作，毕竟我没有什么抗风险的能力</p><p>所以最后考研的梦，也随着工作多年也快碎了</p><p>都说为何不告诉父母，让父母帮衬，我本就是独生子女，父亲吸毒，常年填坑，现如今就我妈一个人在超市工作</p><p>没有任何存款，告诉他们只会徒增苦恼</p><p>他们本就是农村家庭，平时带带孩子，哪有存款</p><p>告诉他们也只是徒增烦恼，现如今能帮我带孩子已是不错</p><p>我也疑惑他有老婆孩子，为啥不努力工作呢</p><p>后悔无用，当知道这些道理的时候，事情已经发生了</p><p>今年9月份，有幸遇到您，念了地藏经以后，感觉想通了很多，我觉得我还是会坚持活下去的，至少，不能让我的孩子，走我的老路</p><p>现在尝试晚上看能不能做点抖音，因上努力，果上随缘</p><p>所以在故事的末尾再次提出是业力问题吗</p><p>有没有什么向外求的东西，能让财运稍微变好一点，我也愿意吃苦努力，确实没啥方向，我财务工作，现在做财务也不值钱</p><p>我觉得我还是会坚持活下去的，至少，不能让我的孩子，走我的老路</p><p>所有在绝望中的人，当你会替他人考虑的时候，就是善念开始生发的时候</p><p>你希望孩子能好好活着，这个善念给了你自己好好活着的力量</p><p>我写这本书之初，只是想跟大家讲讲风水，让大家不要受到风水的伤害，也不要被骗子大师忽悠了</p><p>我自己先依次试过了，又给自己的家人试过了，感觉不错才推荐给大家的</p><p>遇见她们也跟丘书妍无关，而是有其他人一起遇见的，只是故事讲到这里，我不能硬跳的太远，才换了丘书妍的角色写在故事里</p><p>这也是为什么反复跟大家强调，不要一味的索取</p><p>再重复一遍：你愿意给出去的，才是你会收获到的</p><p>给出去的，就是收获到的</p><p>你们现在计算着，我一个月赚万八千块钱，还要养家，欠款几十万那就是个无底洞</p><p>那只是你目前所在的这个维度的计算方式</p><p>有道是，人算不如天算</p><p>据说马云的第一份工作是老师，月薪91块钱</p><p>网上根据阿里市值，推算出他一天可以赚到几千万</p><p>从月薪91块钱，到日薪几千万，如果用大脑去规划，是算不出来这个账的</p><p>计划，只能计划自己认知以内的事情</p><p>而富贵，一定是突破了你原来的认知</p><p>这不算是个贬义词，这是事实</p><p>算，只会让自己固化在自己的认知里</p><p>靠脑子去计算，是算不出来认知以外的富贵的</p><p>正心正念的去做就好，其他的不用自己去费脑算计</p><p>比如有人跟你说有一个投资项目，你交10万块钱，他返给你500，你的第一感觉是什么，真相就是什么</p><p>别再听他讲什么国资背景、扶贫项目，一旦开始动脑分析真假了，就容易被绕进去</p><p>为了你四位数的学费，把日入五位数的赚钱秘诀告诉你</p><p>再比如，偷盗和诈骗，他们赚不赚钱</p><p>要在金钱上翻身，先得调整心理</p><p>不要怕自己没钱，忘记赚钱这件事情</p><p>赚钱之前，不要盯着钱本身，而是要问问自己，我能帮助到别人什么</p><p>把注意力放在做事儿上</p><p>再三推辞无效，只好接受了她的心意</p><p>到最后，我收获了案例，两边的人还都在谢谢我</p><p>钱的问题说完了，再说说心态</p><p>如果一件事情让自己心里不舒服了，无底线的包容，不断的有苦往肚子里咽，是不是也违背了阴阳之道</p><p>如果压抑自己，不断内耗自己，逼到自己起了嗔恨心，那就容易入魔</p><p>照顾别人之前，请先照顾好自己</p><p>在自己失控之前，先把桌子给掀了</p><p>不要过分的苛刻自己，该掀桌子就掀桌子</p><p>不论掀不掀桌子，都是为了保持正念，不要被愤恨蒙蔽了心智</p><p>至于说业力，那是累生累世的事情，我们改变不了过去，那就先做好当下好</p><p>当下做好了，再解决业力的事情</p><h3 id="s-648" tabindex="-1">情绪是修行的重要指标 <a class="header-anchor" href="#s-648" aria-label="Permalink to &quot;情绪是修行的重要指标 {#s-648}&quot;">​</a></h3><p>修行，可以说是修脾气</p><p>也可以说是控制自己的念头</p><p>也可以说是修情绪</p><p>能控制自己的念头，才会不起情绪，才会控制住自己的脾气</p><p>用到压制这个词，意思是内心已经起了情绪</p><p>有火不发，内耗自己，就算不发脾气那也不算修行</p><p>不乐意了，硬憋着，那可能是有礼貌，但肯定不是修行</p><p>修行，是符合阴阳之道的</p><p>如果自己的家人不断地去网赌，自己气的要命，还顾虑着家和万事兴，不断地容忍，不断地替他去填窟窿，把自己都内耗成抑郁症了</p><p>这种不发脾气，能是修行吗</p><p>修行修到不想活了</p><p>天作孽犹可违，自作孽不可活</p><p>卡在情绪里出不来的人，梳理一下阴阳</p><p>那些让自己不开心的人，那些让自己不开心的事儿，是否符合阴阳之道</p><p>可以先保护自己，也可以舍己为人，两者都有没问题，只要是自己愿意的就行</p><p>比如佛祖割肉喂鹰，他心甘情愿就行，他维护了他内心的平衡，他这样做不会内耗</p><p>但如果我们都像佛祖一样，用自己的肉去喂动物，那我们不乐意，我们硬做就会内耗</p><p>怕就怕既不想补，还想落个兄友弟恭的好名声，那就是属于既要又要了</p><p>理清了这些思路，不起情绪，自己内在和谐了，就是修行</p><p>一旦起了情绪，魔就入心了</p><p>所以修行，修的是正心正念</p><p>如果有些事情让我们不开心了，梳理一下原因在哪里，在情绪失控前处理掉</p><p>只要不是既要又要的贪念就好</p><p>有了贪念也无所谓，找到自己愿意付出的东西去交换</p><p>满足阴阳平衡就可以</p><p>再者，所有的事情，都有阴阳两面儿，这面看着不得劲，就看看另一面</p><p>也是认知疗法，即情绪Abc理论</p><p>A是事件，b是解读，c是结果（包括情绪和行为）</p><p>如果你解读为侮辱，那你可能就会生气，甚至会反手打回去</p><p>这就是说，不同的解读方式，会造成不同的情绪和心境</p><p>苦难看成是苦难，那就是苦难</p><p>不会转念的可以看一下《一念之转》，我放橱窗里了</p><p>总结一下，修行修的好不好，看情绪</p><p>不是表现出来的情绪，而是内心的真实情绪</p><p>情绪是活力的象征</p><p>小孩子睡觉时都眉开眼笑的，这是情绪好，这是活力旺盛</p><p>睡觉时也在愁眉苦脸的人，那就是情绪不好，这是死气沉沉</p><p>突破一切阻碍，保护好自己的情绪</p><p>问题先回答到这里，后面开始进入正文</p><p>最后送给大家一个小练习</p><p>（问东四命是因为微信号，看不到先不说了，也还没有讲到</p><h3 id="s-649" tabindex="-1">你的心是不是自由的 <a class="header-anchor" href="#s-649" aria-label="Permalink to &quot;你的心是不是自由的 {#s-649}&quot;">​</a></h3><p>走吧，先下去吃早饭，买眼药水儿，去工作室</p><p>别管什么气色不气色了，就这么个搓搓强度，还能精神饱满的在忙忙叨叨的准备各种法事，就已经很不容易了</p><p>人之所以要不断的修行，就是因为各人有各人的卡点，有想不明白的人或者事儿</p><p>所有的苦，都是因为你的某个贪念没有满足</p><p>破除了贪念，痛苦就消失了</p><p>心理学上有个词叫自由的注意力</p><p>注意力就是生命力</p><p>自由的注意力越多，生命力越强，人就越快乐</p><p>就像刚出生的小宝宝一样，全部的注意力都是自由的，它看到什么都很开心</p><p>求而不得的时候，注意力就被粘在这件事情上了</p><p>随着我们的欲望越多，我们被粘住的注意力越多，可供支配的注意力就越少了，我们就会越来越不快乐</p><p>你的注意力有没有被各种欲望粘住</p><p>没有失望，就不会起情绪</p><p>学会接受了，贪心就放下了</p><p>但显然，有人收不到师父的意思</p><p>是什么原因导致了他这样呢</p><p>很多婚姻关系，看似是对方不可理喻，但实际上一般是一个巴掌拍不响</p><p>虽然前面听师父讲过破相的事情，但是人是有惯性思维的</p><h3 id="s-650" tabindex="-1">修正气 <a class="header-anchor" href="#s-650" aria-label="Permalink to &quot;修正气 {#s-650}&quot;">​</a></h3><p>前几天也有人问，那这一章就先写写冤亲债主</p><p>写冤亲债主之前，先回答一位友友的问题：情绪跟正气有什么关系</p><p>好多人都知道正气足，外邪不侵，但是一直不能理解什么是正气</p><p>所以我们换了个词儿叫情绪</p><p>情绪大家就比较容易理解</p><p>那这两者是什么关系呢</p><p>举个简单的例子，虽然大家很难形容什么是正气，但你觉得情绪低迷不振、或者心里嗔恨嫉妒想杀人，这是正气吗</p><p>情绪是正气的指标</p><p>我们不容易把握正气，但是我们很容易感知到自己的情绪</p><p>情绪状态不是喜悦阳光的时候，正气不可能足</p><p>也可以称之为阳气</p><p>你能想象一个心情不好但阳气很足的人吗</p><p>阳气足，心情一定很不错</p><p>即使遇到让自己心情不好的事情了，阳气足的人也不会把它当回事儿，不会影响到情绪</p><p>当你能被影响到，就说明阳气不足，或者说，正气不足</p><p>升阳了，情绪就好了</p><p>阳气和正气不容易把握，那我们就随时感知自己的情绪就好了</p><p>这里先解释一下情绪的重要性，修行修心，也可以说是修情绪</p><p>如果我们能控制住自己的念头，我们是希望制造更多快乐的念头，还是愤怒的念头儿呢</p><p>但为什么我们还是会愤怒呢</p><p>因为我们控制不了自己的念头</p><p>所以说，修行是修心，修念头，不让自己的心绪飞扬、胡思乱想</p><p>也可以简单的说，就是修情绪</p><p>因为情绪我们比较好感知到，把修行落实到修情绪上，大家比较容易有概念</p><p>修情绪=修心，很重要，后面还会讲到，今天先写说这些</p><p>鬼这事儿，不要把他们想的太玄乎，类似于现在科学界所谓的中微子</p><p>科学界对中微子的定义：个头小、不带电，可自由穿过地球，自旋为1/2，质量非常轻（有的小于电子的百万分之一），以接近光速运动，与其他物质的相互作用十分微弱，号称宇宙间的</p><p>我们就可以把它们想象成，就是差个身体</p><p>首先，态度要诚恳</p><p>那就费点儿事儿，再多拿出点儿诚意呗</p><p>大部分债主也不想麻烦，它们也想早点儿结了账，该干嘛干嘛去</p><p>跟咱们的心态差不多</p><p>咱都已经诚心诚意的赔礼道歉了，它们还恨的牙根儿痒痒的，非得弄死咱的，也可能会有，但很少很少</p><p>比如杀生债，往生债（欠债没还人就走了，这笔债一直在），轮回债，情债，损伤债，偷盗债，抢劫债，宗教信仰债（借助宗教做坏事等），欺压百姓债，轻生债，弃婴债，口舌债，破坏债，讨债债（替人讨债担别人的因果），欺压儿女债，功绩债（没完成自己的使命），亏孝债等等等等</p><p>吉月姐姐说，这几天有人找到她，问题多的人，基本把上面列的这些债都占全了</p><p>化解冤亲债主的恩怨，跟咱们的情况也差不多</p><p>就把它们想成跟人一样的思维就行</p><p>比如它这一世要追五个人的债，正气足的人，它一时拿他没办法，它也知道先放一放</p><p>它们就是没有形体的人，它们也会算账儿</p><p>其他的债主不知道你能还了，它们还只是在伺机等待，等能搞的动你的时候再出手</p><p>几百口子，几生几世的跟着咱们讨债，凭啥轻飘飘几句话，它们就能放下那么久的仇恨</p><p>后面再出现的债主，是之前没收到通知的</p><p>吉月姐姐不给做的，大家也不要勉强，继续好好修自己，缘分没到强求不来</p><p>大家先把自己过好了，好好修行自己</p><p>等你有能力了，你再去帮助别人</p><p>就算到了那个时候，也要等到人家求到你了，再帮</p><p>她们再难再急，她们自己的心性不够，缘分没到，你瞎着急也没有用</p><p>好好修行，先成长自己</p><h3 id="s-651" tabindex="-1">夫妻宫 <a class="header-anchor" href="#s-651" aria-label="Permalink to &quot;夫妻宫 {#s-651}&quot;">​</a></h3><p>师姐在抱怨她老公对她冷暴力的时候，她并没有考虑到为什么</p><p>总不可能婚前就这样，故意找个这样的人结婚了</p><p>改变的原因是什么呢</p><p>巴拉巴拉，后面跟着一堆的抱怨和指责，她的注意力没有跟着师父转向内观，没有看到自己的问题</p><p>或者直接推荐她自己回去看看《一念之转》</p><p>虽然我认为自己也是个注重修行的人，但是有时候，我仍然会不知不觉的就被自己的习气给带偏了，丢失了醒觉的心</p><p>《一念之转》的作者拜伦·凯蒂，在30多岁时曾患上了重度的抑郁症，她甚至几乎下不了床、一心想着自杀</p><p>突然的一天，她在绝望中醒悟，明白了事实才是真相，发明了4句话转念法</p><p>遇到让自己不开心的事情，先问自己</p><p>通过这四句话，审视自己的内心，挖掘出内心最真实的想法，并且化解掉其中的戾气</p><p>那让你生气的那个观点，还是真的吗</p><p>比如，老公对我冷暴力我很生气，他不应该对我冷暴力</p><p>事实的真相是什么呢</p><p>事实就是真相，生气是在跟事实争辩，跟真相对抗</p><p>持有这个想法时，你会怎样</p><p>不持有这个想法时，你会怎样</p><p>而我们要做的就是——尊重别人的事，管好自己的事</p><h3 id="s-652" tabindex="-1">一念之间 <a class="header-anchor" href="#s-652" aria-label="Permalink to &quot;一念之间 {#s-652}&quot;">​</a></h3><p>比如，抱怨老公不爱自己的人，自己有好好爱老公吗</p><p>修行修的是自己，而不是拿着道理去教育别人</p><p>把看别人这也不对那也不对的注意力收回来，这是自己的事儿</p><p>师父还在引导着师姐把关注点放在修自己身上时，旁边坐着的另一位师姐突然元神出窍了</p><p>我是看不到元神出窍的，但其他师兄师姐会马上就知道了，并非常默契的无声无息的靠过去护住她</p><p>元神出窍都是上边又下达任务了，我们外行看热闹，内行看门道</p><p>法界那边与人间是对应着的</p><p>一念天堂一念地狱，是真实存在的</p><p>人类的贪念和嗔恨心越重，就越会增加法界邪恶的力量，魔军的势力就会越强</p><p>人间的正念越少，正仙的力量就越弱</p><p>法界的存亡，在于我们每个人的一念之间</p><p>现在，人间大多以利益为先，贪无止境，正仙在保卫战争中非常惨烈，既缺医少药，又没有武器</p><p>法界被魔占领，对应着人间就有各种不公、战争、瘟疫和自然灾害等不好的事情发生</p><p>唤醒人们心中更多的善念，是法界存亡的唯一出路</p><p>我们现在，就是要协助法界度过这个危险的时刻</p><p>于是，师父带着大家开始做法</p><p>然后师父指向我，问道</p><p>这一次是元神出去做任务</p><p>法界那边打仗，法界是指哪里啊</p><p>人间跟法界的对应关系是怎么对应的</p><p>一念天堂一念地狱是指人的念头可以决定法界和人间的存亡吗</p><p>我这儿有一堆的疑惑没想明白</p><p>我怎么会知道法界带回来的话儿是什么呢</p><p>我们的心是什么都知道的，只是被习性或者情绪蒙蔽住了</p><p>就像刚学骑自行车的时候，又要注意扶手正，又要保持身体平衡，还得配合脚的速度，太慢车子就倒了</p><p>但真正会了的时候，那些需要注意的东西都可以丢了，骑就是了，不需要脑子再提醒了</p><p>歪着斜着都能骑，不必再拘于条条框框</p><p>再给大家拓展几个小知识点</p><p>阴阳平衡，体现在各种细节之处</p><p>好多人希望祖先保佑，我们跟祖先之间，也遵循阴阳的关系</p><p>这个天门，讲的就是乾6位</p><p>在地支的墓库方面，对应的是戌</p><p>这个月又是甲戌月，是比较适合做阴事的时间</p><p>乾既是天门，又是男主人，也代表着脑子，还对应着大肠</p><p>第一个练习是，回答下图的问题，风水上如何调整</p><p>第二个练习是，判断头像性格</p><h3 id="s-653" tabindex="-1">佛魔难辨 <a class="header-anchor" href="#s-653" aria-label="Permalink to &quot;佛魔难辨 {#s-653}&quot;">​</a></h3><p>这些每天都要用，天天跟化工接触，太不健康了</p><p>我记得智策师父好像就有比较健康的配方哦</p><p>哪怕有时间，跟商业相关的事情，我们也都不太适合</p><p>零食，回去可不能吃了啊，都是防腐剂和添加剂</p><p>食品和保健品，你也打算要自己研发吗</p><p>不能不能，吃的东西，还是直接去地里薅新鲜的最好，不做研发</p><p>不然，就算你生产出来了，又如何跟魔的产品区分出来呢</p><p>还是得把注意力放在唤醒更多的人上面，这比我们自己去研究个啥天然产品更重要</p><p>大家能见到的那些仙家们，有几个是正心正念的呢</p><p>（这里的仙家不是指有道行的仙，而是指借着仙胡作非为的人</p><p>所以我每天都感觉自己好忙，忙着去点醒更多的人</p><p>只有放下脑子，不断地修行，心思纯净了，慢慢的用心去感受</p><p>经历过之后，再走高速，那是真舒畅啊</p><p>再次上路的时候，吉月姐姐跟我们分享了刚刚有人让她查童子，之前在别处已经还过了，但是孩子的状态还不如没还之前，妈妈心里犯嘀咕，就让吉月姐姐帮忙查一下，是不是没还上</p><p>吉月姐姐跟我们讲道：如果没还上，最多就是被骗了点儿钱</p><h3 id="s-654" tabindex="-1">除了自我成长其他都不真实 <a class="header-anchor" href="#s-654" aria-label="Permalink to &quot;除了自我成长其他都不真实 {#s-654}&quot;">​</a></h3><p>法力强一点儿的仙家，可以帮忙还到庙里去修行，这就算不错的了</p><p>吉月姐姐蹙眉道：能是能，但是很麻烦</p><p>先得查还去哪里了，再得查他原本应该是哪里的</p><p>然后，再做法事，还到他该去的地方</p><p>所以，如果不是足够信任的，千万别随便做法事</p><p>心不稳的人，还是得先修心</p><p>不论是你帮助他们调整风水，还是我帮助有缘人清理业力，都是为了助力他们的自我成长</p><p>如果人们把风水和业力清理作为了终极目标，清理好了又转头去追名逐利，放弃了自我修行，那是很可悲的</p><p>万法皆空，因果不空</p><p>吉月姐姐道：是啊，真正的修行人，一辈子都在修行</p><p>正心正念的人，尚且需要修一辈子，那些心性不定的人，又何德何能期待自己可以万事无忧呢</p><p>我是很想对深陷沼泽的人伸出手</p><p>因为我一旦拉了他一把，就会引起他心中无限的贪念</p><p>也难怪有人说，可怜之人，必有可恨之处</p><p>如果自己不转念修正道，别人想帮都不敢帮</p><p>无限的贪念，谁敢伸手拉</p><p>我也是要不断的去修自己，遇到心性不够的人，不能轻易去帮</p><p>让生活慢慢的磨砺吧，一直磨砺到他们生出坚定向善的心</p><p>我第一次见到被拒绝后不断纠缠，还到书里留言质疑是骗子的</p><p>没收你钱，都被你怀疑</p><p>佛能割肉喂鹰，咱境界不到，咱就做自己认知内的事情就好</p><p>这就是本章讲的，心性不稳的人，帮了反而会激发很多负面的念头</p><p>只要是正念修行，早晚会有缘分的</p><p>第601章《做法事儿需要知道的事儿》里面已经说过了，这里再提醒大家一次，如果感觉自己可能心性还在摇摆的，先不要做法事</p><p>所有可能让自己起负面情绪的事情，都保持距离，等心性稳了，能辨别真假了再说</p><p>大家可以一直默默的学，感觉学到东西了，或者经过自己验证了，觉得有收获，再去尝试需要付费的内容</p><h3 id="s-655" tabindex="-1">正心正念的人能不能收钱 <a class="header-anchor" href="#s-655" aria-label="Permalink to &quot;正心正念的人能不能收钱 {#s-655}&quot;">​</a></h3><p>君君没想到，我二话不说，第一件事情竟然是先掏出了收款码</p><p>她不能理解，我这会儿对着君君的朋友要随喜红包，这是几个意思</p><p>其中那位瘦一点朋友的开口道：我听君君说，你也是修行人</p><p>如果是正心正念的修行人，怎么会开口就收钱呢</p><p>你认为正心正念的人，就不应该收钱</p><p>甚至还有点儿生气</p><p>正心正念的人不应该收钱，所以，你们认为，钱就应该送给那些不正心正念的人，才是对的</p><p>正心正念的人不该收钱，那在你们的潜意识里，你们认为钱应该流向哪里去</p><p>然后用眼神儿示意我，让我把收款码再拿出来</p><p>我当做没看见，继续讲道：我记得大部分的门派，都说的是修行人要戒贪</p><p>没听说过修行的人就不可以收钱</p><p>另外，修行修的是自己</p><p>但你们不允许我收，那是你们在用你们所认为的道理，在修行我</p><p>而是打着修行的名头，用评判的眼光在看外面的人，这也不顺眼，那也不顺眼</p><p>我从早到晚的念叨他，嘴皮子都磨破了，他也不学</p><p>这样想想，好像我确实是把注意力都放在看别人的缺点上了</p><p>我也知道修行人要保持心平气和，但是任谁看见那孩子油盐不进的样子，都得火冒三丈吧</p><p>也就是说，你说一遍他不听，说十遍他还不听</p><p>你天天说，他天天不听，你就月月年年的重复念叨他</p><p>对呀，那怎么办，总不能不管他吧</p><h3 id="s-656" tabindex="-1">父母凭啥赚那么少的钱 <a class="header-anchor" href="#s-656" aria-label="Permalink to &quot;父母凭啥赚那么少的钱 {#s-656}&quot;">​</a></h3><p>你但凡用点儿心，你能把一套说了没有用的说辞一天十遍八遍的反复念叨</p><p>她终于不再一直盯着孩子说事儿了，慢慢的安静了下来</p><p>你知道批评孩子得分少，那如果孩子天天念叨你赚的少，你就能因此而赚更多的钱了吗</p><p>她慢慢反应过来了</p><p>君君轻声道：如果孩子从早到晚的问，妈妈你为什么不是最有钱的人，你为什么不努力，你能不能使使劲儿多赚点儿钱，如果孩子年年月月的这么念叨，做父母的心里也会不得劲的</p><p>那父母一直念叨孩子，孩子应该也很难受吧</p><p>胖乎乎的朋友眼眶有点儿红了，但是能看的出来，她的注意力还在孩子身上，还是在想着怎么修行孩子</p><p>你知道孩子的使命是什么吗</p><p>念了又没有用，还天天重复着没用的动作</p><p>那就好，心先摆正了，再说其他的事儿</p><p>知道把注意力放在修自己上面，这是首要条件</p><p>在此基础上，再可以看一下是否能借助外力</p><p>不知道有煞是什么意思</p><p>虎皮兰，龙骨，仙人掌，金虎等等，全部都算带刺</p><p>哪怕大人天天念叨孩子，孩子未必忍心反过来责怪父母不努力</p><p>孩子学习不好的话，也有可能是受风水的影响，也有可能是因为业力的原因受一些阴性能量的干扰，也有可能是他有他自己的使命</p><p>就算天天在家躺着的啃老族，难道他不想赚钱吗</p><p>想，但是做不到，那我们就找找做不到的原因是什么</p><p>不要打着我为你好的幌子，去欺负孩子</p><h3 id="s-657" tabindex="-1">无条件的爱 <a class="header-anchor" href="#s-657" aria-label="Permalink to &quot;无条件的爱 {#s-657}&quot;">​</a></h3><p>不要打着为孩子好的幌子</p><p>不要打着……为孩子好的幌子</p><p>她在慢慢的重复着，突然，她眼睛一亮：我如果是无条件的爱孩子，我就不应该只是批评他，而是要想办法陪他一起培养学习兴趣，或者找其他的他感兴趣的方向</p><p>就算各种办法都试过了，仍然不行也无所谓</p><p>对对对对，我确实是光修行别人了，没有好好修行自己</p><p>我又跟她说了一下命宫怎么算，1349的命宫，进1349的房间，睡1349的方向</p><p>从一开始，你们俩的潜意识里就认为，修行人不应该收钱，收钱的人都心术不正</p><p>但你们又自诩是修行人，所以，你们的经济上应该不会很宽裕</p><p>都讲到阴阳平衡了，我只好开口说道</p><p>你今天怎么一开始，不直接说风水哪里有问题，反而先拿出收款码晃一下呢</p><p>跟吉月姐姐聊天，我明白了一个道理，一切先修心</p><p>心不正，单调风水或者做法事，他容易起质疑</p><p>一念天堂，一念地狱</p><p>哪怕是身体健康的人，总是疑神疑鬼的，没毛病也能想出毛病来</p><p>所以，让她们保持正心正念、避免胡思乱想很重要</p><p>不然，调了风水或者做了法事，往上给他拉升了30分，她再怀疑，起了负面情绪往下拽了40分，这算搞了个啥</p><p>先修心，再说其他的</p><p>心如果不能正过来，我就不点她们了，何必费力不讨好呢</p><h3 id="s-658" tabindex="-1">人本来就是人，何必费劲去修人 <a class="header-anchor" href="#s-658" aria-label="Permalink to &quot;人本来就是人，何必费劲去修人 {#s-658}&quot;">​</a></h3><p>古人的事儿确实是不好定论，各有各的说法，我主要是提醒他不要全盘接受主流观点而已，点到为止就好</p><p>鼻翼为财库，此处有痣，代表漏财</p><p>再比如，他后面的发际线很低</p><p>这里代表的起运的时间</p><p>再比如，他是典型的八字眉</p><p>这只是说的眉毛的形状向下，如果是眉毛的毛长的方向朝下，则容易抑郁</p><p>我既不能阻挡他破财，也不能改变他起运，更不能改变他的性格</p><p>要先讲面相，说这个对我更有帮助</p><p>现在，光说了个额头，掀了个刘海，这就讲完了</p><p>智策师父看出了我的意思，他打圆场道：相由心生，心变了，相就变了</p><p>智策师父没着急回答，而是先给我们每个人依次添了茶，这才慢悠悠的说道：修行这两个字，太复杂</p><p>人本来就是人，何必费劲去修人呢</p><p>简单来说，不要想太多，没有分别心了，那么，我就是我</p><p>涛哥端起了茶杯，慢慢的品着，一时没说话</p><p>人在运势低落的时候，脑子反应也会有点儿慢</p><p>人本来就是人，何必费劲去修人</p><p>想得越多，就越不能做自己</p><p>人被各种理念束缚，不断地压抑自己的天性，时间久了，人就偏离了人</p><h3 id="s-659" tabindex="-1">水利万物吗 <a class="header-anchor" href="#s-659" aria-label="Permalink to &quot;水利万物吗 {#s-659}&quot;">​</a></h3><p>智策师父慢慢把话题引导到了压抑和抑郁的方向</p><p>有些心路，得自己慢慢走过去</p><p>我们要像水一样的话，还是要利他呀，要多考虑别人的感受和想法</p><p>我们从小就念叨，念叨习惯了，就会全盘的接受了被灌输的思想，却极少去反思，这样说对不对</p><p>上善若水，就跟《道德经》讲的天地不仁以万物为刍狗的意思接近</p><p>水就是水，水有水的规则</p><p>它是没有喜好的，它只是遵循着它自己的规律而已</p><p>我讨厌我自己，跟违背天道是什么关系</p><p>自己的欲望不能满足的时候，人就有了不同的选择</p><p>我们能做的，就是允许已经种下的果发生，并修正自己的行为，种下新的因</p><p>涛哥又念叨了一遍</p><p>智策师父笑道：因果不空啊</p><p>心和脑是两个方向</p><p>涛哥没说话，我接着道出了我自己的观点：因为我们在跟周围的人比</p><p>包括我们为人处世时，总考虑自己是不是道德，是不是善良的时候，看似是在为别人考虑，其实也是在考虑自己</p><p>涛哥想了想道：对，有道理</p><p>涛哥说的很现实，人有时候就是这样被困住了</p><p>你是不是觉得，真实的表达自己，就是自私</p><p>人会抑郁，就是考虑太多了，为别人考虑太多，也为自己考虑太多</p><p>被世俗的条条框框绑住的人，很难去掀桌子，因为他们宁可自己内耗，也不允许自己那么自私的不管不顾</p><p>上善若水，看似不仁，但正是因为它爱自己，遵循自己的道，不活在别人的嘴里，不管别人赞美它还是骂它，它都坚定的做自己，最终才能帮助到更多懂得遵循这个规律的人</p><p>不要被一些小猫小狗的言论所绑架，不必为一些不必要的人起情绪，做回自己，才能帮助到更多的人</p><h3 id="s-660" tabindex="-1">怀疑耗费正气 <a class="header-anchor" href="#s-660" aria-label="Permalink to &quot;怀疑耗费正气 {#s-660}&quot;">​</a></h3><p>然后就没有然后了</p><p>看起来她也就是顺嘴问问，满足一下好奇心，也没想正式解决</p><p>她都不着急，我不可能给她推荐啥</p><p>知道了也没有用，以目前我的水平，就算知道了也做不了啥</p><p>我只知道人在安静的情况下，比如说禅修、冥想、打坐等时候，神魂很容易被惊动</p><p>能力弱小的时候，就先小心保护好自己</p><p>再慢慢的修行，不断地提升</p><p>修行，其实说到底，是去除自己的欲望</p><p>别人以满足我们的欲望为借口，就会诱惑我们去做一些不该做的事情，也就是所谓的入魔</p><p>有欲望，我们就会起情绪</p><p>欲望没有被满足的时候，就会失望，甚至愤怒</p><p>修行说是修品行，修脾气，修情绪，修念头，归根结底是修欲望</p><p>不贪心，不愤恨，不愚痴，不傲慢，不怀疑</p><p>当人不贪心，情绪稳定的时候，我们就有分辨能力，不必疑神疑鬼</p><p>怀疑是用脑子怀疑的</p><p>只要是对众生好的事情，就可以做，不必去怀疑</p><p>如果哪一天，天道不公，天道不再是为了众生在做事，那我们也不必愚忠</p><p>为了众生的利益（不单单是人类），就是正途</p><p>这个很容易迷惑，大家要注意分辨</p><p>用吉月姐姐的话说：修行，修的是本心，是真心，也是谦虚</p><p>修行是做减法，把身上不好的一点点减掉</p><p>我这边还在慢慢琢磨着越执迷于什么，什么就越不如意的说法，突然接到了李雪的电话</p><h3 id="s-661" tabindex="-1">讲几个笑话 <a class="header-anchor" href="#s-661" aria-label="Permalink to &quot;讲几个笑话 {#s-661}&quot;">​</a></h3><p>往下讲之前，先澄清一个点，上章末尾的习题，总共是三个人</p><p>（找不到合适的词描述，或者说一种无形的情绪</p><p>差的这点儿意思，我找不到合适的词形容，暂且称之为神情（不是特指整容的意思哈）</p><p>不局限于某一个五官，就是整体的看，侧重于中下部位</p><p>再细了我就不说了，不知道谁是谁的偶像，说多了容易挨骂</p><p>（这里也没有说她们不好的意思哈</p><p>人无完人，我们每个人的人生都不完美，这就是一个小练习哈</p><p>要还是看不出来也没事儿，后面找其他机缘再练</p><p>下面再给大家讲个笑话</p><p>昨天看到友友们在讨论番茄一本很火的讲修行的书，我今天去看了一下</p><p>作者说，佛法是违背根本逻辑的</p><p>听起来是不是很有道理</p><p>这个观点，是作者在书的中间偏后的位置提出来的</p><p>打着修仙和正道的旗号，写了大几十万字，可算是洗了不少人</p><p>所以推理出，因为我是人，所以你不是人</p><p>我们既不要轻信，但也不能全盘否定一切，别钻进牛角尖里去</p><p>学习也要注意阴阳平衡，不要一直学一直学</p><p>看小说进入了修仙群，各种买买买，又是丹药，又是修炼手册，又是筑基，又是法力被废的，最后因为没羊毛了被踢出组织了</p><p>不能写出来太可惜了</p><p>修自己的正心念就好，不要追求那些太玄乎的</p><h3 id="s-662" tabindex="-1">篇外：邪教的温暖 <a class="header-anchor" href="#s-662" aria-label="Permalink to &quot;篇外：邪教的温暖 {#s-662}&quot;">​</a></h3><p>我们首先要培养爱自己的习惯</p><p>心念正，自己就可以给自己足够的爱</p><p>先爱自己，保护好自己，然后才能去爱别人</p><p>修好自己，再把爱给到父母、爱人和孩子，让他们不会因为缺爱而误入歧途</p><p>所有的修行，如果你发现需要依赖外在的形式，都是邪道</p><p>包括但不限于让你啥也不干，天天除了修就是修</p><p>人得先活着，才谈得上修行</p><p>（这跟化缘还不一样，正途的化缘化的是贪心</p><p>觉不觉醒也就是个名字</p><p>不要打着为孩子好的旗号</p><p>如果你的父母天天念叨你，赚钱赚钱赚钱，赚钱赚钱赚钱</p><p>你会从这些念叨里，感受到父母的爱吗</p><p>父母每天口口声声就知道让你赚钱赚钱赚钱，你能感受到这是为你好吗</p><p>就像快乐的修行，神通是一个自然而然的结果一样</p><p>不要逼得孩子（或爱人、或父母）要到里面去找、找</p><p>唯一能做的，就是修心</p><h3 id="s-663" tabindex="-1">故宫 <a class="header-anchor" href="#s-663" aria-label="Permalink to &quot;故宫 {#s-663}&quot;">​</a></h3><p>他被双方的家庭绑架着，我也帮不上什么忙，只能默默地听着他的牢骚，给他一个情绪的出口</p><p>t湾在我的认知里，那是属于地理书上的地方，我竟然也能去</p><p>对于丘书妍的这个提议，我自然是同意的不能再同意了</p><p>台湾是信仰非常繁荣的地方，你们要不要去各种道观、寺庙看一下呀</p><p>豪德被我一句话搞毛了：这说的是什么话</p><p>我们才更能代表传承</p><p>凭什么被消灭的还能代表正统呢</p><p>丘书妍轻轻的拍了我一下，嗔道：说什么灭不灭的你</p><p>估计不是什么好话儿</p><p>人家热情的招待我们，我还跟人争辩算怎么回事儿</p><p>咱们先去摘草莓，然后再带你们尝尝地道的台湾菜</p><p>再去一些比较着名的宫观、庙宇去看看</p><h3 id="s-664" tabindex="-1">什么是正念 <a class="header-anchor" href="#s-664" aria-label="Permalink to &quot;什么是正念 {#s-664}&quot;">​</a></h3><p>我又照着他的胳膊来了一巴掌：就是因为人家啥也不缺，不必考虑经济利益，才有可能会单纯的看上你有文化，脾气好</p><p>人家就想找个脾气好的老公，难道不可以吗</p><p>再说了，你长的又白又高，人家的眼光也是很正常的好吗</p><p>就算她们本人同意，她们家里人也不会同意的</p><p>而是换了一个方向，跟他聊起了修行</p><p>那么，你是正心正念的人吗</p><p>不论是工作上还是生活上，我也没干啥坏事儿，怎么就不正心正念了</p><p>我向上直直的竖起了食指，比划道：什么算正念</p><p>如果你的念头一会儿东，一会儿西，摇摆不定，这样算正念吗</p><p>正念的反面，不只是邪念</p><p>并不是说，只要不做伤天害理的事情，你就算是保持正念人</p><p>一会儿左、一会儿右的念头，在正位吗</p><p>左右摇摆的念头，不是在偏左就是偏右，反正就是不在正位</p><p>所以说，怀疑或纠结，最耗费正能量</p><p>所以说，要么我坚决的相信命运，相信我自己命不好，我配不上那么好的人，直接跟那几个女孩儿都断了</p><p>呼，可算是掰过来了</p><p>对的，这才是正念</p><p>正念是笃定的，不会摇摆：自己心里会很清楚的知道应该怎么做</p><p>地上一条水沟，我就是知道我能跳过去，这叫笃定</p><p>如果自己去做一件事情，还需要寻求别人的肯定，这代表着自己的念还不够正</p><p>白志高敬佩的竖起了大拇指，揶揄道</p><p>白志高本来是打算直接走过去的，不过我看老爷爷一个人默默的蹲在那里怪可怜的，就想着能不能帮帮他</p><p>我用疑问的目光看向白志高</p><h3 id="s-665" tabindex="-1">心理阴影 <a class="header-anchor" href="#s-665" aria-label="Permalink to &quot;心理阴影 {#s-665}&quot;">​</a></h3><p>我看老爷爷就是蹲在墙角边，也没有摆画架什么的，便问道</p><p>避免直接看着老爷爷，他会紧张，我看向了白志高的方向</p><p>白志高还沉浸在之前的聊天内容里，他感慨道：我从来没想过，正念还可以这么理解</p><p>我一直以为，不伤害别人就算是正心正念了呢</p><p>我们自己也是众生的一员啊，内耗自己，难道就不是伤害众生吗</p><p>大部分的人，是在用纷乱的心念或者语言，在伤害自己、伤害别人</p><p>我们只要用脑算计，就容易思绪飞扬、胡思乱想</p><p>修心是一辈子的事情</p><p>怕就怕，很多人明明在伤害众生还不自知，还以为自己只要不骂脏话就算修行了</p><p>能看到自己的问题还好，我们可以慢慢修</p><p>你的面相变得更有福气了，运势也确实是变好了，这就是结果啊</p><p>灾难来临，不可消沉，要高兴才对</p><p>灾难能把长期以来依附在灵魂上的业障消除</p><p>这种程度的灾难就能消除业障，越是面对灾难，越要庆贺才对</p><p>修行的人，不怕生活越修越差，那是消业</p><p>老爷爷刚刚就是从英语本子上，撕下来了他的画作</p><h3 id="s-666" tabindex="-1">百折不挠的贱人 <a class="header-anchor" href="#s-666" aria-label="Permalink to &quot;百折不挠的贱人 {#s-666}&quot;">​</a></h3><p>我们修行修的就是一颗平和喜悦的心</p><p>如果我们看外在不满意，是不是确实是我们自己的修行不到位</p><p>白志高这一提，我才想起来，这是很多修行人的误区</p><p>我们今生所经历的坎坷，很多都是业力所致</p><p>往世的业力，可以看作是欠债</p><p>经历过了，业力消了，等同于把债还了</p><p>那只能有一个原因，就是修错了</p><p>白志高又把稻盛和夫的话背了一遍：灾难来临，不可消沉，要高兴才对</p><p>灾难能把长期以来依附在灵魂上的业障消除</p><p>这种程度的灾难就能消除业障，越是面对灾难，越要庆贺才对</p><p>灾难来临，不可消沉，要高兴才对</p><p>这句话重在表达：有机会能清除因果业力，这是好事儿，不然业力会累生累世跟着我们</p><p>而不是修行人，把日子过得越来越苦，不以为耻反以为荣了</p><p>苦难是业力，是欠债</p><p>也就是说，苦难来了，我们高兴</p><p>就是常说的那句话：我们不主动惹事儿，但是也绝不怕事儿</p><p>明白了，不能因为我们不怕事儿，就主动去惹事儿</p><p>所幸他并不傲慢，说的基本都能听进去</p><p>他认可了我说的正念，从宿命论的坑里爬了出来，也算是有收获</p><p>我也收到了一张能拨动我情绪的画作，也是收获</p><p>第二天一大早，我要打车去泾川</p><p>就是在正殿添功德的时候，我被特别优待了一下</p><p>进到大殿里面，我再次认真的叩拜了一番</p><p>所以我拜的时候，只是表达一份敬意，并没有其他的想法</p><p>看你有诚心，跟你结缘两本书吧，也算是缘分</p><p>我恭敬的双手接过，再次跟师父鞠躬致谢</p><p>同样是天然水晶，通透度越高的，功效最好</p><h3 id="s-667" tabindex="-1">神仙的能力也有限 <a class="header-anchor" href="#s-667" aria-label="Permalink to &quot;神仙的能力也有限 {#s-667}&quot;">​</a></h3><p>吉月姐姐迟疑道：呃……他们俩不是一件事儿</p><p>魔既然不是鬼，那魔究竟是什么呢</p><p>贪念和嗔恨，会召唤魔的到来</p><p>恶念一起，人就会被魔入心，做出不可控制的事情</p><p>遇到极端情况，一个人就可能杀掉一片未来佛，也包括他自己</p><p>世界上人那么多，大家呼呼的起贪念，呼呼的升起嗔恨心，呼呼的召唤魔，我能管的过来吗</p><p>吉月姐姐强调道，既关注自己的情绪，不要起贪念，不要生恨</p><p>又要注意自己的言行，不要惹其他人生恨</p><p>任何人的嗔恨心，都能招魔</p><p>既要保证自己心念正，又要尽可能的帮助家人、甚至陌生人正心正念</p><p>而是靠的每一个人，不生恨，不招魔</p><p>我们都不生恨的时候，魔就没有力量</p><p>修自己：让自己保持正念</p><p>修家庭：让家人保持正念</p><p>修乡村：让家乡的人保持正念</p><p>修国家：让全国人民保持正念</p><p>修天下：让天下人全部正心正念</p><p>神仙的能力也有限，也不能无限的对抗人们的贪念诱发来的无限的魔</p><p>唯一能依靠的，就是自己</p><p>做好自己，并尽可能的引导更多的人去除贪念，去除嗔恨心</p><p>跟吉月姐姐聊了一会儿电话，既然她有事儿要忙，那就只能以后有机会再约了</p><p>我们唯一能做的，就是修好自己</p><p>不要天天想着神神鬼鬼的事情，好好把注意力放在自己身上就好</p><p>外力借助归借助，但不能把自己丢了</p><h3 id="s-668" tabindex="-1">最泼皮的无赖 <a class="header-anchor" href="#s-668" aria-label="Permalink to &quot;最泼皮的无赖 {#s-668}&quot;">​</a></h3><p>他们打开了八字排盘软件，找到了各自的日干，互相的验证</p><p>都想知道我属于哪种五行</p><p>他们对照着曲总列出来的性格，念道：向外发散，太阳，谦让，热情，慷慨，开朗乐观，性子急，脾气暴躁，没心机，善变，缺乏耐心和毅力……</p><p>想过的话，从房后绕过去，反正是不能从我眼前儿走过去</p><p>曲总道：所以说，修行人的八字是看不准的</p><p>但注重修行的人，在慢慢的修正自己的业力和习性，他们不会按照原来的剧本走的</p><p>修行有关系，我们的心在变，认知在变，我们的情绪和行为也会改变</p><p>修行是一辈子的事情，极少有人会完全的脱离</p><p>做中介，已经算是我坚持最长时间的工作了</p><h3 id="s-669" tabindex="-1">注意力就是生命力 <a class="header-anchor" href="#s-669" aria-label="Permalink to &quot;注意力就是生命力 {#s-669}&quot;">​</a></h3><p>注意力就是生命力</p><p>你的注意力在哪里，你的生命力就在哪里</p><p>你的注意力在哪里呢</p><p>你的注意力都去挑别人的毛病去了，那还用什么去成就自己的人生</p><p>她幡然醒悟之后，第一时间跟我道歉：对不起对不起，我刚刚不应该带着情绪攻击你的懒惰</p><p>我算是看出来了，这大姐比我还不会说话</p><p>曲总主动接口化解尴尬道：心无旁骛、全力以赴的去做一件事，这就是愿力</p><p>我也是实打实的付出了努力，起早贪黑的干</p><p>我还需要怎么做，能再加大一些愿力</p><p>着急对应着上火，火克金，伤财</p><p>但那人已经急的有点儿心乱了，他抓狂道：但我就是急需要钱呀，根本就静不下来</p><p>我还可以再加大愿力吗</p><p>只有魔才会用无限满足贪念的噱头，拉人下水</p><p>我努力的付出，钱就应该会进来，这不正是阴阳吗</p><p>这个阴阳，是哪里出了问题</p><p>也有人跟着他的思路一起迷糊了，皱着眉琢磨阴阳怎么不平衡了</p><p>但你不愿意静下来，修心动脑</p><p>阴阳一直都是平衡的</p><h3 id="s-670" tabindex="-1">刚洒下种子就想收获是贪念 <a class="header-anchor" href="#s-670" aria-label="Permalink to &quot;刚洒下种子就想收获是贪念 {#s-670}&quot;">​</a></h3><p>我又换了个角度，给他解释了一下阴阳：你努力付出，是向外</p><p>让钱自然的回流，阴阳自动平衡，心才不会累</p><p>有时候，人卡在某种思维里，不太容易能转过弯儿来</p><p>不如先把自己的爱送出去，然后等对方的爱自然的回流</p><p>那人表述道，我把关注点放在做事儿上，帮助他人，就是把爱送出去的过程</p><p>家家有本难念的经</p><p>刚洒下种子，就想要收获，这是一种贪念</p><p>我确实是需要先静静心</p><p>这些道理本来都懂，但一着急，就都给忘记了</p><p>岂能事事尽如人意，戒贪是修行的第一步</p><p>着急上火，是火克金</p><p>气氛慢慢又热络起来了</p><p>首先，你要向外克</p><p>比如你要去完成一个任务，你能克制的住这个任务，就代表你能拿下它完成它，这叫克者为财</p><p>如果你接了一个任务，你没能胜任，就是没克制住</p><p>如果自身不够硬，一斧头下去给自己砍卷刃儿了，那就是没克制住反被伤了</p><p>前面说的着急上火的那个火克金，克的是自己，是向内克</p><p>就好比，一个任务在你面前，你还没干呢，就开始胡思乱想的内耗自己，这种克自己，是不能克来财的</p><p>那人弱弱的嘀咕道：哦，要看能不能克制的住哈</p><p>难怪身处高位的人脾气都很大，这就是他们能克制住别人，是吧</p><h3 id="s-671" tabindex="-1">股票大神 <a class="header-anchor" href="#s-671" aria-label="Permalink to &quot;股票大神 {#s-671}&quot;">​</a></h3><p>当时我一直是看股评专家们推荐的股票，再看看老板的面相</p><p>一般专家推荐，也就是说哪只股票好</p><p>但在那一年，我遇到了一位大神斩钉截铁的发誓，如果他推荐的那只股票不能翻两三倍以上，他就退出股评界</p><p>我那是第一次见到那么笃定的推荐，我还是按照往常的惯例，去看了看老板的面相</p><p>我只能猜测，这位是不是有什么内幕消息</p><p>当贪念一起，大脑开始参与决策的时候，心就藏起来了</p><p>这个时候就无所谓随心而走了，只剩下满脑门子的分析和算计</p><p>在我的认知里面，就没其他的可能性</p><p>腰斩之后，我就开始怀疑这个决定是不是正确了</p><p>不论翻几倍是真是假，我都不想再继续了</p><p>然后，完美的割在了地板上，错过了随后反弹的那一波儿</p><p>删了之前的帖子，又发了个新的帖子说，不好意思看走眼了，然后继续他</p><p>删了之前的帖子，又发了个新的帖子说，不好意思看走眼了，然后继续他的人设</p><p>真正的愤怒过，我才深刻的体会到：所有能让我们不能忍受的人或事儿，都是为了来成长我们的</p><p>虽然这次入坑，亏了70%，但股票里的钱，本来就是闲在里面的，它亏不亏对我的生活并没有什么影响</p><p>丘书妍又摆出了她的杀手锏，她眨巴着无辜的眼睛掐着腰，装成卡通人物的模样，搞笑道：你不要撒撒的哦</p><p>改变能改变的，接受不能改变的</p><p>友友反馈：我家里这也不能动，那也不能改</p><p>不是能不能改的问题，而是愿不愿意改的问题</p><h3 id="s-672" tabindex="-1">可能会瘫痪 <a class="header-anchor" href="#s-672" aria-label="Permalink to &quot;可能会瘫痪 {#s-672}&quot;">​</a></h3><p>运势低落的时候，不适合做重大决策</p><p>这就是天命不可违吗</p><p>个人有个人的因果吧</p><p>八运是土运，九运是火运</p><p>所以九运重技术，轻资产</p><p>（技术，既包括高科技，也包含让人快乐的能力，比如搞笑文化、心理疗愈、气功等等</p><p>所有跟有形相对的，摸不着的都算无形</p><p>） 虽然从后天运来说，是从2024年开始进入九运，但从先天运来说，2017年就已经开始进入了</p><p>（等后面再找机会一起写一下其他的地产商</p><p>就算钱够了，万一手术后真的瘫痪了，小男孩儿才19岁，后半生怎么办</p><p>我跟丘书妍快速地商量了一下，先救人，我们俩就做好破产的准备吧</p><p>他说虽然工人还没有上班，但是既然申请到他的公司了，那就是他的缘分</p><p>他先垫付了医院的钱，救人第一，其他的让我们等以后再说</p><p>我们也在第一时间通知了Z国中介，通知了孩子的父母</p><p>还没开始做手术，也有护士在，我们就是帮他跑跑手续，带他做各种检查</p><p>术后万一瘫痪，孩子本人以及他的父母能不能接受</p><p>住院的第一天，做完了检查，拿到了医院的报告，我们及时的传回了Z国，等待国内的回复</p><p>父母不签字，我们不能做主这么大的事情</p><h3 id="s-673" tabindex="-1">魔咒又捡回来了 <a class="header-anchor" href="#s-673" aria-label="Permalink to &quot;魔咒又捡回来了 {#s-673}&quot;">​</a></h3><p>我本来以为，妍爸过了64岁的坎儿，这一关就算过去了</p><p>但没想到，过完年之后，妍爸又会想起来就念叨念叨一遍</p><p>既然咱已经活着走过了64岁，那就说明大师算的不准啊</p><p>64岁，就是我的寿命啊</p><p>事实明明就是人还活着呢，凭什么是个死人</p><p>我非常不能理解这种耍流氓的说法</p><p>事实都已经证明那位算的不准了，妍爸为什么非要坚定不移的相信自己应该在64岁寿终呢</p><p>人的信念是很重要的</p><p>妍爸看着丘书妍可爱的样子，也确实会被逗笑，但他依旧固执的相信大师所言：自己就是应该在64岁寿终</p><p>对于这种不讲道理的执念，我也没有什么办法</p><p>丘书妍发现她改变不了她爸的观念，便想着要不通过外力做些事情</p><p>没有种子，哪怕土壤再肥沃、阳光再充足，那也是发不出芽来的</p><p>话都说到这儿了，我也不好再说什么</p><p>剩下的就是看看请哪位师父帮忙做的问题了</p><p>再后来，他戒酒了，又精神抖擞了</p><p>再后来，他觉得自己已经康复了，又开始酗酒，人突然就……</p><p>要不，先问问秉烛师父吧</p><p>丘书妍问秉烛师父能不能帮忙做一下法事</p><p>不论是风水还是法事，说的都是因果</p><p>先要自己持正念，再说借外力</p><h3 id="s-674" tabindex="-1">魔咒 <a class="header-anchor" href="#s-674" aria-label="Permalink to &quot;魔咒 {#s-674}&quot;">​</a></h3><p>我们想象一下，为什么有人痴迷于玩游戏</p><p>玩游戏的最终结果是什么</p><p>宇宙的真相就是，从无中来，到无中去</p><p>但用游戏的眼光来看，是一样的，那就是：终有一死</p><p>我们能尽情的享受走向死亡的过程，就是幸福</p><p>如果每次打游戏，一死就气的要命，那这种人不适合玩游戏</p><p>跟必然的事情生气，那不就成了没气儿找气儿生嘛</p><p>如果有人因为太阳东升西落而生气，那他大概率是精神不太好</p><p>但这个道理，很多人都看不透，包括见过世面的人</p><p>妍妈慢慢上了年纪，腿脚没有那么利索了，拎东西就有点费劲</p><p>妍爸想起这件事儿之后，经常挂在嘴边的口头禅就是：我今年是注定要走啦</p><p>如果一个人总是感觉自己要死了要死了，哪怕没病没灾的，也扛不住这么强大的念力</p><p>我们想尽了一切办法，扭转妍爸的观念</p><p>我是一个相信预测，但不相信宿命论的人</p><p>我跟她从结婚开始，就是家里家外都靠我</p><p>有人问智策师父讲手机号，怎么只看倒数第三位和倒数第六位</p><p>而是由于时间关系，只讲了倒数第三位——人和，顺便捎带着说了一下倒数第六位的组合</p><p>互动的时候，有人问到要不要换手机号的事情，智策师父没有正面的回复</p><p>如果是趁热打铁的促单，让大家在不理智的情况下做决定，心不静，东一头西一头的对修行不利</p><p>我们先把心稳下来，有了完整的认知之后，反复斟酌，再决定自己的选择</p><p>奇门遁甲是一个体系，是一种思维模式</p><h3 id="s-675" tabindex="-1">精神分裂症 <a class="header-anchor" href="#s-675" aria-label="Permalink to &quot;精神分裂症 {#s-675}&quot;">​</a></h3><p>韬韬适不适合结婚，我不太清楚</p><p>人有时候就是很矛盾</p><p>一边认为他不适合结婚，一边又喜欢他的朝气和热情</p><p>咱俩分开，你也瘦了，我也瘦了，我们再次变成了更好的自己</p><p>这是不是就是最美好的结局</p><p>你都多大人了，还需要别人哄你</p><p>自己的情绪，自己消化</p><p>再聊，又要暧昧回去了</p><p>我是个很理智的人，做事情之前想清楚，自己要什么，不要什么</p><p>欲擒故纵的手段，不适合用来考验爱情</p><p>闭关班还剩最后一天，要早起</p><p>但那天早晨一起床，我虽然第一反应是要去闭关，但走到了公交车站点时，我又迷糊了</p><p>地铁只要找对方向，就不会上错车</p><h3 id="s-676" tabindex="-1">他们的老婆也都出轨了吗 <a class="header-anchor" href="#s-676" aria-label="Permalink to &quot;他们的老婆也都出轨了吗 {#s-676}&quot;">​</a></h3><p>过去的事情，就不要再追究了吧</p><p>死者为大，都到这时候了，我肯定不能追究什么</p><p>我缓了口气儿，解释道：我只是不明白，他为什么最后要来找我</p><p>葬礼怎么安排，我能去送他最后一程吗</p><p>我们的葬礼流程是，把遗体接回来，在楼下先摆七天的流水席，然后才火化</p><p>那我也等晚上再过去吧，跟你一起为他守夜</p><p>接下来连着七天，我每天晚上都会去给妍爸诵经祈福</p><p>妍妈见了我也很和气，没有再说什么奇怪的话</p><p>我们每个人接下来都有不同的人生轨迹，人生总不能走回头路</p><p>当一段感情走到最后，为了利益竟然会去背刺对方的时候，大概就是最悲惨的结局了吧</p><p>然后，没事儿找事儿的我也被愤怒的情绪给波及到了</p><p>他们疯狂的辱骂背后，情绪的动力出自哪里呢</p><p>我这都还没共情呢，他们倒是先激动上了</p><p>如果一件事情坚决的否定阴的一面，只强调阳的一面，是违背阴阳之道的</p><h3 id="s-677" tabindex="-1">篇外：篆书的灵力加持 <a class="header-anchor" href="#s-677" aria-label="Permalink to &quot;篇外：篆书的灵力加持 {#s-677}&quot;">​</a></h3><p>古萨满师父（也就是吉月姐姐的师父），一个多月前就让我们开始写了</p><p>之所以没有第一时间推荐给大家，是我自己先描了一卷试试</p><p>我先描的是篆书2500字，现在在写《道德经》</p><p>算是最早的成熟文字，在隶书、楷书、行书、草书之前</p><p>之前没太注意，这次写的时候才发现，篆书没有顿笔，没有花里胡哨的形式，非常纯朴，很像画符儿</p><p>大概画符就是从篆书演变而来的</p><p>再比如那个，好像就是画了一个开心的小孩儿，写的时候就会心生喜悦</p><p>经济上不宽裕，或者没有时间写的话，先不要拍，这不是个摆件</p><p>除了篆书这种文字本身的能量之外，描红这类的简单不用动脑的事情，本身就有解压的功效</p><p>类似的动作还有撕纸，或者用小抹布擦地板、用手搓洗衣服等等</p><p>如果在做的过程中，能把注意力放在手上，去感知毛笔的柔软，地板的平滑，水流过手指的感觉等等，更有助于把脑子放下，把心释放出来</p><p>很多病，都是情绪引起的气血上的淤堵导致的</p><p>免费看半个小时，就能吊打95%的风水师，这多划算</p><p>理由是，罗盘指的是磁极，而磁极是变化的</p><p>然后用了四五分钟的时间，证明罗盘有问题</p><p>95%的风水师，他们连方向都测不准</p><p>因为方向都找不准</p><p>然后用自己住过的房子举例子</p><p>核心内容是：单元门的朝向很重要</p><p>要用卫星地图，才能更准确的找到方向</p><p>理论是，24山不能直接用</p><p>也就是说，同一个单元，单元门方向一致，如果入户门是相对的，那么24山在这两家就是截然相反的摆放方式</p><p>因此证明，理论确实准确，测出来的好，就真的非常好</p><p>我的疑问是，就凭一个24山，再怎么转，也做不到无一不准确吧</p><p>不要听别人说了什么就全盘接受，每个人要设置一个属于自己的信息过滤门槛</p><p>自己亲自验证过的，才算数</p><p>只要原理弄懂了，剩下的就是实践了</p><p>我之前试过一次，预测的结果与我分析的不一致</p><p>我还是不甘心，过了一段时间，又测</p><p>现在看，预测的是准确的</p><p>这种变化，不是我们在当时的认知下，用理智可以推理出来的</p><p>（当时是在2016年下半年测的</p><p>上面的《看完本视频，零基础的小白，可以吊打95%的风水师》的案例，聊天记录的最后，那位友友还是有疑惑</p><p>她疑惑的点是，人家的分享也是免费的，也没骗我们钱，不至于故意分享个错的吧</p><p>至于对方的动机是什么，我们不必去纠结，因为跟我们无关</p><p>比如，有可能是他本身的认知问题，他验证了三个人，全准了，他就认为这套理论是对的</p><p>把自己包装成天下无敌，95%的风水师连方向都找不对，那以后风水问题，是不是就只能咨询他了</p><p>还有可能单纯就是为了赚流量的钱</p><p>我爸曾经刷到一个视频，题目是：《吃饺子千万不能蘸醋</p><p>我爸吃饺子就喜欢配醋，一看这标题，那必须得看呀</p><p>先是戳痛点，举例子：哪个老头不听话，吃饺子蘸醋了，最后上医院了</p><p>为什么千万不能蘸醋</p><p>看到最后，说醋酸是酸性的，能刺激胃</p><p>另外，说醋酸能溶解钙，吃醋能骨质疏松</p><p>因为小孩儿是纯阳之体，阴阳和合刚刚好</p><p>在这个末法时代，大家更不要轻易相信任何人</p><p>《吃饺子千万不能蘸醋》这个事儿，大家看到最后，发现没有说出个为什么，评论区一片骂声，说她危言耸听，脱裤子放屁等等</p><p>一个是完播率，就是能看到最后的有多少人</p><p>分享三个点，尤其是最后一个，最重要</p><p>如果真的是最重要的，分享就是为了利他，为什么不拿到前面说</p><p>如果前后是有一个逻辑关系，必须要放后面说的话，那正常人也会丝丝入扣的往后听完的</p><p>她特意点出来最重要的放最后，那就说明三个点是独立的</p><p>跟一样，就想知道的原因是什么，何况还有，一般人都会坚持要看完</p><p>开头儿往天上夸，说的使劲儿大一点，至于后面能不能圆上去不是很重要</p><p>因为视频考核的第二个点是互动率</p><p>不论大家是夸你的，骂你的，只要有人回复就算完成考核</p><p>我爸看完那个《吃饺子千万不能蘸醋》的视频之后，虽然不屑一顾，但总归是觉得醋还是有点儿问题的，不然人家也不能那么说</p><p>所以多少还是会注意一点儿</p><p>结果没几天，又有一则视频说《吃饺子不蘸醋的，都是汉奸</p><p>理由是，醋对人体那么好，还不多用点儿，会导致生产醋的厂家倒闭的</p><p>醋，那是老祖宗留给我们的养生智慧，谁吃饺子不蘸醋，谁卖国</p><p>保持独立的思考能力，才能心正，这也是修心的一部分</p><p>那这个心，就是摇摆的</p><p>摇摆的，就是不正的</p><h3 id="s-678" tabindex="-1">腰痛 <a class="header-anchor" href="#s-678" aria-label="Permalink to &quot;腰痛 {#s-678}&quot;">​</a></h3><p>但七哥得开车回家，不能走北线</p><p>在火车上，遇到了一个到西藏修行回去的师姐</p><p>本来遇到喜欢修行的人，是一件很开心的事情，大家有共同语言</p><p>而且上的还都是修行的课</p><p>修行，得自己切实的行出来啊</p><p>灵魂的觉醒，不可能靠着上课获得</p><p>姐姐很坚决的否认道：你不能理解我在上灵修的课程时，有多快乐</p><p>我也不能说那种快乐不真实，只是……反正那不是修行</p><p>师父领进门，修行在个人啊</p><p>总不能让师父一直领着，那怎么能成长呢</p><p>姐姐愣了愣，没有再狡辩</p><p>你这样常年修行，家里人同意吗</p><p>他们又不修行，愚钝的人，不需要经过他们同意</p><p>她的思路，在修行和世俗的观念之间，自由的切换，弄得我倒不知道该说什么好了</p><p>修行，修理的是每个人身上的各种不服</p><p>不一定是表面上的硬，而是指的心里不服气</p><p>修行修的是自己，所以对应的身体症状也是自己的</p><h3 id="s-679" tabindex="-1">等我学好了再去渡人 <a class="header-anchor" href="#s-679" aria-label="Permalink to &quot;等我学好了再去渡人 {#s-679}&quot;">​</a></h3><p>要不怎么说，修行是一辈子的功课呢</p><p>姐姐条件反射般的就想反驳，我紧接着又加了一句</p><p>好多人修行，把自己修成了一个事不关己高高挂起的人</p><p>谁也看不上，都是朽木不可雕</p><p>姐姐虽然熄火了，但还是转不过弯儿来，她反问道：跟世俗又爱占便宜的人在一起，怎么修慈悲</p><p>也不能修的是非不分了吧</p><p>不起情绪是修的自己</p><p>修，本身就是要做事情</p><p>姐姐又找了一个理由：那等我学好了，再去渡人吧</p><p>已经上了十几年的课了，还要等学好再说</p><p>这个世界，本来就是有很多未知的事情</p><p>不可能靠着学习把什么都学会的</p><p>不会的，在实践中再慢慢琢磨呗</p><p>等学好了再去渡人，那就永远都不会有开始的那一天的</p><p>第一，今天跟吉月姐姐确认了一下，小摆件儿这个月底确定来不及</p><p>第二，想预约火阿姨的人也不少</p><p>最近大家先静静心，把心稳下来，修自己</p><p>等春节之前两三天，再给大家预约一次</p><p>第三件事情，辟谷</p><p>辟谷，不只是不吃主食的意思</p><p>还有一个更重要的是，辟谷期间不要生气</p><p>一生气，气机就乱了</p><p>辟谷不是简单的不吃饭，更是一种的修行</p><h3 id="s-680" tabindex="-1">颈椎问题 <a class="header-anchor" href="#s-680" aria-label="Permalink to &quot;颈椎问题 {#s-680}&quot;">​</a></h3><p>但情绪上的伤害，会带着气淤堵在那个部位</p><p>找到生气的原因，解开那个心结，就好了</p><p>我四处上课，就是为了要寻找一个解脱的答案</p><p>在每一次起情绪的时候修</p><p>我们在成长的路上，也不能全靠自己悟，那样会很慢</p><p>但不能一直依赖于老师</p><p>自己有了积累之后，可以再考虑请老师提点一下，跨上下一个台阶，这样才是一步一个脚印的向前</p><p>包括有些学生也是</p><p>大学毕业不想工作，就继续往上读研究生、博士生，一直念到三十多岁</p><p>明明自己的专业不适合再往上了，但为了逃避现实，硬是在象牙塔里躲着不出来</p><p>等到实在没得念了，毕业之后一般的工作不想做，高端的又胜任不了，最终选择躲回家里啃老去了</p><p>能做什么做什么，赚不赚钱的先放后面，向外付出体力劳动，跟单纯的体育运动相比，升阳效果是有区别的</p><p>做实事儿，把注意力放在外面的事情上，阳升起来了，很多事儿就不是事儿了</p><p>困得都一直点头，还是硬扛着就是不睡</p><p>如果孩子睡在五鬼位，容易有这种情况</p><p>我把五鬼的气场组合写在了一张小纸上</p><p>又画了一张九宫格，让她找一下孩子睡觉的房间，门和床是否构成五鬼气场</p><p>这本书，看到大家问的多的问题，我就先写，所以很多事情跟实际发生的时间是不符的</p><p>下一本书，前期简单写一下小时候的事情，中间顺带提一些这本书没有提到过的事情，重点从2016年开始接着往后写</p><h3 id="s-681" tabindex="-1">篇外：自由的心 <a class="header-anchor" href="#s-681" aria-label="Permalink to &quot;篇外：自由的心 {#s-681}&quot;">​</a></h3><p>皈依，意味着你要赞同这个宗教的一切教义</p><p>人在局外，选择性的大小，代表着自由度</p><p>（这个等写到2019年的邮票之争再详细说局外的事情</p><p>也不是说一定不能皈依</p><p>佛法，就是小船，给人传播道理</p><p>不能过完河还背着船，不然怎么解脱</p><p>丹霞烧佛，就是打破这个枷锁</p><p>丹霞禅师道：既然是木头做的，又没有舍利，那就再拿两尊来烧一烧吧</p><p>人能起情绪，也是一种禁锢</p><p>当心里有一个的框框时，就是被那种理念禁锢住了</p><p>家里就应该打扫的干干净净的，不然就生气</p><p>老公就应该多赚钱，不然就生气</p><p>孩子就应该乖乖的，不然就生气</p><p>同事就应该是有礼貌的，不然就生气</p><p>有多少应该，就有多少生气</p><p>不如说是我们的执念，把自己捆住了</p><h3 id="s-682" tabindex="-1">【篇外：】修心：正心正念 <a class="header-anchor" href="#s-682" aria-label="Permalink to &quot;【篇外：】修心：正心正念 {#s-682}&quot;">​</a></h3><p>先给大家做个提醒吧</p><p>接下来一年多时间，尽量不要去险峻的地方旅游</p><p>再过十年二十年会怎样</p><p>再次提醒大家，不要去人挤人的地方，要考虑建筑物的承受能力</p><p>不但是室内，也包括室外景点，假山、大桥等等</p><p>善于推理的友友应该可以自行推理出来了</p><p>如果物业和维修人员都是正心正念的还好，万一有人起了贪念，想省钱或者省事儿呢</p><p>贪念一起，就容易招引负面的能量</p><p>这两天反馈到我这边的一直想外求的友友特别多，还是有很多人分不清什么叫正心正念</p><p>还是有人觉得，只要自己不害人，就是正心，那离正心还差的远呐</p><p>有人总怀疑别人要害自己，但既没有证据，又没有具体的对象，就是疑神疑鬼</p><p>一会儿怀疑是不是同事，一会儿怀疑是不是虚的方面</p><p>这种心，随着怀疑四处飘荡，哪里谈的上正</p><p>遇到问题，先看自己哪里做的不好</p><p>自己没做好，不要去外求</p><p>吉月姐姐也反馈，处理好了，有人心念不正又招来新的魔了</p><p>（这里只是说的心不正的人，有些人是业力和缘分导致的不在此列</p><p>如果你就想躺着等别人拽你，拉一把，一松手你又躺下了，再拉一把，一松手你又躺下了，那我们耗时耗力的这个拉的动作就毫无意义</p><p>值得我们去帮的正心正念的人那么多，为什么要浪费时间在一个扶不起来的人身上呢</p><p>大家如果已经加过吉月姐姐的，在找她之前，请先确定两个点</p><p>第一，我的心是否是笃定的正直的</p><p>摇摇摆摆，疑神疑鬼的，不要问</p><p>自己所面临的困局，能不能找到自己的问题在哪里</p><p>能不能解决先放一边，毕竟习性不是一个两次就能轻易的解决干净的</p><p>如果没有这个意识，也不要向外求</p><p>外求遇到正心正念的人还好，万一对方把你护法神给扣了呢</p><p>心不定的时候，不要四处去求，以免作的把自己逼上绝路</p><p>我们可以再自省：我太相信自己的眼睛了，没看透他是伪装的，我以后要注意这个问题</p><h3 id="s-683" tabindex="-1">风水脸 <a class="header-anchor" href="#s-683" aria-label="Permalink to &quot;风水脸 {#s-683}&quot;">​</a></h3><p>她根本都不管自己的话能不能圆上去，就知道扒拉算盘珠子</p><p>反正，师母最终是传出话来儿，说因为大爱的刘老师拯救众生太多，遭同行暗算了</p><p>如果说要有点儿什么不同的话，就是陆续在上新项目</p><p>点痣项目，一颗痣300，哪怕再干净的脸，大大小小的再加上脖子、后背，找个十几个二十几个痣点点很容易</p><p>最后，连医美项目都上来了</p><p>不做不买，那就是不尊师</p><p>但我之前在新加坡闭关时，看到那些师兄师姐们靠自己练功练到气色红润，我觉得那才是我追求的方向</p><p>于是他就开始恶语相向了，倒是也不直接点名，只是公开的影射道：有些人啊，给了你们方法，你们又不用</p><p>还天天抱怨布局不好用</p><p>老刘都把话都说到这里了，以后验证的不好用的地方也不能再问老师了，因为顶着一张，不配问</p><p>想要问，先去老师指定的地方，把脸做成符合风水的脸再说（外面做的不地道，不好用很正常，必须去老师指定的机构才算数）</p><p>老刘自封为国学文化的代表，打赢了网红一哥，就是代表着正义的胜利</p><h3 id="s-684" tabindex="-1">免费看八字的套儿 <a class="header-anchor" href="#s-684" aria-label="Permalink to &quot;免费看八字的套儿 {#s-684}&quot;">​</a></h3><p>我以为，老刘不信因果是个例</p><p>我无论如何也想不到，一个学《易经》的人，还是一个经常抄写《地藏经》的人，口口声声的修行人，竟然也不信因果</p><p>以老刘的贪财程度，最终也没看在她的份儿上，多退她钱</p><p>反正，后面还有老刘的后手兜底儿呢：不管卖啥，反正不好使，就是你德行不够</p><p>我没有具体算过，也可能只有1%而已</p><p>我自己十几年前就熟悉自己的八字，所以，我当时是没有麻烦大爱的刘老师的的</p><p>就算有时候，同修们之间在讨论八字的时候，有人提议让我把八字拿出来，他们一起帮我看看，我也会婉拒的</p><p>就像那些学员一样，明明一肚子牢骚，但就是不敢动</p><h3 id="s-685" tabindex="-1">大师的发明创造 <a class="header-anchor" href="#s-685" aria-label="Permalink to &quot;大师的发明创造 {#s-685}&quot;">​</a></h3><p>曾经的信任只代表曾经，一旦她心眼儿坏了，我们也别凄凄惨惨戚戚的念念不忘了</p><p>好人，面对利益尚且可能变坏，那些把当成敛财的戏服，穿着演戏的，我们就更不能当真了</p><p>除了戒贪之外，最简单的辨别方法是：上赶着不是买卖</p><p>反正从根本上，遇到那种让人一看就觉得自己占了大便宜的事儿，多想想阴阳平衡</p><p>正常来说，如果要改成1349开门的卧室，就要把门改在1349宫的位置</p><p>但阴阳是平衡的，付出与收获是成正比的，捷径自然有捷径的弊端</p><p>第一个问题是，大房间里套小房间，不利婚姻</p><p>对于要钱都可以不要脸的人来说，伤点儿感情怎么了</p><p>又不是什么大事儿</p><h3 id="s-686" tabindex="-1">【篇外：】粉丝反馈 <a class="header-anchor" href="#s-686" aria-label="Permalink to &quot;【篇外：】粉丝反馈 {#s-686}&quot;">​</a></h3><p>发现了评论区里有很多高手，跟大家分享一些很有代表性的评论</p><p>不但是剑指功，而是整本书里写的东西（也包括下一本书），大家都是本就会的</p><p>所以，很多功法都叫，回归本元，我们本自具足</p><p>对于剑指能打出气感的人来说，这是个再正常不过的事情</p><p>但对于剑指打不出气感的人来说，这都属于玄到让他怀疑其真实性了</p><p>修行好的，感知力特别的强</p><p>下面就是个坚持向外求的反面案例</p><p>管理员已经提醒过了，，先修自己</p><p>但这位友友听不进去，非得还要再找我确认一遍</p><p>原来的微信号预约不到师父，她就换了一个微信号再预约</p><p>预约完了，不但自己的问题没解决，又找到了师父的问题，抱怨师父不认真</p><p>硬纠正，是用人的思维在纠正天意，这是傲慢</p><p>管理员前面已经反复多次的拒绝过了，再换着不同的微信去预约，这样尊重师父了吗</p><p>希望大家引以为戒，不要硬求</p><p>修行不够，即使再贪心也强求不来的</p><p>关于修行，前面也写了很多，想不起来的倒回去再看看，这里就不赘述了</p><p>鉴于还在摇摇学步的友友太多，跟智策师父商量了一下，感受能量场安排到线下课吧，线上暂时先不安排了，以免适得其反</p><p>修行，是一个阶段一个阶段的</p><p>只需要把不知道飞到哪里去了的注意力集中起来，放在可触摸的真实世界里，就会对我们的心神有一个正向的作用</p><p>不论我们现在处于什么状态，是否蒙尘，但只要我们曾经见过光，我们知道看不见的力量不是虚无缥缈的，我们的努力就有坚定的方向</p><p>不但是控梦，咱们粉丝里面有好多人会一些更玄的事情，不过太玄了，发出来感觉比托儿看起来还假，暂时就先不发了</p><p>我们大家一起向内修，遇到问题，先关注自己的情绪，反省自己的问题</p><p>等更多的友友可以感知到玄妙的力量之后，咱再共享一些更玄的事情</p><p>现在虽然能感知到的人也不少，但是还有很多友友的眼睛仍然在外面到处挑别人的毛病，自修不到位，就容易攻击那些自己不能理解的事情</p><p>我也没有自虐倾向，为了避免被不理解的人攻击，等大部分友友都调整好了，咱再聊更神奇的事情哈</p><h3 id="s-687" tabindex="-1">【篇外：】神话故事 <a class="header-anchor" href="#s-687" aria-label="Permalink to &quot;【篇外：】神话故事 {#s-687}&quot;">​</a></h3><p>那我每天写书，是不是也是奴隶</p><p>前面在第597章讲过认知疗法，即情绪Abc理论</p><p>A是事件，b是解读，c是结果（包括情绪和行为）</p><p>我跟吉月姐姐同样是忙了一天，本来打算中午码字的内容都没来得及弄，同样A是工作，但是b的部分，我们解读为今天忙得十分有意义</p><p>在各种的生活压力下，大家能守住自己的正心，保护好自己的情绪不崩溃，安稳的度过这一年就很难得了</p><p>我们能借助水晶替大家清理磁场，提升正气，辅助大家度过这一年，所以我们对这个工作解读完之后，得到的结果c是充满成就感</p><p>不能创造价值的生命，真的是好的吗</p><p>而蓝色，刚好位于眉心轮</p><p>眉心轮是肉身的最后一个脉轮，也是咱们平时说的（祖窍的位置）</p><p>眉心轮代表着智慧，是从人性走向神性的关键部位</p><p>后期考虑到大家不同的喜好，还会搭配黄水晶、紫水晶、红玛瑙，超七、发晶等材质，设计出不同价位的手链，以及适合普及的小葫芦</p><p>不论是手链，项链，葫芦，主要作用都是净化磁场，提升正气</p><p>只要自己保持正念，也可以提升正气，不一定非要请外力，大家不必执着</p><p>喜欢手机贴的友友，也可以算好自己的命宫留言给吉月姐姐，一起发</p><p>如果不够分的话，我再做一些，大家别着急</p><h3 id="s-688" tabindex="-1">君子有成人之美 <a class="header-anchor" href="#s-688" aria-label="Permalink to &quot;君子有成人之美 {#s-688}&quot;">​</a></h3><p>我慢慢的理解师父的意思，去改</p><p>一旦我们被外界牵动了情绪，心一动，就不正了</p><p>很多人，人云亦云并非出于恶意，他们就是处于灰色的中间地带</p><p>我们认为的对，也只是局限于我们认知范围内的对而已</p><p>我们修行，只需要保持一颗观察的心</p><p>一切都不是凭空发生的，每个人也有每个人的因果</p><p>包括画错的太极八卦也是</p><p>他们可能出于生活的压力，也可能出于无限的贪念，所以不愿意花费大量的时间去认真学习</p><p>如果是压力的原因，要允许别人想要利用捷径先活下去的不得已</p><p>如果是贪念在作祟，那么就要从根源上解决贪的问题</p><p>只有放下向外去追着钱跑的执念，把注意力放在自己身上，做好自己该做的事情，才会有对应的收获</p><p>这也就是《论语》讲的：上天有好生之德，大地有载物之厚，君子有成人之美</p><p>也这就是《论语》所讲的：君子谋道不谋食，君子忧道不忧贫</p><p>他们现在不是，说不准以后就是了呢</p><p>我们以前不也跟大家一样，都是从最初始的开始修行的吗</p><h3 id="s-689" tabindex="-1">篇外：聊聊天 <a class="header-anchor" href="#s-689" aria-label="Permalink to &quot;篇外：聊聊天 {#s-689}&quot;">​</a></h3><p>先回答上章文末的提问吧</p><p>我平时也懒得算，都是他们算好了发给我一份</p><p>等我这几天问问他们有没有勤快人算好了的哈，没有的话，我自己找时间算一遍，完结前安排上</p><p>第二个问题是超度的事情</p><p>如果自己都饿肚子了，建议先照顾好自己</p><p>一直没能画出来符合预期的，等我看看能不能用水晶拍出来合适的哈，如果可以，本书完结前发正文里送给大家</p><p>这个是今天跟吉月姐姐刚做出来的，等后期加持完，再看看能不能拍出可以做头像的效果</p><p>吉月姐姐加持的物件，需要先给佩戴者做一下清理，再佩戴</p><p>这也是为什么前几天我跟大家说，快手没有的话就不要下载了，到处都很乱</p><p>虚其心，实其腹比较好理解，就是虚心，吃饱肚子</p><p>所以《道德经》讲，尽量不要动用意志力，而是去找到自己感兴趣的东西，去做天性就喜欢的事情</p><p>说这些，是想告诉大家，修行，修自己，向内修，自己关注好自己的情绪就好</p><p>只要不贪，物质上的回馈是一个自然而然的结果</p><p>人活着要吃饭，但是人活着，不能只是为了吃饭</p><p>尤其是不要为了灵性，去到处上课</p><p>修行，自己修就好了，不要向外求</p><h3 id="s-690" tabindex="-1">【篇外：】心正不正 <a class="header-anchor" href="#s-690" aria-label="Permalink to &quot;【篇外：】心正不正 {#s-690}&quot;">​</a></h3><p>都是重点要考的内容哈，再给大家重申一遍</p><p>先接着上一章的护法神说吧</p><p>大家首先要相信自己的心</p><p>这件事儿从第一感觉开始，就应该结束了</p><p>但这位友友的关注点一直是，大师说了这个，大师做了那个，自己到底是什么转世，自己是不是有特殊的缘分</p><p>但紧接着又想让人看看自己</p><p>问题是，心明明已经飘忽不定的左摇右晃了，自己还觉察不到</p><p>觉察不到，就没办法修</p><p>坚定的承认在我们认知之外，有很多未知存在，这样的心是正的</p><p>秉持着这个理念，也可以过得积极阳光</p><p>疑神疑鬼，但又不够敬畏</p><p>不论信不信鬼神，都不能丢了自己</p><p>不论信不信鬼神，都要先相信自己</p><p>注意力就是生命力</p><p>把注意力放在自己身上，而不是放在外面</p><p>谁说了什么，谁做了什么，都与我们的修行无关</p><p>为什么佛家、道家、灵修体系都注重打坐观呼吸</p><p>因为要把注意力放在自己身上</p><p>打坐是修行的一种方式，修行不一定非要打坐</p><p>但修行一定要把注意力放在自己身上，不然谈不上修行</p><p>修心，在风水之前</p><h3 id="s-691" tabindex="-1">【篇外：】调整的几个层面 <a class="header-anchor" href="#s-691" aria-label="Permalink to &quot;【篇外：】调整的几个层面 {#s-691}&quot;">​</a></h3><p>这是点个精，让我给画条龙的意思……</p><p>自己不能仔细的去找找问题，把事情都推给其他人，这不就成了外求吗</p><p>外求是贪念，贪念一起，容易招魔</p><p>提醒大家，修行要趁早</p><p>我最多能做的就是，大家看不懂的地方，我给大家做个解答而已</p><p>不能治病，也不能替大家背业力</p><p>我是习惯性先找风水的问题，咱这本书的主题也是风水，建议大家先找风水上的原因</p><p>前面讲过，有人被几个字困住了，以为人应该按照角色住在对应的卦的位置上，这只是兼顾的一个点而已</p><p>所以，家里西北卧室如果住人的话，最好是家里说了算的那个人住在这里</p><p>不是爸爸住在乾位就是好的，大家要根据具体情况酌情考虑</p><p>归根结底还是谁懂都不如自己懂，自己可以根据自己家的实际情况做调整</p><p>本书快完结了，再给大家总结一遍可以调整的几个层面</p><p>天地人，如果从我们看得见的这个维度来说，天是指天时，地是指风水，人就是我们自己</p><p>调整的时候，兼顾天时、地利、人和</p><p>如果跨越维度来说，天地人，天是指天上的，地是指地下的，人是指我们这个三维世界</p><p>调整的时候，兼顾上面的、下面的，中间的</p><p>中间的就是指人能选择的部分，这里面包括了天时地利人和三个层面</p><p>所有问题的调整，无非就是这几个方面，能做到多少做到多少</p><p>有粉丝问，请了手串是不是人生就会一帆风水了，所有的业力都会帮忙挡了</p><p>能问出这个问题的人，说明业力很大，我前面写的是一点儿都没看进去啊</p><p>前面讲过，当业力大的时候，所有对自己有利的内容都会视而不见</p><p>要想改命，必须要有一颗坚定的心，不然我们的眼和心都会被糊住</p><p>再啰嗦一遍：心不正，外力帮不上忙，只修自己就够了</p><p>本书结尾这几天，多跟大家说一下修行</p><p>这位友友的问题，我本来是没打算回的</p><p>第597章讲过，佛祖割肉喂鹰，但我们不能都去割自己的肉，喂那些肉食性动物吧</p><p>理解不了就先放在一边，活在当下，把此时此刻过好</p><p>修行，修正的是我们的行为</p><p>（众生，既包括他人，也包括自己</p><h3 id="s-692" tabindex="-1">【篇外：】扁桃体问题 <a class="header-anchor" href="#s-692" aria-label="Permalink to &quot;【篇外：】扁桃体问题 {#s-692}&quot;">​</a></h3><p>我记得小时候一感冒就会扁桃体发炎</p><p>因为本来就肥大，一发炎肿起来了之后就会呼吸困难，医生多次建议摘除</p><p>父母又考虑到我还太小，免疫力下降了更麻烦，做手术也有风险，想等着我长大一点再说</p><p>再后来，我即使再感冒也不会呼吸困难了</p><p>修行之后我的性格也不那么急了</p><p>修行之后是水偏金，肥嘟嘟的</p><p>既关注好自己的情绪，同时也多关注一下自己的呼吸</p><p>随时感受一下自己的气吸到哪里，有意识的气沉丹田</p><p>红点处加推拉门，化解大门正对厕所的问题，可以吗</p><p>我不想自己修，太麻烦了</p><p>我就是非得要运气变好，怎么办</p><p>修行这个事情吧，就跟考学一样</p><p>我们的人生结果，就是修行的成绩</p><p>自学是根本（自修），请老师教最多算是一个捷径（外力），但根本上还是要自己努力（自修）</p><p>自己不努力（不自修），老师再好也白搭</p><p>上清华能不能用足够的钱去买个名额，我不太清楚</p><p>还有人问我2025年可以适合大干一场吗</p><p>我都觉得我再重复写，都好像在水文字了</p><p>好好修自己，放下贪念，放下贪念，放下贪念</p><p>关于修行，我也是不知道还要不要再啰嗦一遍</p><p>你们要是不嫌啰嗦，那我就再解释一遍</p><p>已经很注意身体了，但为什么还是躲不过去</p><p>注意保养，是躲不开因果的</p><p>注意保养自己的身体，是向内，是私欲</p><p>德行不好，找师父借力都找不到正心正念的师父</p><p>打着大爱的名义，告诉大家这么做就，那么做就，简简单单买个啥就能得偿所愿了，全是不劳而获的诱导，往邪魔的方向带</p><p>大家不要因为名气大就信了，关键只在于他自己是不是正修，他传播的是不是正修的观念</p><p>顺便再澄清一次，德行不是指念经、放生</p><p>念经有助于让我们的心静下来</p><p>而不是念念经，曾经做的恶业就消失了</p><p>不是花钱去多买些小动物放一放，就算是德行了</p><p>大家在工作中正心正念的去做，也算是积攒德行</p><p>只要没有损害众生的利益（众生包括自己），偶尔放松一下不算损福报</p><p>就像前面讲的那种，没有考核门槛只要交钱就行的，都不是什么正经缘分</p><p>主动送上门的，基本都是陷阱，大家注意提升警惕</p><p>再提醒大家一件事</p><p>阻断率并不是100%，不要以为有药了就可以侥幸</p><p>显示用过的人少，可能是因为自己的朋友圈子知道这种药的人少，并不一定代表染病的人少</p><h3 id="s-693" tabindex="-1">唯有套路得人心 <a class="header-anchor" href="#s-693" aria-label="Permalink to &quot;唯有套路得人心 {#s-693}&quot;">​</a></h3><p>我跟老板讲完了原理，老板又叫了个员工体验了一下实际效果之后，还挺满意，问我道</p><p>老板疑惑的问，也就是说，对别人来说不好</p><p>大概她是有慎重的考虑转型的打算，所以问的比较详细</p><p>安时而处顺，哀乐不能入也</p><p>如果把美固化了，不论多大年龄都去追求十八岁的模样，有了执着就必然会起情绪</p><p>修行，修的是脾气</p><p>所有能让我们起情绪的事情，都是人为的执念，没有顺应天道</p><p>大家都认为18岁的美才是美，你开不开美容院，她们都会起情绪</p><p>你帮助她们在不受伤害的前提下能达成所愿，这算是功德啊</p><p>如果在这个过程中，你能劝她们放下对固化美的执着，让众生不为情绪所困，不更是在做好事吗</p><p>别的美容院不断的在贩卖焦虑，你这边不但修身，还修心</p><p>配合修心，你这边修身的效果会更持久</p><p>不能跟客户谈感情</p><p>我相信，她原来秉持的信念肯定是会动摇的</p><p>我也不明白为什么会有这种不符合逻辑的地方</p><p>她们的模式类似传销，一次性买她们9万8的产品，以后再拿产品就是批发价，拉下线也有提成了</p><p>她们的理念是：变美是一辈子的事情</p><p>9万8的产品早晚能吃完，一次性拿了，以后介绍朋友还有收入，这是一个暴富的机会</p><p>那主管看我不参与的暴富事业，都急眼了，口不择言道：八运的房地产运大家都错过了，难道九运你还想错过吗</p><p>我就是想去看看她们是真的赚钱，还是真的穷困</p><p>她跟我讲九运，我是一点儿都不心动</p><p>她看跟我谈暴富我不上头，便又换了个说辞：你看看，时代的大运都已经送到你面前了，你也抓不住，你这脑子反应也太慢了呀</p><p>但你看看你，长这么一身恶心的肥肉，就算你想努力，谁愿意跟恶心的人说话</p><p>当年李雪说我胖的跟猪一样，我一点儿都不生气</p><p>因为跟她那种天才比，说我跟猪一样算是客观描述</p><h3 id="s-694" tabindex="-1">躺平和接纳 <a class="header-anchor" href="#s-694" aria-label="Permalink to &quot;躺平和接纳 {#s-694}&quot;">​</a></h3><p>她强势的抓过我的手，把笔硬塞进了我手里，道：别再犹豫了，赶快在这里签个字，抓紧先定一个单子</p><p>我再次确认，她运势很差</p><p>我把笔轻轻的放在了桌子上，看着她的脸，慢条斯理道：难道你只知道离9运主美丽，却不知道瘦到露骨主贫贱吗</p><p>老话讲：面无三两肉，奸滑多算计</p><p>每人将近10万，这就是几百万，她的提成几十万得有吧</p><p>我疑惑的看着她们</p><p>但当时是她们招商会的收尾阶段，我也不能详细讲，只是给她们举了个例子</p><p>所以此时我再看美容院的老板时，我就有把握她的钱也是赚的多但是到处有漏洞，最终也是没留住</p><p>点准了她面临的问题，我再跟她讲做好自己的事，钱是自然而然的结果时，她才能听进去</p><p>不主动去追求钱，被动的等着钱自己上门，这算是躺平吗</p><p>如果我们跟他在同一个层面，就会在意就会生气，这样我们就被这件事情给困住了</p><p>被困住了还不能还手，这是躺平，是憋屈的无可奈何</p><p>如果把注意力都放在外面，这个小朋友搞定了，可能还会有下一个没礼貌的小朋友</p><p>而修行自己，强大到我们对那些小把戏根本就不屑一顾，他们就伤害不了我们</p><h3 id="s-695" tabindex="-1">【篇外：】不求而求 <a class="header-anchor" href="#s-695" aria-label="Permalink to &quot;【篇外：】不求而求 {#s-695}&quot;">​</a></h3><p>关于项链（手链），这里再重申一遍：手链不可以治病，也不能化解业力</p><p>大家不要期待戴上之后人生就圆满了，没有这个功效</p><p>如果脾胃不好，风水上找找大小太极的坤2（西南角）的问题</p><p>也包括头像（第814章那个乾6的案例，我写的时候漏了一个知识点：头像的乾6也算乾6，图案有阴影</p><p>1为水，六煞也为水</p><p>身体的问题，是修行和业力的问题，不是戴个手链就能好的</p><p>手链不能代替自己修行</p><p>我们想象一下，赌博或者买彩票马上要开奖的时候，如果我们把那个结果看的很重要，那我们的呼吸和身体会有怎样的变化</p><p>这就是特别想要向外求的人身体上的反应</p><p>特别想要的时候，呼吸是不顺畅的，气肯定沉不到丹田</p><p>时刻关注呼吸，人活一口气，呼吸不对了，路就错了</p><p>大家把手链就当正常的水晶手链看待，一定不要起贪念</p><p>前面讲过，先修好笃定的心，然后才可以借助外力</p><p>在763章，讲到情绪与健康的问题时，说到</p><p>修行修自己，是为了让自己变得越来越好，而不是攻击和打压自己</p><p>比如说，看爱人不顺眼，看孩子不顺眼，觉察到了自己的情绪，意识到修行修自己，那我就不要把注意力放在挑剔别人的毛病身上</p><p>不挑剔他们的毛病了，还生气吗</p><p>自己的情绪也平和了，爱人和孩子的情绪也平和了</p><p>如果修行不修自己，天天骂爱人懒，骂孩子皮，不但自己生气，爱人和孩子也跟着生气</p><p>所以说，修行修自己</p><p>修自己，不挑别人的毛病了，不代表就要挑自己的毛病</p><p>聊到了爱，我们就接着这个话题，聊聊下面这位友友的提问</p><p>我们先梳理一下问题的关键：孩子很烦人，每天骂完孩子都很愧疚，想第二天改，但实际上第二天还是在重复着昨天的故事</p><p>这一套操作下来，与上面讲的修行完全相反</p><p>修行修孩子，既向外攻击孩子，又向内攻击自己</p><p>与其把注意力放在孩子身上，挑剔他这也不好那也不好，不如把注意力放在自己身上</p><p>我们先放下要求和条件，试着无条件的去爱我们想要爱的人</p><p>这句话，不单单指的是季节，也指的是人生</p><p>对小孩子要多表扬，不要处罚</p><p>养孩子就跟种庄稼一样，先要锄草施肥浇水（给予孩子足够的呵护），然后静等禾苗抽穗成熟</p><p>大多数让我们气急败坏的事情，都是无意识的贪</p><p>一切都是因果，与其责备，不如从上努力</p><p>我们也曾经做过小孩儿，我们能够体谅孩子的想法吗</p><p>如果我们不能跟孩子感同身受，那就反思一下自己的注意力放在哪里了</p><p>好多人把耐心和注意力都留给了外面的人，回家就暴躁了</p><h3 id="s-696" tabindex="-1">【篇外：】好的不灵坏的灵 <a class="header-anchor" href="#s-696" aria-label="Permalink to &quot;【篇外：】好的不灵坏的灵 {#s-696}&quot;">​</a></h3><p>最近几天在从头看书，刚看到100章出头，那一部分写的东一锄头西一锄头的太零碎了哈哈，大家没听懂的我再解释一遍，补补漏</p><p>前面评论区的图，好多友友看不到，我这次梳理的时候，慢慢都会补上</p><p>没有能力考上去的人，想努力再努力，考上的概率也不太大</p><p>比如卧底，不能用大拇指是直的还是弯的，来判断一个人会不会撒谎</p><p>大拇指直是指不愿意违背自己的心去委曲求全，但不是缺心眼儿</p><p>大拇指的形状，只是说这个人的性格是否随和，是否能够顺着人说话，还是硬气的坚持己见</p><p>无名指和食指的长短比较，也是这个道理</p><p>食指长，语言记忆能力强，有野心，事业型</p><p>无名指长，更乐观，不容易焦虑或抑郁，肢体协调性更高</p><p>这是指本来的天赋</p><p>放弃本来的天赋很简单，无名指长的人，只要贪心足够大，不断的向外求，肯定能把自己整的焦虑或抑郁了</p><p>这是向下改命，很容易</p><p>如果无名指长的人，同时还可以展示出食指长的特质：有较强的语言天赋，记忆力强，有野心，事业型，这是向上改命</p><p>第108章截图 因为可以改命，所以不论是手相面相还是八字，都不一定百分百跟预判一样</p><p>比如很多人能不能考上大学，并不完全由八字决定，跟自己也有很大的关系</p><p>（改命并不容易，大多数人都在随波逐流</p><p>第111章评论区截图 如果靠意志力改命，确实很难持久，需要持续的给自己打鸡血</p><p>我前面说的道士，一般指的是遵循天地自然规律的人，不一定要花几十块钱去网上买个皈依证</p><p>也有好多为了赚钱而去买个皈依证的人，哪怕他们连因果都不信，也叫作道士</p><p>从证书的角度上来说，骗子可能是真道士，没有证书的反而不算道士</p><p>（不足是寡淡了一些） 加上字再用，类似下面这种</p><h3 id="s-697" tabindex="-1">【篇外：】向内求 <a class="header-anchor" href="#s-697" aria-label="Permalink to &quot;【篇外：】向内求 {#s-697}&quot;">​</a></h3><p>这是算天灾，还是算人祸</p><p>大多数的情况，都是我们自己的修行没到位，大家不要什么事情都往阴性方面去想，很冤枉</p><p>问题的根本，还是在于阴阳</p><p>我们不论是在居家摆设方面，还是头像、情绪、行为等各方面，都要有意识的去阴阳平衡</p><p>你们光看，光理解了，还不够，阴阳没平衡起来</p><p>道理大家基本都懂，但就是不改，理由是找不到更好的头像，害怕换成更不好的</p><p>我当时在想：换的再不好，还能比这张更差吗</p><p>遇到这种情况，我建议大家用【更笃定的心，把这本书再认真的看一遍</p><p>坚定的要改变的心，才能让我们脱离业力的牵扯</p><p>果然是我的错，我只写了加字，没写清楚要同时注意五行和穿宫，呜呜</p><p>书里写过的内容，我没有时间再单独讲一遍</p><p>这位友友很认真的回去看书，第二天回复，得出的结论是……</p><p>这位友友留言说，急需想调整一下风水</p><p>槽点太多，点不了，只能劝她自己再好好看看书</p><p>还是那句话，改命，得付出足够大的心力去自修</p><p>今天，这位友友再次给我留言，被商家搞蒙了</p><p>是个人都能卖风水摆件 图画的是对的，也有代表性，我放大给大家看一看</p><p>先不说正北有马路这些细节，单单说缺角，大家能看出来缺哪里吗</p><p>这位友友其实学的是不错的，能把图画到这个水平，算是很用功的了</p><p>借助这个案例提醒大家一下：看房子先找方向，尤其是买房子的时候</p><p>指南针会受到钢筋混凝土的干扰，要靠在每个墙上都测一下</p><p>室内室外都要测，有时候干扰会很大</p><p>方向很重要，有些房子可以做到四个角缺八个</p><p>今天，她再次提到了投资的事情</p><p>这个问题，是不是应该先拖出去揍一顿再说</p><p>每个人的一生，都会有起起落落，哪怕命再好的人也有</p><p>只有下沉的时候，顺势蹲到更矮的位置，弹的时候才可以蹦的更高</p><p>所谓的势，无非也是阴阳</p><p>我们首先分析一下自己在什么运势上，自己的行为决策跟自己的运势是否一致</p><p>运势低的时候（阴），不要去搞大投资，向外投资为阳</p><p>就像蹦蹦床在往下弹的时候，不要向上使劲一样</p><p>（如果两口子运势都不咋样，那就一起臣服下来，不要非得在矮子里面找个将军</p><p>方向不对努力白费，越使劲离目标越远</p><h3 id="s-698" tabindex="-1">【篇外：】每个起心动念都是种子 <a class="header-anchor" href="#s-698" aria-label="Permalink to &quot;【篇外：】每个起心动念都是种子 {#s-698}&quot;">​</a></h3><p>前面不是反复提醒过大家，自修为主，神话故事听听就好不要当真吗</p><p>紧接着9点13分，在千人群留言</p><p>紧接着，qq群主也特意找我说了这件事情</p><p>大家在给自己改命的时候，得有这样的决心才能扭转命运的齿轮</p><p>还在抱怨生活的友友可以问问自己：【我付出了百分之百的努力了吗</p><p>如果方向不对，这么搞就变成死缠烂打了，我会屏蔽消息的</p><p>这位友友在那一刻的心念还是挺正的，他没有执着的向外求结果，只是想着自己能做多少都努力到而已</p><p>不期待结果的努力，这算是不求而求</p><p>粉丝中已经有人接到任务了，还不能够独立完成，所以需要吉月姐姐辅助</p><p>所以没有特殊的情况，打嗝放屁的事儿尽量不麻烦吉月姐姐，咱们自己修自己就好</p><p>我也不经常看手机，吉月姐姐更是不能一直盯着手机</p><p>这件事情是上周发生的，我本来还在想着要不要写出来</p><p>就算你敢信，但是我不敢说啊</p><p>因果，因果，因果</p><p>没有东西会无缘无故的产生，一切都是因果</p><p>不说能不能，只说我们为什么要这么去做</p><p>不是谁出钱就帮谁，还得看你占不占理</p><p>法界也有法界的规则，不可以为所欲为</p><p>不要让恶的种子结出了恶果之后，再四处外求</p><p>这件事情能不能解，关键也在于自己，得看自己的态度能不能让对方愿意和解</p><p>恶灵只是原因之一，还有其他事情就不细说了，还需要持续的保持正念</p><p>这也是为什么不建议大家轻易做法事</p><p>不如把注意力好好放在自己身上</p><p>起心动念都是种子，随时随地注意自己种的是什么种子</p><p>咱这就是一本小说嘛，大家一起聊聊天，一起自修，多么愉快的事情</p><p>大家不要再弄这么紧张的事了哈</p><p>大家不要遇到点儿事情就胡思乱想</p><p>不论什么时候都不要疑神疑鬼，乱了分寸</p><p>自己才是一切的根源，时刻记住：【修正心，存正念</p><h3 id="s-699" tabindex="-1">【篇外：】何为正道 <a class="header-anchor" href="#s-699" aria-label="Permalink to &quot;【篇外：】何为正道 {#s-699}&quot;">​</a></h3><p>大家看看下面这位友友的情况，好像这是我第一次连名字一起截图发进书里的案例</p><p>前面已经说过很多次，【改命，得有足够强大的心力</p><p>哪怕是再长久的黑暗，只要有光就能破除</p><p>既然看了书了，为什么不在第一时间改掉</p><p>把心里的贪念扔掉，给阳光腾出一些地方</p><p>生气位 这位友友反馈的是孩子学习</p><p>不同的宫格，有不同的五行八卦场，就是这么简单</p><p>承浆穴 这位友友反馈的是健康方面，口腔溃疡和嗓子疼，按承浆穴</p><p>承浆穴是唾液的开关</p><p>玉液生津，唾液可以灌溉脏腑、润泽肢体、促进消化、滋阴降火、生津补肾、祛病延年等等</p><p>但凡见效慢的，我都懒得坚持</p><p>对于陷在困境中的友友，大家一定要记得，不论是我说的，还是其他友友们反馈的，我们对于来说，都是外人、外物、外力，【改命得靠自己</p><p>不要听信任何人的任何说辞</p><p>德行，就在我们的一言一行起心动念之间</p><p>我们起的是善念，留下的就是德行</p><p>我们起了恶念，招引的就是邪魔</p><p>而修正念，则是根本</p><p>一旦执着，就容易起贪念</p><p>贪念招魔，入魔之后处境会更难</p><p>关于放下贪念和要不要赚钱这两者的区别，可能个别友友仍旧搞不清楚</p><p>不论是修行层级，还是物质生活，还是社交能力，还是任何方面，我们都希望自己越来越好</p><p>就算那些不思进取天天打游戏的人，也希望自己在游戏里面越来越厉害</p><p>我说的戒贪，从来不提倡大家过穷苦的生活</p><p>不贪，不代表不可以赚钱</p><p>我们要把注意力放在利他上面，只要我们对别人有足够大的帮助，阴阳平衡，钱是自然的结果</p><p>就好比放下贪念修回本真是种子，神通是自然而然的结果一样</p><p>我们在种子上下功夫，这就叫不贪，因为阴阳会平衡</p><p>贪的意思是，不想认真种种子，就想要个又大又好的结果</p><p>急功近利，期待不劳而获，烧几块钱的香许几个亿的愿，这是贪</p><p>的意思是，超出目前的正常水平</p><p>钱都是在做的过程中，慢慢赚到的</p><p>想赚钱的人，恨不得用一百种办法把别人兜里的钱弄到自己兜里</p><p>这个众生，包括自己</p><p>比如，我懂一点点五行八卦，我把它写出来，千千万万的人看到了，验证了，受益了</p><p>在这个过程中不耽误赚钱，只要别人收到的，多于我拿回来的，就不算是贪</p><p>至少在我目前的认知里，是这么认为的</p><p>把注意力放在利他的种子上，顺便赚钱，而不是把注意力放在钱本身上</p><p>通过买卖头像赚钱，这本身不是问题，问题在于上图这个交易里面，卖家并没有帮助到别人却赚了钱，这就算是贪，甚至算是骗</p><p>戒贪，是把钱的概念先放下</p><h3 id="s-700" tabindex="-1">【篇外：】五鬼磁场 <a class="header-anchor" href="#s-700" aria-label="Permalink to &quot;【篇外：】五鬼磁场 {#s-700}&quot;">​</a></h3><p>今天友友推荐的这本从第一章开始，作者就站在上帝的高度，保证还声称医院无法治疗的绝症，书里有</p><p>群里的好几位友友都看过这本书，我便问他们99%的好办法是什么</p><p>不论是否收钱，提倡外力可以解决99%的问题，都是诱发人的贪念的</p><p>即使不收钱的也可能是魔，只要诱发人的贪念的都是不正的</p><p>大家也不必到处去看很多的书，把注意力收回来放在自己身上，关注自己的一言一行就好</p><p>我本来打算快速梳理一遍本书，查漏补缺一下就完结的，但是每天读不了太多</p><p>我也是一个一个的评论点开看的，确实是慢，但评论区太搞笑了又不舍得放弃，一时半会儿看不完</p><p>我看的慢还有一个原因是其他的事情太多了</p><p>我刚开始忙的时候还疑惑呢，吉月姐姐的还能传染吗，我都不打卡了怎么还能累的跟个陀螺似的</p><p>19延年，做尾号本来就挺累的，再叠加一遍，两个延年更累</p><p>虽然数字9结尾代表累，但是跟具体是哪个气场的9也有关系，累的方向不一样</p><p>比如我的199累的是工作，吉月姐姐是，89祸害磁场代表的是口才，她要不闲着的在手机上回复大家的各种留言</p><p>再比如下面这个案例</p><p>9代表累，那她累的是哪方面呢</p><p>79是五鬼气场，就忙活这些事儿了</p><p>7999，相当于是三个五鬼磁场</p><p>如果是9797，也算是三个五鬼磁场</p><p>同样都是三个五鬼，但9结尾的话会加重强度，所以7999这三个叠加，比9797还累乎</p><p>五鬼也有好的一面</p><p>五鬼的主要特点是飘忽不定，不论是性情、还是财运、还是感情</p><p>五鬼的五行属火，容易火气大，影响心脏和血液方面</p><p>但好的地方是，五鬼的思绪飘忽，灵感强，很聪明，反应快，学习能力强，创意也多</p><p>只要能修好脾气，不贪心，可以发展其正向的能量</p><p>7999最好还是算了，别挑战这么高难度的，能改还是改一改的好</p><p>五鬼磁场还有其他的表现形式，比如下面这位友友遇到的问题</p><p>这位友友爱受伤，也爱乱想，这也是五鬼的特点</p><p>比如有的人的五鬼磁场全用在睡不好上面了，他就不容易受伤</p><p>【记得戒贪，戒火气</p><h3 id="s-701" tabindex="-1">【篇外：】孩子的问题 <a class="header-anchor" href="#s-701" aria-label="Permalink to &quot;【篇外：】孩子的问题 {#s-701}&quot;">​</a></h3><p>姓名学、吉日、以及本书的收尾篇章我都写个差不多了，但是不想发，总觉得还没到时候，那就先存着吧，顺势而为</p><p>担心将来他不能自力更生，成为社会拖累</p><p>（没回复的友友自己再找找，改命得靠自己</p><p>不想努力的施肥浇水，就盯着结果抱怨孩子的成绩不好</p><p>我前几天见了一位朋友，就是这种情况</p><p>他口口声声孩子废了，全班倒数第一</p><p>这位朋友也是常年修行打坐练功的人</p><p>我现在多打坐多练功，不会再跟他生气了</p><p>他爱学学，不爱学拉倒，并不能影响我的情绪</p><p>我们两个人分别出几根手指头，看谁最先算出来加在一起是多少</p><p>小孩子玩游戏也喜欢赢的感觉，我基本都是跟他同时说出答案，偶尔慢一点点，督促他更快更熟练</p><p>孩子也很精，他很快发现一个诀窍，后来每次他都出1，只要看到我的手指数量，再加一个就是答案，速度就更快了</p><p>我也发现了他的小技巧，但是我不能否定他的做法，否定就是打压</p><p>孩子一听有道理，可不能再总是出1了</p><p>孩子玩这个游戏，他大部分时间都能赢，而且越熟练速度越快，玩一会儿再做卷子，卷子上的题也变简单了，几分钟就算完了</p><p>我儿子都二年级了，不适合玩你说的这个游戏</p><p>我再次白了我朋友一眼：看看，多聪明的孩子</p><p>你这个爸爸连孩子学什么都不知道，就知道抱怨孩子成绩不好</p><p>倒数第一就倒数第一，随缘吧</p><p>你都不知道孩子会不会乘法口诀，你好意思说你看着孩子写作业</p><h3 id="s-702" tabindex="-1">【篇外：】我可以做什么让事情变得更好 <a class="header-anchor" href="#s-702" aria-label="Permalink to &quot;【篇外：】我可以做什么让事情变得更好 {#s-702}&quot;">​</a></h3><p>随缘指的是，尽人事听天命</p><p>不播种也不施肥，躺着啥也不干就等着，这算不算是另一种的</p><p>就算是出家人，还得一大清早起来做早课呢</p><p>一开始就盯着孩子的问题，修行光想着修孩子，最终发现修不了孩子，不得不放弃</p><p>那所谓的修行修自己，体现在了哪里</p><p>躺平就算修自己了吗</p><p>修自己的意思是，【我可以做什么，让事情变得更好</p><p>没有，那就不算修自己</p><p>（这种算损人不利己</p><p>（这种算不损人也不利己，比上一种好一点，但什么都不做是懒惰</p><p>不论是孩子还是爱人，都是一样的道理</p><p>天天唠叨没结果却还继续跟复读机一样，光动嘴不走心，那不是修行</p><p>（而不是以的傲慢偏见来衡量</p><p>这也是前面一直讲的，注意力就是生命力</p><p>我们要随时觉知自己的注意力，放在了哪里</p><p>再强调一次，众生包括自己和他人</p><p>损人利己都还不算是最坏的，有多少人常年做着的事情</p><p>不要让的幌子蒙蔽了事实</p><p>把孩子当成一个跟我们一样的人，他有情绪，有想法，有感觉</p><p>顺势而为，首先要顺应他的运势</p><p>需要休息的时候（比如晚上或低谷期），父母一直督促他上进、努力、多做题，那么到了白天，他肯定就会没精神，犯困，注意力没办法集中，只有游戏里那种刺激的画面才能勉强让他睁开眼</p><p>发生这种情况之后，父母除了不断的向孩子抱怨这个结果，你有具体做了什么能让他变得更好的事吗</p><p>把心立正了，再说术的层面的调整</p><p>如果心是歪的，修行光修孩子不修自己，给出去的都是负能量的打压却希望开出美丽的花，无异于缘木求鱼，这是贪念</p><h3 id="s-703" tabindex="-1">【偏外：】随缘是修行者的大忌 <a class="header-anchor" href="#s-703" aria-label="Permalink to &quot;【偏外：】随缘是修行者的大忌 {#s-703}&quot;">​</a></h3><p>修行两个字，很简单，也很难</p><p>书能看到这里的人，估计都是修行的人，至少是打算要修行的人</p><p>修行跟躺平，很多修行者容易混淆</p><p>如果执着于有，（包括亲情、爱情和友情），大家都明白这是执着</p><p>那如果想起某个人就生气，坚决的屏蔽他所有的消息，坚决不来往，坚持，这算不算执着</p><p>一辈子别来往了，这算是放下吗</p><p>修行，很容易堕入空的陷阱里</p><p>所有修行修到消极的人，都是执着于空了</p><p>误把空认为是放下，打着的幌子，不努力不上进，结果越修越偏，越修心灵上越不自由</p><p>放下指的是不为所困，是自由的，是喜乐的</p><p>不是一辈子不来往就叫放下，恰恰相反，只要还有情绪，那就是没放下</p><p>有特意想要避开的人和事，对应着的是自身能量的淤堵</p><p>不太聪明的人比所谓的聪明人快乐的多，因为他不会多想，不会过多的在心里给自己加戏，上演情绪小电影</p><p>（当然，有些人过于无知者无畏，也不一定就是好的</p><p>阴阳平衡，过犹不及</p><p>放下，意味着能分清楚</p><p>比如别人不讲道理，那是</p><p>我能点你一句就点你一句，你收不收的到我说了也不算</p><p>（不说不是因为我生气了，而是我单方面输出你收不到，那我做的就是无用功</p><p>如果哪天你又愿意听了，想要寻求帮助，（众生的总体利益有可能会增加）我还可以再点几句</p><p>如果做出一个决定（与某人老死不相往来），对社会的进步没有意义，那么做这个决定的目的是什么</p><p>修行，修正的是自己的行为</p><p>修行者，尽量不提两个字</p><p>大部分修行者口里的，都指的是消极逃避不愿面对</p><p>魔披着袈裟在讲法，讲的就是的法</p><p>魔披着袈裟在讲法，打着的名头，消磨大家的斗志，让大家陷入的逆来顺受的心境里</p><p>如果修行者们都了，魔在大举侵略祸害人间的时候，谁会站出来维护正义</p><p>指望那些自私自利不修行的人吗</p><p>修行者，一定要随时观察自己的心，问问自己：【我这样做（一言一行），对众生有帮助吗</p><p>心不自由的人，先看《金刚经》</p><p>修行者自己先正了，才能引导其他人一起走上正路</p><p>修行，是为了自由</p><p>如果越修生活过得越不自由，请再读几遍《金刚经》和《心经》，及时纠偏</p><p>不要听张三说什么，李四说什么，也不要听我说什么</p><p>我说的，也只是局限于我的认知下对经典的理解</p><p>既然是法，我们正心正念的听，也可以从中学习到有用的部分</p><p>自己要有主观意识，辩证的学习，不要照盘全收</p><p>比如下面这位友友，他很热心的跟我分享了很多功法</p><p>他花了大几千买的视频功法也无私的分享给我了 这位友友前面发的功法，功看起来是没问题，但感觉传播的人心不是正的</p><p>假的多，真的少，大家再多加上一百个警惕心</p><p>能最好，不行的话，就只关注自己的起心动念就好，不必借助太多外力，以免被带偏</p><p>小男孩的决定是：再买件一样的，天天换着穿，让他看习惯</p><p>要想学透姓名学，花费的时间和精力一点儿都不比风水、修心等方面少，但是作用远远没有风水和情绪对我们的影响大</p><p>我会在下一章写一下姓名学的主要知识点，利用五行化煞给自己做一个辅助，但不建议花费大量的时间和精力去深挖</p><p>尤其是重症，除了业力问题，还有情绪和风水的问题</p><p>有些人迷迷糊糊，可能都不记得自己在哪里生气把自己的能量堵住了，能找到根源就容易了</p><p>六字诀念的时候，虽然每次的气都吐干净好，但是每个人呼吸深浅不一样，不强求，随着自己身体的状况，慢慢吐就行</p><p>适合自己的，才是最好的</p><p>风水和情绪疗法，在改命里面的性价比最高</p><p>因为风水和情绪，作用于人体的时间很长，我们一天到晚都沉浸在这种气场中</p><p>姓名学也有五行助运的作用，就跟带个配饰，穿个五行衣服差不多，用一次有一次的力量</p><h3 id="s-704" tabindex="-1">【篇外：】人活一口气 <a class="header-anchor" href="#s-704" aria-label="Permalink to &quot;【篇外：】人活一口气 {#s-704}&quot;">​</a></h3><p>先就着前段时间火阿姨清理的结果，跟大家说一下</p><p>这么细的脖子，大家第一眼看，感觉卡气不</p><p>再者，头比身子还要大，脑子里的欲望太多太多</p><p>修真啊，得放下脑子里的欲望和算计</p><p>再比如说，气，可以反应人的运势</p><p>生气或者紧张，也容易卡气</p><p>所以情绪也很重要</p><p>坏脾气本身就是煞</p><p>正向思维，常怀感恩之心，可以化解自己的坏脾气</p><p>（注意：修行修自己，是自己要懂得感恩，而不是拿着这句话去教育别人</p><p>人之所以起情绪，是因为的利益被侵犯了</p><p>作者?露易丝·海，5岁时遭受邻居的性侵和继父的虐待?，15岁辍学，16岁未婚先孕并被男友抛弃</p><p>但她没有放弃，她明白，病是情绪的反映，于是开始转念，积极疗愈</p><p>坎坷的经历，让她蜕变成着名的心理治疗导师，帮助无数人提升了生命质量，被称为</p><p>在第73章讲过，肩膀酸痛僵硬，代表心理压力大</p><p>在头像上也是一样的，都是潜意识的反应</p><p>脖子跟这个项链的比例，再配上那么大的耳坠，会加重肩颈负担，容易有各种事情导致压力大</p><p>头像，反映的是我们的潜意识，说明了我们处在一个怎样的状态中</p><p>比如黑白色头像，反映人的情绪低落</p><p>有一门课程叫《色彩心理学》，讲的是颜色对人的情绪和健康的影响</p><p>（也就是视觉、听觉、嗅觉、味觉、触觉</p><p>哪个用的最多，答案是毫无疑问的吧</p><p>比如，同样户型的房子，大红的软装，全黑的软装，白色的软装，淡咖的软装，能不能引起身体不同的舒适程度</p><p>比如紫色代表高贵和神秘，可以帮助人们进入深度思考的状态</p><p>蓝色代表宁静和信仰，可以降低血压、舒缓情绪，有助于焦虑症患者放松身心</p><p>（五行属性介于水和木之间</p><p>绿色代表生机和治愈，可以缓解压力</p><p>（五行属木，主肝，肝开窍于目</p><p>红色代表激情和欲望，可以加快心跳、提升血压、激发斗志、增加活力</p><p>黄色代表温暖和稳定，给人带来积极乐观的情绪</p><p>（五行属土，卧室装修用浅咖色比较平和</p><p>白色代表纯净和无生命</p><p>（五行属金，意味着肃杀和收敛</p><p>黑色代表否定和恐惧</p><p>（五行属水，其特点是向下</p><p>学玄学，不是看谁的名气大，也不是看谁能吹，而是看有没有道理，然后看结果</p><p>五行八卦有用，但是不建议大家到处去学，除非亲自验证过其有效性</p><p>别人说的再好，那也不能成为掏钱的理由</p><p>九运，离中虚，既指虚拟的技术和文化，也指虚假，大家谨慎辨别，不要贪心求不劳而获的</p><p>但如果自己没有能力的时候，不要贪，脚踏实地的过好自己的日子就很好</p><p>在拜佛之前，一定要先问清自己：我拜的是佛，还是拜的心中的贪念</p><h3 id="s-705" tabindex="-1">【篇外：】正念是2025年最重要的护身符 <a class="header-anchor" href="#s-705" aria-label="Permalink to &quot;【篇外：】正念是2025年最重要的护身符 {#s-705}&quot;">​</a></h3><p>我们借着这个话题，先聊一聊人与人之间的关系</p><p>一个满嘴都在抱怨老板、抱怨同事、抱怨父母、抱怨社会的人，他是一个懂感恩的人吗</p><p>不论多少功劳，一抱怨全没了</p><p>我们把注意力放在事情积极正向的一面上，才不会把贵人赶跑，我们的运势才会越来越好</p><p>大家看完了感觉有收获，这算是善事儿</p><p>如果我非得强迫那些看不进去的人看，他们看了一肚子气，产生了厌恶的情绪，这就不算是善事儿</p><p>再比如陪孩子写作业</p><p>如果孩子不写作业就骂他，口口声声为他好，把孩子骂的一无是处，孩子除了受到了心灵上的伤害之外一无所获，这就不算是善</p><p>如果孩子不写作业，我们找到他不愿意写作业的卡点，帮他解决问题，比如给他一个更简便的算法，让他能感觉到自己变成了更优秀的自己（这是快乐的本质），作业越写越快，越写越开心，这是善</p><p>让别人厌恶的事情，不能称之为善</p><p>同理，为恶，别人都喜欢，要不要为恶</p><p>危机，拆开来看就是危险和机会</p><p>正心正念的做事，是2025年最大的护身符</p><h3 id="s-706" tabindex="-1">【篇外：】自我实现的预言 <a class="header-anchor" href="#s-706" aria-label="Permalink to &quot;【篇外：】自我实现的预言 {#s-706}&quot;">​</a></h3><p>人的本质在其现实性上，就是一切社会关系的总和</p><p>命运好不好，说的就是我们跟他人之间的关系是怎样的</p><p>改命，改的就是关系</p><p>所以，这个问题我们拆开来再详细说一下</p><p>也就是说，你相信什么，什么就会实现</p><p>比如，你认为老板喜欢你（正向思维），他多给你安排工作，你会觉得他这是在重用你（想锻炼你提拔你），他少给你安排工作，你会觉得他这是在照顾你</p><p>如果你认为老板不喜欢你（负面思维），他多给你安排工作，你会觉得他是在给你穿小鞋，他少给你安排工作，你又会觉得他看不上你、想把你边缘化</p><p>不论你认为老板喜欢你还是不喜欢你，你都能在工作中找到各种，证明自己的，然后理直气壮的说</p><p>但如果反过来，我认为自己运气很差，那我可能就会想，写书的这些人有几个学历比我好的，写了些什么乱七八糟的大家还无脑跟风，没有慧眼不识珠，我怎么那么倒霉就是遇不到更多的伯乐呢</p><p>我们拥有怎样的人生，取决于我们的信念</p><p>上面截图的观点，翻译过来是：我穷=我没有价值=我不能付出=没有贵人会帮我</p><p>有付出才有收获，实现对等的交换，这是阴阳，也是天道</p><p>我穷=我没有价值=我不能付出</p><p>退一万步讲，就算你没有特别能拿得出手的优势，你会的，你的贵人全都会，那还有时间成本的差别呢</p><p>贵人忙的时候，你可不可以做一些力所能及的事情为他分担呢</p><p>不能付出，不是因为穷，也不是因为自己没有价值，而是因为没有那个意识</p><p>要不要挤进去，关键要看你的目的是什么</p><p>如果你挤进去是想占人家的便宜，那确实不能硬挤，这会让彼此都不舒服</p><p>所以，与其抱怨，不如问问自己，【我能为他人提供什么样的价值</p><p>让心自由，得打破思维模式</p><p>丹霞禅师连佛像都能烧，人生还有什么不能</p><p>我长得胖，我可不可以少吃多运动</p><p>我不会做家务，我可不可以去学</p><p>我白头发，我可不可以搞成黑的</p><p>不是不能，而是我们选择把时间和精力花在我们认为更重要的方面</p><p>就像我跟大家分享面部的调整一样，调不调其实也没那么重要</p><p>……只有问题，没有方法</p><p>至于要不要把时间花在变美上，这是每个人自己的选择</p><p>我可以不烧佛像，但不是必须不能烧</p><p>我可以不杀生，但不是必须不能杀</p><p>所有的必须和不能，都是禁锢</p><p>我可以这样做，但不代表我必须这样做</p><p>当你心中有的时候，就有了执念</p><h3 id="s-707" tabindex="-1">【篇外：】利他即是利己 <a class="header-anchor" href="#s-707" aria-label="Permalink to &quot;【篇外：】利他即是利己 {#s-707}&quot;">​</a></h3><p>分数确实是老师给打出来的，但修行，修的是自己</p><p>也就是说，一旦把问题归因于外在，会容易产生轻生的念头，这就是入魔</p><p>天堂与地狱，就在一念之间</p><p>把注意力收回来，放在自己的身上</p><p>这种思维模式很重要，可以应用于生活的方方面面</p><p>比如有人懊恼：别人都不喜欢我</p><p>找到我们自身的特质，再遇到欣赏我们的人，问题便解决了</p><p>即使没有好看的外表，没有有趣的灵魂，没有矫健的身材，没有显赫的家庭背景，但只要有积极乐观的思维模式，也足够吸引到一些需要正能量的人喜欢我们</p><p>也不必贪多，能满足基本的社交需求就好</p><p>主耶稣和佛菩萨都不能让所有人都喜欢，我们又何必太贪心呢</p><p>就算什么都不会，打扫个卫生总可以吧</p><p>如果啥也不是还期望让别人喜欢自己，那就是太贪了</p><p>在意别人喜不喜欢自己的时候，注意力是放在了别人的身上</p><p>提升利他的能力，就是自我价值的实现</p><h3 id="s-708" tabindex="-1">【篇外：】捡了个大元宝 <a class="header-anchor" href="#s-708" aria-label="Permalink to &quot;【篇外：】捡了个大元宝 {#s-708}&quot;">​</a></h3><p>一位友友说，用五行杵啄肉垫，好了几天又出现了</p><p>先给大家当个小练习吧</p><p>如果能分析出别人的问题，自己在修行路上也会心里清清楚楚</p><p>关于修行，书里讲了很多，因为这是一切的根本</p><p>情绪是正气的指标</p><p>正气足的时候，外邪不侵</p><p>再比如第601章和第602章</p><p>再比如，第654章</p><p>这个道理，放在健康上也一样</p><p>五行杵轻轻敲几下就有效果，仅仅因为，消失的小肉垫竟然还会出现，就这么个事儿也能起情绪，可见日常生活中，是秉持着怎样的思维方式</p><p>关于思维模式的问题，书中也反复讲过很多</p><p>现在既然聊到这里，那就再重复一遍</p><p>第二，万事皆分阴阳</p><p>感恩是体现在起心动念的那一刻，而不是做给别人看的</p><p>如果我不懂感恩，我可能会想：五行杵又不是没有效果，我还是免费分享的，竟然却有人不懂感恩，还鼻子不是鼻子脸不是脸的来我，凭啥呀</p><p>（责怪别人不感恩的同时，也代表自己没有感恩之心</p><p>这种思维模式，导致的结果就是怄气</p><p>这不就是捡了个大元宝嘛</p><p>阳气足了，可不就是越来越开心了嘛</p><p>只有好和更好两种结果，哪里还会起情绪呢</p><p>不起情绪了，自然也就不会产生新的淤堵了</p><p>再啄几天肉垫没了之后，那就是在好和更好的两种结果里面，出现了更好的那个结果了呗</p><p>感恩，只跟自己的起心动念有关</p><p>不是发个红包表达感谢，就是感恩了</p><p>自己的情绪怎么样，气在哪里卡住了</p><p>自己的言行和念头是积极正向的吗</p><p>另外，贪为五毒之首</p><p>不贪图结果，就没有期望</p><p>没有期望就没有失望，自然也不会起情绪</p><p>顺便再说一下外在影响</p><p>再跟大家说说另一个案例</p><p>然后不依不饶的闹</p><p>管理员实在是不能理解：就是不想收你的钱而已，这有啥可闹的</p><p>我前面几次三番的说过，师父接不接，是要看缘分的，不是什么事情都会接</p><p>前面也反复说过，【先修心，心正了，才能借助外力</p><p>心念不正的话，这边刚给你处理好了，你一个贪念又招惹一堆鬼神，就好那么一会儿会儿能有多大意义</p><p>我们首先要学会转念，把起心动念放在积极正向的一面上</p><p>比如这位非得看前世的友友，赖我引起了她的兴趣，不给她看不行，这件事好的一面是什么呢</p><p>用她的逻辑来推理的话，就好比说我看爽文</p><h3 id="s-709" tabindex="-1">【篇外：】放屁容易破产吗？ <a class="header-anchor" href="#s-709" aria-label="Permalink to &quot;【篇外：】放屁容易破产吗？ {#s-709}&quot;">​</a></h3><p>先给大家分享一个的头像练习</p><p>不论是用卡通人物，还是用小动物，都是代表自己</p><p>似乎是想拽着自己的头发，试试能不能把自己从地面上提起来</p><p>我们只要活的清醒，能觉知到自己的状态就好</p><p>借着这位友友说的，我们聊一聊改命</p><p>命不能改，改的是运</p><p>我们现在的生活状态，就是我们真实的命运</p><p>改的意思，是改变</p><p>但谁能证明我们原来是什么样的命</p><p>有人认为现在比以前过的更好，就是改命或改运了</p><p>但有没有可能，这个人本来的命运就是先抑后扬的呢</p><p>人生只有一个结果，就是当下的事实</p><p>如果有人信了，可能就会觉得命不能改，只能小幅度的改改运罢了</p><p>这个推理逻辑，跟是一样的</p><p>确实，所以就把两者凑成因果关系了</p><p>包括《地藏经》能不能在家里读，也有类似的推理</p><p>《地藏经》不能随心念的观点，既不是经书所示，也不是高僧所传，只是流传于民间</p><p>有人读《地藏经》，然后招阴了</p><p>于是就有人得出结论，《地藏经》不能轻易读</p><p>评判一个说法对还是不对，除了看事实，还得看有没有道理</p><p>比如大爱的刘老师，大家之所以那么相信他，就是因为看到了太多的人在感恩的</p><p>我当时的认知就是</p><p>那么多人好了，就是足够的证据</p><p>如果心不稳，或者心里犯嘀咕，窜稀便秘的事儿都赖在《地藏经》上，那就先别读</p><p>可以从《金刚经》或《心经》开始，先提升一下正气和正念</p><p>别人说的观点，可能受他认知的影响，也可能是出于某些个人目的</p><p>把问题归因于外在的逻辑，会很荒谬</p><p>乞丐都放过屁，因此，放屁容易成为乞丐，建议大家都不要放屁</p><p>然后，大家都要夹紧双腿过日子吗</p><p>确实是我要着重修行的点</p><p>软，代表的是活力，就跟小婴儿一样，随时都能抱着脚丫就啃</p><p>硬气=气硬，肢体硬了，代表的是失去活力</p><p>虽然也修的圆乎乎的，平时看起来笑呵呵慢悠悠的，但还远没有修到位</p><p>这既跟修为有关系，也跟业力也有关系，在新书里面会写到这部分</p><p>我命局里炙热的火气还没有完全修到位，思维模式上还是急的</p><p>别说这种套话，你再说点儿别的我看看</p><p>比如这本书开篇的第一章，初见老道儿时，我有一句话是第一章截图 一位友友认为，应该是听听，怎么能</p><p>有句话说，性格决定命运，不无道理</p><p>修行是一辈子的事，我跟大家一样，都还走在修行的路上</p><p>我觉得这句话很有代表性，所以就拿出来说了</p><p>是因为这句话本身，代表了很多人的思维模式，我并没有攻击具体某个人的意思</p><p>我的注意力都放在了案例上，可能忽略了友友们的感受，你们不会吓得不敢留言了吧</p><p>你们是不是也不记得自己曾经评论过什么，然后突然被我截图到书里，吓了一大跳</p><p>我尽可能再收敛一些哈</p><p>命和运，在现实生活中并不能分开，我们当下的生活就是命运</p><p>改命，指的是改变命运</p><p>（之前为了认知习惯，有的地方写的改命，有的地方写的改运，意思是一样的</p><p>那为什么小的能改，大的不能改</p><p>这不是因为不能，而是因为阴阳平衡</p><p>也就是说，月入五千的人，感觉月入一万就很幸福了</p><p>这既说明人的贪念无止境，也说明人的认知有局限</p><p>万法皆空，因果不空</p><p>比如，不少友友问的问题，书里都有写过，但大家却迷茫着四处询问，就是不能认真的多看几遍</p><p>前面说过，业力会蒙住眼睛</p><p>公众号留言 我看到不少友友说，看第二遍通透了很多</p><p>有些人业力更大的话，可能需要看第三遍甚至第四遍</p><p>想解决多大的业力，就要付出对等的努力</p><p>你想要的，确实有可能借助五行力量得偿所愿，但</p><p>不到最后一刻，你并不知道自己要付出的代价是什么</p><p>注意力都放在了求而不得的事物上，会自动忽略了自己所拥有的，那是即将失去的代价</p><p>也不是说追求安稳就是好的，只是我认为，就算要去追求大成就，至少在交换之前，先搞清楚自己要付出的代价是什么，以免得偿所愿之后，又追悔莫及</p><p>这位友友早就算出来自己在2024年有一个坑，然后仍旧一脚踩了进去，导致现在，在家闲的揪耳朵玩</p><p>我们绝大部分人，都在五行之内，都还没跳出去</p><p>该敬畏还是要敬畏，五行是一种力量</p><p>但尊重了就可以了，不要掉进另一个极端的宿命论里去</p><p>五行，只是一种力量，我们可以顺势而为</p><p>但尊重了之后，也不要宿命，认为我命中注定，就应该挨这一棍子</p><p>如果从出生开始，除了喝奶啥也不会，那么就算命里有钱，也拿不到手</p><p>万一他不满足，还想再赚200万，那么即使他付出再多两倍的努力，也是很难达到的</p><p>在上限范围之外，没有多余的福报可以兑现了，那么努力的方向就不再是努力工作，而是要改成提高上限</p><p>也就是说，能力被压制住了，没有活出自己该有的样子</p><h3 id="s-710" tabindex="-1">【篇外：】戒贪，是每个人的终身功课 <a class="header-anchor" href="#s-710" aria-label="Permalink to &quot;【篇外：】戒贪，是每个人的终身功课 {#s-710}&quot;">​</a></h3><p>太多了也记不住，大家就看鼻头和人中附近的数字就行</p><p>这些数字，代表的是年龄</p><p>如果面相上，鼻头两侧的部位，线条不流畅，或者说看起来紧绷，有拧巴的感觉，那这个位置就卡气</p><p>对应的数字，是虚岁</p><p>再给大家分享个好玩的事情</p><p>这位友友的工作是水电消防，他的意念可以当用</p><p>什么念头都放下，把注意力放在呼吸上，就容易入静，然后感知力就会扩大</p><p>迷茫和踩坑，都是因为贪</p><p>就像我当年，就是贪图了大爱的刘老师保证的，也保证</p><p>人一旦起了贪念，什么阴阳之道，全都抛之脑后了</p><p>虽然说起来简单，但贪念有时候是很隐秘的</p><p>我当时以为，十万也不算小钱，我是交学费学的，这算是交换，不算是贪</p><p>这个交换的内容，既违背因果，又违背阴阳之道，全宇宙都没这种好事儿，怎么不是贪呢</p><p>贪，不一定是贪钱</p><p>贪健康、贪神通、贪功德、贪面子，都是贪</p><p>几百的其实也够用，就是有点儿厚，所以就了一下</p><p>不贪的话，我们会很清醒的知道自己在干什么</p><p>戒贪，是我们每个人都需要警惕的</p><p>90%以上的痛苦，都根源于贪</p><p>贪念不除，换个环境并不能解决问题</p><p>但如果能下定决心，咬紧牙关坚定要改命，那么从下决心的这一刻，无解的问题就变成有解了</p><p>用钱去换钱的坑，就别踩了，比如短视频剪辑课程就不要报了</p><p>就像明明没钱，还要用钱去装点面子的行为，就是自己给自己找不自在</p><p>让心里舒服的办法有很多，唯独不要用自己短缺的东西去交换，那样留下的隐患会更不舒服</p><p>脚踏实地，先解决生存问题，再谋求发展</p><p>只要还没成道成佛，我们都有贪着的点</p><p>坚决不收钱，贪图名声或功德，也是贪</p><p>戒贪，是每个人的终身功课</p><h3 id="s-711" tabindex="-1">【篇外：】积极心理学 <a class="header-anchor" href="#s-711" aria-label="Permalink to &quot;【篇外：】积极心理学 {#s-711}&quot;">​</a></h3><p>沙哈尔教授的作品有《幸福的要素》、《幸福的方法》、《幸福超越完美》等等</p><p>很多让人生气的人或事儿，是因为不能理解对方为什么要这么做</p><p>但事实可能是，大家觉得既然有这么多人在围观，肯定有人已经报警了，自己就不要重复占用公共资源了</p><p>不然，大家会觉得，反正又不是我一个人的责任，互相推诿，最后谁也没干，大家还都不认为是自己的问题</p><p>这就是社会心理学</p><p>下面给大家发几个友友们自己推理验证的案例</p><p>如果身体不舒服了，在对应的位置找找问题，大小太极都看一下</p><p>先推理，然后验证</p><p>下面再给大家分享另一位友友的案例</p><p>这位友友学的也挺明白的，东南角巽4位和坎1位不宜见水</p><p>另外，她还自行推理解读了自己的头像</p><p>头像解读的也挺好，说明学习的非常认真，不但记住了讲过的，还能自行推理出对应关系</p><p>所谓的白花了，是指没有对自己产生直接的益处</p><p>再给大家分享一个情绪疗法的反馈</p><p>吐干净了就不会再吐了</p><p>最后提醒大家一件事，现在网上有很多小视频，是用AI模拟的一些名人的口型和嗓音，读的是胡说八道的文案，不是视频当事人自己的观点</p><p>目前非常非常乱，即使是自己以前相信的师父的视频，也可能是AI模拟出来的谎言，大家注意辨别内容，不要照单全收</p><h3 id="s-712" tabindex="-1">【篇外：】越学习，离道越远 <a class="header-anchor" href="#s-712" aria-label="Permalink to &quot;【篇外：】越学习，离道越远 {#s-712}&quot;">​</a></h3><p>截图里的道之光分享1，是一位友友建立的，问过我可不可以分享书里的内容</p><p>个人不可以组织募捐，我也没有什么很好的捐款平台给大家推荐</p><p>我推荐的课程，我肯定要一一筛选过，根据不同老师的优缺点，做一些优化调整</p><p>比如，有的老师做过培训会讲的比较详细，有的老师悟性很强言简意赅对小白更友好，有的老师则是偏实战的更侧重于化解，能不能融合，还是分开做小课，还是推荐其中的某一位老师，我还没有时间梳理</p><p>状态好的话，和心情烦躁相比，两者能差出去多少分</p><p>修心这一部分，外求是求不到的</p><p>不是学五行八卦有多么特别，其实它就跟学画画、学舞蹈一样</p><p>有了基本功之后，能不能表现出有生命力的美，取决于静</p><p>把人为的的想法放下，顺其自然</p><p>把会的能用出效果来，就是最好的</p><h3 id="s-713" tabindex="-1">【篇外：】自我疗愈 <a class="header-anchor" href="#s-713" aria-label="Permalink to &quot;【篇外：】自我疗愈 {#s-713}&quot;">​</a></h3><p>关于自修还是有人找不到方向</p><p>第二步，好好做事</p><p>看了经书之后，知道何为正道，然后落实到生活中，修行为，修脾气</p><p>第三步，才是打坐冥想这些</p><p>如果没有前两步的基础，只是打坐练功，很容易落入空里面</p><p>经书是引导，做事是践行（用实际行动来实践），修行方法只是辅助而已</p><p>如果看不进去书，也可以从练功先开始</p><p>大家要注意一点是，刚开始练得时候不要在意呼吸，每个人的身体状态不一样，呼吸顺其自然就好</p><p>第一行和之间，可能少了个逗号</p><p>再就是小太极和室外也要注意到</p><p>风水看似简简单单，但就这么简单的事，我至少也是学了几十遍再加上大量的验证，才理解到现在这个程度，还远不够全面</p><p>没有基础的人，看起来就是一句话</p><p>一开始可能由于业力的原因，看不到对自己有利的内容</p><p>也有可能第一次接触，思维模式还不习惯</p><p>下面的案例问的是化解</p><p>至于化解，一层是一层的力量，中国结只是中国结的力量，挪走肯定会更好</p><p>（这里说的德行，不是去捐款，而是指修脾气</p><p>另外，心肾相交，也称为水火既济</p><p>肾水受伤，不足以与心火相交，对应着也容易火气大</p><p>可以给别人提一句，至于要不要改，那是别人自己的选择</p><p>一切都是因果，阴阳平衡是天道</p><p>大家要养成正向思维的习惯</p><p>这位友友为了躲让他人，自己和孩子都受伤了，甚至身体的右边都不能动了</p><p>遇到问题，不急不躁，静静的感知，注意力回来了，身体就开始恢复</p><p>疼痛是一种提醒，当我们的注意力去感知的时候，相当于是身体知道我们注意到这个问题了</p><p>如果一次不行，可以把注意力放在外面放松一下，用前面说的洗心养神功，把注意力关注在具体的实物上</p><p>一分半分钟之后，再回到自身，感知疼痛</p><p>之所以说，是因为生气的时候，是在责怪外在，没有感知到身体的提醒，于是这个提醒就淤堵在体内了</p><p>随时能感知到自己的情绪和不适，能量就不会淤堵</p><h3 id="s-714" tabindex="-1">【篇外：】利他 <a class="header-anchor" href="#s-714" aria-label="Permalink to &quot;【篇外：】利他 {#s-714}&quot;">​</a></h3><p>我本来就是肿眼泡，所以没有当个事儿</p><p>下播前给大家总结的内容，本来是打算录播后发公众号的，这种情况就先不发了，等以后再播一次吧，录到合适的再发</p><p>而且那天的新增粉丝，不知道为啥后台没给算数，橱窗还是看不到，争取下次能凑够的</p><p>我们把所有看不见的部分，统称为阴</p><p>如果是普通的问题，我自己就感觉到了，请吉月姐姐帮忙清理一下就是了</p><p>别说道家和仙家有冲突，就算仙家和仙家之间、道家和道家、不同的风水门派之间，也都各有冲突</p><p>比如，有的师父曾说，我已经到了觉醒的时间，我也确实会慢慢感知到一些事情，所以感觉师父说的挺准的</p><p>但有的师父则认为我得在马年才能打开灵性，并对我现在的状态嗤之以鼻：你那点儿感知，算个毛的觉醒</p><p>同一层里又分为多少区、域</p><p>有的师父认为，冤亲债主，满足他们的要求大家和解了，它们不祸祸人了就算超度</p><p>也有的师父认为，他们离开人体不附在身上了，就算超度</p><p>还有的师父认为，得把它们送去修行才算超度</p><p>但也有师父对上述的说法都全盘否定，她认为重新进入轮回了才算超度，但阳寿未到等各种情况一时还没有办法轮回，所以她认为，超度个毛超度</p><p>至于看不到的部分，等看到了再说</p><p>在第853章讲过，【改命，也可以理解为改变自己的社会关系</p><p>钱大家都会给，那你跟其他人的区别是什么</p><p>不能简单粗暴地比谁的钱更多吧</p><p>钱最多的人，就是师父最关注的人吗</p><p>弟子不必不如师，师不必贤于弟子，闻道有先后，术业有专攻，如是而已</p><p>这也是第856章讲的，利他就是利己</p><p>就算我自己不会，但我可以找到会的人啊</p><p>不论是想收获健康，想收获财富，还是想收获自我能力的提升，本质上都是阴阳</p><h3 id="s-715" tabindex="-1">【篇外：】贪心是大忌 <a class="header-anchor" href="#s-715" aria-label="Permalink to &quot;【篇外：】贪心是大忌 {#s-715}&quot;">​</a></h3><p>今天先给大家聊聊贪</p><p>贪的本质，是阴阳失衡</p><p>这种情况，旁人很容易看清这是贪，但本人却不容易察觉到</p><p>阴阳之道一定要时刻警醒</p><p>当我们有苦恼的时候，就静下来想一想，是不是在哪方面阴阳失衡了</p><p>再给大家分享一位着急买房子的友友的案例</p><p>这位友友是真的很着急买房子，我提醒了好几遍她也收不到我的意思，只是反反复复的提问，就是想买个好房子</p><p>就算是请师父帮忙看风水，提供十套房子二十套房子，师父是可以在里面帮忙挑个更好一点儿的</p><p>就算是请师父看，也不会选到超出自己能量的房子的</p><p>因为阴阳之道啊，你提供的选项基本都是跟自己相匹配的，师父只能是在此基础上去做化解，不可能违背了天道</p><p>前面反反复复的提过，先修人</p><p>前面也提过，心不静的时候不要做重大决定</p><p>迷迷糊糊的时候，不适合做买房子这么大的决定</p><p>如果不差钱儿，买房子对你来说不是件大事儿，今年买了明年还可以再买，那就无所谓</p><p>先买个相对好一点儿的，过段时间状态更好了，再换更好的就是了</p><p>但如果是普通人，买房子需要花半辈子的积蓄，那最好是先把人静下来再说</p><p>关于修心，前面也写过很多，先要把自己的心稳住，清净</p><p>前面也写过很多次，业力有时候会蒙住人的眼睛，对自己有利的内容都看不到听不到，必读得自己下定决心要改，一遍不行就两遍，两遍不行就三遍，业力总不可能次次都蒙住自己的眼睛</p><p>关于读书再说个关键的点</p><p>这本书的术看不懂，可以先跳过去，但自修的部分就不要轻易划走了，先把心修好</p><p>我都点明了关键在于业力和修心，她还在问房子的问题……</p><p>信指的是信用，诚信</p><p>过于谨慎，容易疑神疑鬼，缺乏果断，容易钻牛角尖</p><p>先修人，人修好了，才会遇到跟自己福德匹配的美好事物</p><p>积德行善没那么快见到效果，也至少先把心定下来再说</p><p>如果木是喜用神，可以佩戴木质或者绿色手串</p><h3 id="s-716" tabindex="-1">【篇外：】根 <a class="header-anchor" href="#s-716" aria-label="Permalink to &quot;【篇外：】根 {#s-716}&quot;">​</a></h3><p>下面这种情况，就算是</p><p>反正以我的阅读理解能力，不足以理解具体指的是什么</p><p>按照我个人粗俗的理解，道德就是对众生有帮助</p><p>这既包括，也包括，因为我们自己也是众生之一</p><p>但这个，不是损人利己，而是指提升自己，不论从精神上还是肉体上，都成为更好的自己</p><p>阴阳合一，精神和肉体是一体两面，是互相影响的，两方面都需要提升</p><p>精神层面，心眼小，爱生气，影响气血运行，容易生病</p><p>天天感知鬼，对众生既没有精神层面的帮助，又没有肉体层面的帮助，这种就算是</p><p>感知敏锐的人，也有感知敏锐的烦恼</p><p>无根之草，可不就是风都能欺负的吗</p><p>首先自己要能站得住脚</p><p>就像没有根的草一样，自己不能主动的汲取营养，单靠外力输送营养液，不是根本的解决之道</p><p>第一，长期依靠营养液，需要多少持续的资金往里搭</p><p>不要指望慈悲和大爱的持续性救助，世界上值得救的人多了去了，而外力是有限的，就算要救，是不是也得先救有根的草</p><p>这就是自助者天助</p><p>心都不知道在哪里飘着，就不要四处去寻找外力了</p><p>先自修，把根儿扎稳</p><p>即使五行八卦的部分看不懂，只要能看懂这三个字也够用了</p><p>就算不爱招鬼的人，天天想着鬼要吃我鬼要吃我，也真的会常常遇到邪乎事</p><p>祭祀S纸的话，最好是到寺庙、道观或者指定可以烧的地方烧，注意安全</p><h3 id="s-717" tabindex="-1">【篇外：】聊聊运气 <a class="header-anchor" href="#s-717" aria-label="Permalink to &quot;【篇外：】聊聊运气 {#s-717}&quot;">​</a></h3><p>不知他能不能在书里找到答案，这里再啰嗦一遍</p><p>我们假设一个人请师父催财，包了200的红包，后期生意上只能看出多赚了2000，他会不会觉得，然后翻个白眼儿</p><p>也就是说，在玄学行业，十倍的回报率是远远满足不了人们的期待的</p><p>我不是说不能扩大，只是说不能凭空扩大</p><p>因为气在这种程度上，只看一遍的话，能看进去一半的一半的一半就算不错了</p><p>先内求，自己站稳脚跟之后，再考虑外力</p><p>就好比说，我们都知道用镰刀割草比用手薅的快，但如果是姗姗学步的小宝宝，自己还站不稳的情况下，就别想着用镰刀了，薅一把算一把就行了，别贪</p><p>等自己站稳了，有能力了，再考虑镰刀的事情</p><p>避免大家有误解，这里再澄清一下，不是说换个气特别足的头像就好了</p><p>虚不受补，没有一口吃成的胖子，好好看书，一点一点的把自己的心气调整起来</p><p>这也是为什么《孙子兵法》开篇就讲：，这五件事的第一个就是『道』</p><p>前面说过，九运要火的行业，跟玄学相关的、跟中医相关的、跟五行相关的、跟传统文化相关的课程，基本都是骗局</p><p>上面这位友友说，她找老师看个户型图9999，微信头像1300，花了一万多这还算花的少的，几万几十万的</p><p>也就是说，假的比真的看起来更像真的</p><p>这就是《道德经》讲的：五色令人目盲</p><p>因为最近发现很多讲国学的、讲中医的，以及讲太极拳之类的，都是被资本包装出来骗钱的</p><p>我相信你们每个人都刷到过她/他们，因为背后有资本的运作，占据了大部分的流量</p><p>这就是《孙子兵法》讲的</p><p>只要让老百姓相信了他们讲的话，他们就站在了必胜的位置上</p><p>这就是为什么有人会感觉，就算是为了拯救中华文化，都得买她/他的课支持一下，这样才算是有骨气的中国人</p><p>田单的士兵看到祖先被辱</p><p>田单成功的激发了大家的怒气，最终反败为胜</p><p>而现在很多的视频言论，也是想借助抨击西医、抨击某些狼性国家，以此激发大家的怒气，悄悄把大家绑上了他们的那条船</p><p>殊不知，那条船本身就是披着爱国大旗的狼</p><p>不论是用五行、还是用布局、还是用象数、还是练气功、还是修情绪，最终都是为了修好那口的气</p><p>提升自己的正气是一方面，不要被人利用了自己的怒气也是一方面</p><p>不是气足就是好，气不足就是不好</p><h3 id="s-718" tabindex="-1">【篇外：进错门了】 <a class="header-anchor" href="#s-718" aria-label="Permalink to &quot;【篇外：进错门了】 {#s-718}&quot;">​</a></h3><p>微信是全拼后面加个13，如果有粉丝牌的友友私聊我再多拿一个微信号</p><p>特别是那些貌似可以不劳而获的引导，慎之再慎</p><p>所以比较讲究的修行者，只有很少的几件衣服，避免自己的信息飘散的到处都是，防止扰乱自己的心神</p><p>关于养心补肾能量手印，我看到评论区很多友友说有感觉</p><p>上图的中指是直的</p><p>我个人感觉，食指和无名指弯曲的话，能量是更柔和的</p><p>大家做手印的时候，留意一下直和弯的区别</p><p>再给大家分享几个反馈</p><p>大家在调整的时候，不论是问题一下子解决了，还是解决了一部分，还是反而加重了，都是有原因才有结果的</p><p>积极正念地找到问题出现的原因，对应着去解决就行</p><p>于是友友又从情绪上继续找根源</p><p>这位友友的问题是，抗上包不包括同辈里面年长的人</p><p>能压制自己的人都算，对抗领导、长辈、兄长等等都算抗上</p><p>再比如下面这位友友的案例</p><p>阳宅是阳宅的问题，阴宅是阴宅的问题，业力是业力的问题，情绪是情绪的问题，饮食是饮食的问题，运动是运动的问题，福报是福报的问题</p><p>买个物件摆上，并不能保证万事大吉</p><p>风水摆件只是能化解五行和阴阳的问题，它既代替不了业力，也化解不了情绪，更不能帮忙积攒福报</p><p>当没有了贪嗔痴慢疑的时候，心里的匮乏感就消失了</p><h3 id="s-719" tabindex="-1">【篇外：从术数到修行（一）】 <a class="header-anchor" href="#s-719" aria-label="Permalink to &quot;【篇外：从术数到修行（一）】 {#s-719}&quot;">​</a></h3><p>好多友友问到了孩子的问题，先给大家分享一个正面的案例反馈</p><p>这位友友的女儿抑郁比较严重，需要吃药干预的程度，问我可不可以借助外力</p><p>我推荐她先看一下《生命的重建》，个把月后再反馈看看</p><p>今天反馈说情绪和身体都有好转</p><p>这位友友还找到了手机号和婚配方面的负面影响</p><p>在这种情况下再考虑要不要借助外力，比直接借助外力效果要好的多的多，因为内在的根基站稳了</p><p>如果满眼都是孩子不好，那么就是在孩子啊</p><p>大家看到的是，这不能倒出（饺子汤）来嘛</p><p>业力就是想体现出来，都找不到合适的机会</p><p>也就是说，既然某个人出现在你的生命中了，那就是你的因果</p><p>即使有业力问题，努力也可以解决</p><p>自己的因果要自己努力，而不是让别人去努力</p><p>这辈子先过好了，再说下辈子的事儿</p><p>我们接着说说先把这辈子过好的事情</p><p>这位友友的术学的不错，命宫和流年算的都对，走到了绝命年</p><p>至于要不要离婚，这是个人的选择，我不发表意见</p><p>借着这件事，再跟大家聊聊自修</p><p>友友最后的一句话是</p><p>前面的案例，人家的婚配还是绝命婚加上子午冲呢，但只要自己努力，仍旧是可以看到情况的好转</p><p>虽然努力离开也算是努力，但努力自修成为更好的自己是更大程度上的努力，并不是只有一条路可以走</p><p>如果不自修，不反思自己，换个老公并不能解决问题</p><p>从心理学角度来说，这是，是指人们在亲密关系中会不自觉地重复某些行为模式</p><p>而从玄学的角度来说，这是业力所致</p><p>也就是说，如果业力需要有一个人来伤害我们，就算不是张三，也会有李四、王五、赵六……</p><p>消除业力才是根本</p><p>如果一时半会儿业力还消不了，那么就做到好好锻炼，改善脾气，让业力就算是想体现出来，都找不到合适的机会</p><h3 id="s-720" tabindex="-1">【篇外：从术数到修行（二）】 <a class="header-anchor" href="#s-720" aria-label="Permalink to &quot;【篇外：从术数到修行（二）】 {#s-720}&quot;">​</a></h3><p>这位友友用来治嗓子，也算是别具匠心</p><p>那个发音就是，佛教是在唐朝发展到鼎盛时期的，所以很多经书在音译时，都采用了唐朝的发音</p><p>就算是读成或者，只要心怀正念，也是有效果的</p><p>下面再说一下灵性的问题</p><p>这位友友说，佛家说不要饮酒，但为什么他喝点儿酒之后，悟性反而会比较高</p><p>下面给大家发一个风水调整的案例</p><p>大家自己学会了就是自己的技能，自己能找原因是最好的</p><p>问火阿姨的人不少，我基本都是让大家先修自己</p><p>再给大家解释一下剑指的事情</p><p>拿回来的前提是，我们得先知道我们有</p><h3 id="s-721" tabindex="-1">【篇外：从术数到修行（三）】 <a class="header-anchor" href="#s-721" aria-label="Permalink to &quot;【篇外：从术数到修行（三）】 {#s-721}&quot;">​</a></h3><p>接着说一下术数和修行</p><p>这位友友当时是问我心衰的象数，他并没有提到火阿姨，我也不知道病人的情况有多严重</p><p>可能跟我说的借助外力是差不多的意思，不一定是用嘴吃饭，而是指通过外在的途径补充</p><p>最近我才明白，他说的，可能跟我说的借助外力是差不多的意思，不一定是用嘴吃饭，而是指通过外在的途径补充</p><p>也就是说，有外力和内力两种途径</p><p>心正的人缘分会更多，因为修就是修的正心，心正说明修得好</p><p>我自己也会隔段时间就请火阿姨帮我以及我的家人助力一下，但不能在粉丝中宣传这种办法，因为没完没了很容易被人诟病</p><p>大家感受过了有敬畏之心就好，还是自修的方法更根本一些</p><p>而且也有一些情况不适合借助外力，比如下面这种</p><p>她用人工智能查了一下自己的症状原因，然后找了对症的象数</p><p>人工智能现在确实很厉害，我用deepseek试过了一些命理的测试，准确率90%以上，找不准自己喜用神的友友可以参考一下</p><p>最近用deepseek试了一下星座的分析，也非常有参考性，输入的时候注意写清楚男女</p><p>这就是我跟丘书炎的相处模式，新书里会写到</p><p>本来想着面部调整做成视频发公众号上，后来想想还是大家自己会了自己录视频发表吧</p><p>友友们如果发现哪个平台发了我本人的直播视频，麻烦帮忙提醒一下博主撤下来换成大家自己的哈</p><h3 id="s-722" tabindex="-1">【篇外：洗发水】 <a class="header-anchor" href="#s-722" aria-label="Permalink to &quot;【篇外：洗发水】 {#s-722}&quot;">​</a></h3><p>因为中药就是一种植物，或者说一种菜</p><p>也可能有就是短期使用的，不加防腐剂的，我不太清楚</p><p>本来是打算拍个视频发公众号上的，但小欣拍的画面黑乎乎的，还是在这里写一下做法儿吧</p><p>这位友友分享的方法就很好</p><p>加生姜能促进血液循环，刺激毛囊生长</p><p>今天抖音上转发的孙思邈养生十三法中的，那位博主也测试过洗发水</p><p>她的主页里，标题为那个视频就是</p><p>大家都知道我是比较懒的，我平时洗头一般是用面粉加醋</p><p>洗的时候加一点点醋（这里用的是低度醋），搓洗一会儿冲干净就可以了</p><p>这个方法的主要优点是温和，头发不怎么会出油</p><p>下面给大家再说一下归因</p><p>这位友友说，自己收获了一些感悟，然后就被卖西瓜的人恶语相向了，这是不是阴阳平衡</p><p>这个跟前面聊过的是差不多的逻辑</p><p>之所以反复跟大家说逻辑，是因为我们的世界最根本的关系就是因果关系</p><p>如果被人恶语相向的原因归结为阴阳平衡，因为自己有所收获，所以就要付出代价，那么在这件事情上自己是无能为力的</p><p>不同的思维模式，会把我们的人生带向不同的方向</p><p>有可能某人就是因为刚刚跟媳妇干了一仗，他自己情绪不好而已</p><p>注意力就是生命力</p><p>别人的心情好不好那是别人的事，不值得我们浪费注意力去琢磨他</p><p>我们尽可能地把注意力放在有助于自己提升的方面，那么我们的成长就会焕发出勃勃的生机</p><h3 id="s-723" tabindex="-1">【篇外：风水和福报的关系】 <a class="header-anchor" href="#s-723" aria-label="Permalink to &quot;【篇外：风水和福报的关系】 {#s-723}&quot;">​</a></h3><p>这章先解释一下风水和修行的关系</p><p>不论是风水、还是占卜、还是命理，都只能帮忙避开的人生选项，并不能带领我们脱离六道轮回</p><p>玄学之所以称之为术，是因为它的作用就跟算术一样，或者说跟技术一样</p><p>会了一门技术（或者说学会了算术），利于我们更好的在目前这个层面生活</p><p>比如说，我们知道手湿的时候不能碰通电的物品，否则容易触电，那么我们在生活中避开这个行为，就会避免被伤害</p><p>我们知道怎么做不好，那么避开就是了</p><p>这就是术，或者说知识</p><p>术是底线，是指导我们不要去做那些常见的有伤害性的行为</p><p>这个要怎样，指的就是自修，从内心成为更好的自己</p><p>不必须要赚大钱，也不必须非得不能赚</p><p>生活无忧的人可以修行，陷于困苦中的人也可以</p><p>这个自然，指的是正常吃饭、正常睡觉、正常工作、正常学习</p><p>而不是天天研究怎么呼吸大周天小周天，怎么炼气化神等，那些都是术</p><p>莫名其妙找人恶心了自己一顿，算完要不要给钱</p><p>那就说明后面还有一大堆需要出钱的地方，说的哪一项不得化解</p><p>师父哐哐一顿唾沫横飞，他认为他了，你不给钱就是不尊重他的辛苦，万一小心眼他再说点儿难听的，是不是更恶心</p><h3 id="s-724" tabindex="-1">【篇外：贪念】 <a class="header-anchor" href="#s-724" aria-label="Permalink to &quot;【篇外：贪念】 {#s-724}&quot;">​</a></h3><p>这章先给大家重申一遍啥是贪念</p><p>这位友友一开始的诉求就是：孩子心脏不好，想找一位既会看实病又会处理虚病的道医</p><p>我回复，心脏的问题跟情绪和风水也都有关</p><p>有这样的业力，所以才会遇到生气的事儿</p><p>有阴性物质的干扰，所以才会迷迷糊糊地住到风水上有对应伤害的房子里</p><p>不同的层面都会有问题，调整一层是一层</p><p>她再次强调想找的医生</p><p>在前面讲山医命相卜的时候说过，任何一门学精了都很难，更何况这位友友想找虚实两方面都精通的道医</p><p>我只能建议她先好好看书吧</p><p>这位友友再次问，有没有虚实都精通的道医可以介绍</p><p>推荐我学道医的那位师父，他只是拿手通经络这一条，每天预约的客人都排得忙不开</p><p>他既不给人扎针，也不给人开药，也不给人画符，更不给人做法事</p><p>本来是想解决问题，如果遇到骗子再一折腾，岂不是雪上加霜</p><p>努力地修好自己的脾气，让业力想发生</p><p>当我们开始期待外力的时候（希望家人多爱自己一点），我们就等于放弃了人生的主动权，我们把力量（即注意力）送给了他人</p><p>再说一遍，不是别人不爱我们，而是没有主动权的人感受不到</p><p>要不要吃药是自己的决定，但父母愿意花钱，那是父母的心意</p><p>不把注意力放在自己身上，一直向外求的话，感知力会严重下降</p><p>借用他人的一句话：先管好自己再说</p><p>所以，在自己还无法好好活着的时候，优先照顾好自己</p><p>把注意力都放在自己的身上：『我』可以做什么</p><p>注意力就是生命力，把自己的注意力全部都放在自己身上</p><p>给自己注入生命力，这是第一步</p><p>有了生命力之后，下面再说意义</p><p>这位友友说，学历很重要，虽然道理懂，但自己并不认可</p><p>你想做自己喜欢的事情，你的优势是什么</p><p>那么你所谓的指的是什么</p><p>所以，学历不重要这句话，你现在还不能说</p><p>除非此时此刻自己确定有什么千载难逢的大机会，否则，不论学历重不重要，都不急于在这会儿下定论，只剩一个多月就高考了，就算为了自己有资格说一句学历不重要，都应该去全力以赴</p><p>最后说一下人生的意义</p><p>最后的最后，再上升一下价值</p><p>哪怕我们的人生目标不是为了自己，我们就是想着全心全意地为众生服务</p><p>那么，站在更高的位置上，你才有能力帮助到更多的人</p><p>怎么站上更高的位置</p><p>其他的以后再研究，先把能拿到手的拿到手再说</p><p>如果没有学历，我到新加坡最多就是刷盘子刷碗，我既遇不到那些合伙人，也遇不到丘书妍，因为他们都看重了我的学历</p><p>换的前提是自己得有底气和资本，也就是上文所说的选择权</p><p>这个选择权，换言之就是能力</p><p>这也是为什么我非常认可那句，有付出所以有收获，这就是阴阳之道</p><p>关于学历，再说一点</p><p>谁爱天天啥也不能玩，就是闷头刷题</p><p>大家都想放弃的时候，你能坚持到最后，就证明你的心性坚定</p><p>我做劳务中介那么多年，也看过我初中同学、高中同学、大学同学毕业后所获得的发展机会，我的观点是，如果没有足够的机会去获得更多其他的，那么学历就是普通人突破圈层最便捷的途径</p><p>虽然不是唯一的路，但这个捷径现在既然摆在自己面前，为啥不先试试看</p><h3 id="s-725" tabindex="-1">【篇外：别欺负孩子】 <a class="header-anchor" href="#s-725" aria-label="Permalink to &quot;【篇外：别欺负孩子】 {#s-725}&quot;">​</a></h3><p>关于修行修自己，也写过很多</p><p>我不知道这位友友所说的，代表着几个意思</p><p>我把图调了方向，上面是南</p><p>这种情况大家要注意大小太极兼顾，因为卫生间还有一部分在艮8宫，如果不小心挂到了艮8的宫里，会加重孩子的火气</p><p>不要内耗自己，也别苛责他人</p><p>大家互相理解，尊重因果，慢慢修正，别贪心就好</p><p>能不能得到自己想要的结果，跟业力和福报都有关系</p><p>我们不论来自哪里，在没有想通之前，执着在了情绪里都会影响到健康</p><p>一切都得靠自己修，修好自己的情绪</p><p>大家不要去丘大的评论区里争论这件事</p><p>刚巧那个章节的内容就是</p><p>有人说的是，我用的词是阴阳</p><p>有出有进，才是阴阳之道</p><p>那位朋友能有那样的认知，肯定是没看完我的书</p><p>鉴于那位朋友的评论是这个月头发的，避免有人误以为我是提早看到了，这个月故意做做样子，那我再截图个早几天的记录</p><p>反正我出门也不能御剑飞行，我也不会自己种棉花再织成布再做成衣服，我不否认也不排斥人活着都要赚钱这件事</p><p>说，要不要贪的问题</p><p>如果盈利是我的主要目的，那我用三千两千的月薪请几个客服，天天在群里大家，好几万人啊，粗略算算我能赚到多少钱</p><p>我是学经济的，又不是不会算账</p><p>既然有人质疑，那可能也不止一个人心里犯嘀咕</p><p>因此我把公众号里转发的课程删了，包括管理员的微信通知也删了，大家有问题好好看书就行</p><p>我之所以写出来，是希望能坚持看到这里的友友们不要因为外在的因素影响了自己的心念</p><p>既然聊到了这里，就简单地说一下原理，为什么通过图画、声音、文字等途径，感知敏锐的人会收到特别的感觉</p><p>还是先拿狗狗举例子</p><p>那么人走过之后还是能被猎犬追踪到，留下的到底是什么</p><p>这是一种理性上的推理，随着大家的反馈越来越多，能不能侧面印证某些的客观存在呢</p><p>对于人来说，心性如果被欲望和情绪蒙住了，感知就会麻木</p><p>这个话题先聊到这里</p><p>至于没赶上课程的友友，也不要因为错过而遗憾</p><h3 id="s-726" tabindex="-1">【篇外：心的力量】 <a class="header-anchor" href="#s-726" aria-label="Permalink to &quot;【篇外：心的力量】 {#s-726}&quot;">​</a></h3><p>命理适合东北，但本人不想去那边</p><p>一位友友问到了工作的方向，问题是</p><p>如果某个方向是有利于自己的，但那个地区大势不利，那么不建议去</p><p>书刚写的时候，我的级别还不能插图，所以建群给大家发插图</p><p>她从一开始就声明要盯着我不要行骗，不然她就造反</p><p>不如放在自己的修行上面，好好做事，修好情绪</p><p>持续的把注意力收回来就行</p><p>读经也有助于把注意力收回来</p><p>但如果正气不足（或者说阳气不足），就先读金刚经、或心经，或道德经、或清静经</p><p>大家内修之后，要多注意自己的状态（尤其是凉的、冷的、心不舒服、头晕、酸的，甚至感觉到被腐蚀等状况）</p><p>不论是象数、还是经书、还是看到的短视频、还是番茄上看到哪本书，只要有异常感觉，都先停下来</p><p>如果有异样，最好的办法就是感恩（提升正气）和忏悔（排出毒气）</p><p>再给大家分享一个有趣的验证</p><p>下面是腰痛的象数反馈</p><p>也有个别人说象数念了没反应，大概可以从业力、自己不够相信、念得力度不够几个方面找原因</p><p>在第874章分享过借助火生土温暖子宫的象数反馈，评论区也有人再次反馈印证</p><p>或者有没有找找风水上的原因，或者情绪上的原因</p><p>之前说过，上火的话可以借助河水把火气带走</p><p>大家在借助象数之力的同时，如果可以检查一下自己所处的信息场有没有持续的阴寒之象，效果会更好</p><p>这个世界唯一的真理就是因果</p><p>也就是说，原因不是唯一的</p><p>其他层面的原因，也都慢慢的找一找</p><p>有了这个信念，才会产生行动</p><p>注意力就是生命力</p><h3 id="s-727" tabindex="-1">【篇外：相信相信的力量】 <a class="header-anchor" href="#s-727" aria-label="Permalink to &quot;【篇外：相信相信的力量】 {#s-727}&quot;">​</a></h3><p>那个地方是我描述的有歧义，文笔不行就是有弊端</p><p>这种行为不可以用肉体表达出来，不然看起来就跟耍流氓似的，所以只能通过使劲儿鼓掌来宣泄内在的那种急切</p><p>不论在任何时候，我们都不能迷信于任何人</p><p>不论他的光环看起来有多大</p><p>这个世界，唯一不变的就是变化</p><p>而不能以为衡量标准，否则就变成了刻舟求剑</p><p>这本书一直能跟着看下来的友友，都是心存善念的</p><p>我跟上面这位友友的想法一样，希望</p><p>但自己练的功能不能补上神，这个不一定</p><p>但有的人气不足，硬饿着不吃饭，这就不能算是正常的辟谷</p><p>关于术法的修行，不论是炼气还是辟谷、还是修炼灵魂，我都建议慎重</p><p>至于要不要以身试法，大家要根据自己的情况酌情且慎重地考虑</p><p>与其冒着重大损失的风险去修炼自己不了解的术法，还不如认认真真地把家里的风水上调整一下</p><p>再脚踏实地、正心正念地为大家做点儿正事，通过积累福报的方式从根本上提升自己</p><p>为了修神通而修神通，不论是在道家还是在佛家眼中，都算是歪门邪道</p><h3 id="s-728" tabindex="-1">【篇外：钱和情要分清楚】 <a class="header-anchor" href="#s-728" aria-label="Permalink to &quot;【篇外：钱和情要分清楚】 {#s-728}&quot;">​</a></h3><p>为什么术法的修行建议拜师，而不是看书学</p><p>比如咱们下面这位友友就是这种情况</p><p>她说是我提倡大家，，，然后被人得窦儿窦儿的，不知道怎么</p><p>继续帮助这样的人，我真的会有情绪</p><p>用我的原话，去攻击我要表达的意思</p><p>这就是前面说过的</p><p>指的是心甘情愿的去帮助别人，是不求回报的</p><p>利他也不是指去帮助所有的人，不论好坏的那种</p><p>利他，是心甘情愿不求回报的，而且并不是指所有的人</p><p>如果利他之前，我们已经很清楚地想好了自己想要得到一个什么样的回报，那就不能称之为了</p><p>而不是在修之前就先设定好了，我要获得这个结果那个结果</p><p>如果说帮领导做事，目标很明确就是想得到评优的好处，那这属于是交换</p><p>不要出现那种他以为你是，但你心里想的却是跟他做交易的这种情况</p><p>帮是帮、交易是交易，这两点一定要分清楚，不然会很内耗</p><p>利他说完了，咱接着说自修</p><p>自修的意思是，想一想自己在这件事情里</p><p>所以，我说的自修，并不是指对方没有问题</p><p>最后，，但自己又不想无偿地去帮助别人做嫁衣裳</p><p>佛祖的境界他愿意割肉他就割呗，但咱的境界咱不愿意割就不割，不强求，不内耗</p><p>比如我认识的一位师父，他就是把玄学作为了职业，他也有能力帮助别人解事儿</p><p>他不跟缘主说清楚化解需要多少钱，就直接给人家化解完了</p><p>师父却生气对方太不讲究，自己不主动要钱，对方竟然就真的不给</p><p>比如我就是想要五星好评和书荒推书，我老早就开始要了对吧，哈哈</p><p>如果是自己高估了自己，那么调整自己</p><p>如果是对方低估了自己，那么换人就是了</p><p>简简单单，拒绝内耗，做个真实的人</p><p>再比如下面这种情况</p><p>不要外求这件事儿吧，前面说了应该不止十次，哈哈哈哈</p><p>买课的事情吧，能买到物有所值的还好，但事实上很难，还是自修比较简单，这个观点也不止说过两三次</p><p>所以修炼的功法，不建议大家看书学</p><p>咱自己修自己，不但能积累功德，还能自然而然地就有了神通，这样看是不是更划算</p><p>咱是学过经济的人呢，性价比我是很会算的</p><p>别说是你们，就算是我自己倒回去看，都经常会很惊讶</p><p>催债这件事情就不写了，因为涉及到了业力</p><p>如果自己家里的财局布好了，财务通道也都顺畅了，外面欠的钱还不回来的话，可能是有别的因果</p><p>只要咱自己做好了，就算这笔钱不回来，天道也会在别的地方补偿给我们的</p><h3 id="s-729" tabindex="-1">【篇外：修好自己这尊佛】 <a class="header-anchor" href="#s-729" aria-label="Permalink to &quot;【篇外：修好自己这尊佛】 {#s-729}&quot;">​</a></h3><p>这个世界无非就是阴阳</p><p>从阴阳上论的话，孤阴不生，独阳不长</p><p>一个人之所以能称之为大师，只能说他在某一方面比较厉害，并不代表各方面都好</p><p>就算是个骗子，他之所以能骗到人，那也是因为人家的表达技巧高</p><p>也就是说，只要咱自己心正，就算跟着骗子也能学到东西</p><p>就算我们听魔讲，也会有所收获</p><p>只要自己不贪，只要自己记得向内求才是根本，就不会被带沟里去</p><p>反过来说，就算作者传播的是正法，但人不可能有完美的，所以每个人也都会有他的局限性</p><p>这就是为什么不能搞盲目崇拜</p><p>说来说去，无非还是在说阴阳之道</p><p>阴阳是易经的灵魂</p><p>不能承认自己无知的人，只能说明他的见识太少</p><p>大家也不要对我有任何过高的期待</p><p>修行，就是修在每一个向善的起心动念中</p><p>我书里的话跟他师父，这也再次印证了我上面说的话：我确实只是会提醒大家本来就会的东西</p><p>懂了逻辑道理，原话就不会去记它</p><p>这就是本书最正确的学习方式</p><p>本来就是大家都会的内容，所以大家看的时候不必费劲地往脑子里记，而是要吸收到心里去（心藏神）</p><p>就是因为自己很善良，所以过得不顺</p><p>……这个归因逻辑……</p><p>修行修自己，别人有着怎样的因果咱不去研究，咱就说说怎么才能过好自己</p><p>不就是因为的人没有站出来吗</p><p>他想给团队做减法，，这就是善念善行啊</p><p>比如再上面那位反馈能感知到的友友，也是心正在前，所以才能感知到</p><p>如果心不正，大家不在一个频道上，我就算再使劲，你们也收不到信号啊</p><p>站在更高的位置上，能力会更大</p><p>所以大家更要努力，为了正义而努力地站在更高的位置上</p><p>不要把升官发财的机会都留给骗子，谦让不是在这里用的</p><p>不是你啥坏事都没干，就没有业力了</p><p>在其位不谋其政，犯了要不要量刑</p><p>自己看不惯的地方，就是自己要努力的地方</p><p>只有每个持正念的人都比骗子更努力，这个世界才有可能会变得更好</p><p>不向外抱怨，只向内修行</p><h3 id="s-730" tabindex="-1">【篇外：八星与健康】 <a class="header-anchor" href="#s-730" aria-label="Permalink to &quot;【篇外：八星与健康】 {#s-730}&quot;">​</a></h3><p>关于头像前面说的挺多的了，这里就不再赘述了，这章着重说一下八星</p><p>19指的是延年磁场，我们就先从延年开始说</p><p>强势的话对应着健康方面，在心脏、头部、精神、睡眠等方面就容易承受压力，肩颈和脊背也是承压部位</p><p>被压垮了脊梁的反面状态就是气宇轩昂</p><p>9本身就是压力大，连着三个9，还是19延年的9，那么产生的压力是可想而知的</p><p>延年五行属金，金克木，木主肝</p><p>用延年磁场的人，要多注意自己的脾气</p><p>天乙也写作天一或天医，五行属土，土主承载，代表着财富、善良、包容、信仰、爱（也能代表正桃花）</p><p>生气五行属木，代表着生机和乐观</p><p>快乐的人贵人缘会比较好，所以生气磁场也能代表贵人和机缘</p><p>如果生气的磁场过重，太懒散不利于事业，时间久了容易产生怨气（或生暗气），伤肠胃</p><p>伏位五行也是属木，代表着延续，是持续性消耗的磁场，容易焦虑，缺乏安全感</p><p>持续的精神内耗，对心脏和脑部不是很友好</p><p>六煞五行属水，特点是灵活、温和、心思细腻敏感、情绪不安（忧郁、自闭等）、也容易内心空虚、异性缘好</p><p>在健康方面，要多注意精神方面的问题</p><p>也容易湿寒重（出现手脚冰凉、宫寒、拉肚子等情况）</p><p>祸害五行属土，易钻牛角尖、爱面子、口才好（用在负面就是犟嘴、狡辩，这一特点在《修仙封神榜》中明一妈妈身上体现的就比较明显），容易冲动逞强、脾气差、耳根子软、分析能力弱（容易被骗）</p><p>祸害磁场主要影响口腔、眼睛、耳朵、气管、喉咙、胸腔等，也容易在身体上形成（长凸起形状的东西）</p><p>五鬼的五行属火，特点是有才华、思绪不稳定、鬼点子多、不甘于平淡，易憎恨他人，火气大</p><p>绝命五行属金，特点是情绪管理差、不圆润、主观成见深、性格冲动、极端、敢想敢做、冒险、反应快、重朋友</p><p>这种极端的性格会透支身体，肾为先天之本，容易出现与肾相关的身体状况，比如糖尿病、泌尿生殖系统问题等</p><p>比如懒散的人，可以加一点延年磁场</p><p>比如抑郁的人，多清理一下六煞磁场</p><h3 id="s-731" tabindex="-1">【篇外：把万物都看做“人”】 <a class="header-anchor" href="#s-731" aria-label="Permalink to &quot;【篇外：把万物都看做“人”】 {#s-731}&quot;">​</a></h3><p>这章我们聊聊修心的事儿</p><p>有的友友问：为什么测算的结果不准</p><p>不论是我们测算、还是拜求，都相当于是请求帮助我们</p><p>不论是帮我们指明道路、还是帮我们达成愿望，都算是一种</p><p>麻烦让我这次事业编的考试通过</p><p>然后就回家等结果去了</p><p>最终没有等到期待的结果，再埋怨省长不好使</p><p>对省长你尚且不会有如此傲慢的态度，你凭什么认为你可以用这样的态度对待神仙</p><p>把天道看成是修行比较好的就容易理解了</p><p>要是我不能通过，那就证明你是个没本事的</p><p>有人抱怨自己的运气不好，不论鬼神都不愿意帮助自己</p><p>这种情况建议反观一下自己，是不是傲慢地把贵人在当佣人使</p><p>人家确实可能不会在意，但这个世界是有因果的啊</p><p>如果你尚在低位的时候就态度傲慢，哪怕对方不介意，那人家也可以选择无视呀，他为什么要帮你</p><p>如果硬求的缘分不能让你过得更好，那你天天又拜又求的图啥呢</p><h3 id="s-732" tabindex="-1">【篇外：利他是有前提的】 <a class="header-anchor" href="#s-732" aria-label="Permalink to &quot;【篇外：利他是有前提的】 {#s-732}&quot;">​</a></h3><p>第一个是，烧香、磕头、念经、持咒有没有用</p><p>这句话表达的并不是说吃饭没有用，不让你再吃饭的意思</p><p>而是说，烧香、磕头、念经、持咒这些事情（包括风水也是），就跟吃饭一样，是很基本的事情</p><p>如果光做这些，并不能保证你就万事如意了</p><p>这些事情就跟吃饭一样有用，但是不能花费太多的时间在上面</p><p>第二个要澄清的点是，天天去求省长，就算省长给你了一个岗位也很难胜任</p><p>这句话跟上一段的意思是一样的，不是说见贵人没有用，只是说不要花费太多的精力在这种事情上</p><p>这不是我要表达的意思</p><p>包括利他也是一样</p><p>治国、平天下之前，得先修身、齐家</p><p>书里前面说过，修心，修的是笃定的、慈悲的心</p><p>还振振有词自己这是，这是正心正念</p><p>贪图功德、好高骛远也是贪</p><p>贪并不只是体现在钱上</p><p>一门心思的，就算不收钱，但你想做的跟自己的能力不匹配，也算是一种贪，这个要特别特别注意</p><p>贪念一起，就容易入魔</p><p>但因为自己是奉献的，被假象的迷住了，很难接受自己是起了贪念</p><p>先把自己和家人照顾好，给自己和家人足够多的爱之后，再去关爱更多的人</p><p>把拯救苍生的远大理想先收回来，脚踏实地先把自己的日子过好再说</p><p>再澄清一句：把的意思，不是说不要去，而是说别好高骛远，脚踏实地的先从修身和齐家做起</p><h3 id="s-733" tabindex="-1">【篇外：出偏】 <a class="header-anchor" href="#s-733" aria-label="Permalink to &quot;【篇外：出偏】 {#s-733}&quot;">​</a></h3><p>很多人修行修偏了，但是自己却不愿意面对</p><p>起了贪念，就算偏</p><p>这个贪不只是用钱来衡量的，而是用是否能匹配来判断的</p><p>比如上一章说的自己小学一年级的题还不熟练，就想去大学当教授，这种不匹配就叫贪</p><p>我们为什么要不断地修行</p><p>就是因为我们还不够正，所以才要不断地修正</p><p>如果已经很正了，就不需要再修了</p><p>所以，不正才是我们每个人的常态，没必要因为自己不正而起负面情绪或者抵触情绪，意识到了改了就好了</p><p>尤其是跟仙相关的事情，人修好了，神通是自然的事情，不要主动去求，否则很容易出偏</p><p>这位友友说视频上很多的功法，很想练</p><p>玄学界有的人有多恐怖等下两章再说，我们先说一下什么叫广告</p><p>还有各种降血糖、降血压的保健品广告，轻轻松松就能根治三高的那种小视频，咱们能用出视频里的效果吗</p><p>洗发水等产品，就算是假的，也骗不了多少钱</p><p>除非能戒贪，才能醒悟</p><p>戒贪是唯一的出路</p><p>只要有贪念，就会有魔的诱惑</p><p>只要你贪，你就会感召各种的路数等着你</p><p>每个月1800，一年就是两万多</p><p>而且，再重申一次，在玄学里面，被骗钱只是最轻最轻的后果</p><p>麻烦看到这里的友友帮忙去本书的第一个段评处留言：提醒大家看完书后再调整，别还没看懂就乱改，心要先笃定</p><p>然后又买了四个，摆上后感觉更不好</p><p>然后凌晨两点多给我留的言</p><p>一次一次又一次的借助外力之后，明明已经看到效果不好了，仍旧没有认真的想一想，是不是要先把四处飘散的注意力收回来</p><p>关于修行，儒家、道家和佛家其实讲的核心内容都是差不多的</p><p>比如儒家的中庸、道家的无为和佛家的放下，最根本的意思都是说不要执着</p><p>只要有执着，就会有贪念</p><p>有贪念，就容易入魔</p><p>所以各种修行法门，都强调放下执着，戒除贪念</p><p>好多人还在问怎么修行</p><p>再比如，儒家作揖、道家抱拳、佛家合十，甚至于跪拜等姿势，表达的都是谦虚和恭敬</p><p>（下一章是一位友友发来的他的个人经历，总共写了一万多字，我完整地复制出来给大家看看，等下下一章我们再细聊</p><h3 id="s-734" tabindex="-1">【篇外：粉丝的经历分享】 <a class="header-anchor" href="#s-734" aria-label="Permalink to &quot;【篇外：粉丝的经历分享】 {#s-734}&quot;">​</a></h3><p>感谢缘分让我看到了这本书，很惭愧，我是一个既懒又怕麻烦的人，从不看未完结的书，所以我未曾给《改命》做出过任何贡献</p><p>机缘下，我表哥把这本书推给了我，当我看到吉月姐姐这章节时，我还堪堪能忍住，但是跳过去看明一时，想想我的守护者们，鼻子一酸再也忍不住了</p><p>骗子可恶，要的可不止这点东西，其起心动念要扣你护法的，跟我们的经历比，这些都算仁慈了</p><p>我目前看到的657章以前，都没有实际案例讲过灵体（姑且这么称呼吧）被害的详细细节，我可以很负责任的说，比想象中严重痛苦的多，一定时时刻刻告诉自己千万不要轻信他人</p><p>先看到《改命》的各位朋友真的很幸运，这其中讲述的防骗以及防骗原理真的可以抵御大部分被骗</p><p>我自负聪敏，心眼子八百个，依旧教训惨痛，我甚至都无法说清楚他到底是骗了我还是在点拨我们的路上突起邪念</p><p>前面三合老师写到，财布施得财富，法布施得智慧，我心性依旧差得远，也免不了希望能多做一些功德有益于自己</p><p>脱离骗子这段时间以来，我常常向有缘人讲述我们的经历，希望帮助大家突破障碍，但是这种方式太慢了，很多相同经历的人遇到我们的时候已经晚了，并且目前也不允许我出来做事</p><p>我就想，上面能不能允许我通过三合老师这个平台，用我们的故事来启发更多的人</p><p>A年，我刚刚毕业，立志考试参加工作，没有毕业时，有种声音一直告诉我，你必须干某行，你也适合干某行</p><p>恰逢此时，身体状况出现问题，青年人得老年病，每天郁郁不得志，压力一日比一日大</p><p>我本在旁暗中观察，在一番对答结束后，激动的不能自已，马上问道：我呢我呢</p><p>这次出来玩反正也没事，如果你愿意相信，那我们可以去你家看看，但是先说好，这些要收费，涉及因果就不多解释了，修改名字是2188等等</p><p>愿意的话再说做不做，你要是愿意再说，我们可以先去你家看看无所谓费用</p><p>在绝望中的我如听天籁之声，恨不得弹跳起飞，马上就约好时间</p><p>一番法事过后拿着我八字摇头叹气道：今生看了这么多八字，没见一个有你好的，可惜没有早点遇到我们，可惜了，不过还没有出大岔子，也算万幸</p><p>于是安排晚宴，席前再三叮嘱我们要清淡，他们平时不在外吃，吃的也少，有固定餐食，一副世外高人做派</p><p>随后几月，有小事麻烦也是耐心解答，并不断教育我，要有耐心，有慈悲心，良好的心性才能走得更远，我心中感恩更甚</p><p>此法事被其称为独创，意在链接先祖等等与自己有关之人，我到之后，F女士一直在吹嘘此法事如何厉害</p><p>一人一人到桌前跪拜，E先生在旁说，来了，意为链接到了自己祖先，然后上他的身</p><p>此时E先生说法声音音调完全变了，对于跪倒在地之人一番评价</p><p>有的人请来的是天上当差的，有的是请到地下的，过得好的先人会送跪拜之人附身符、仙丹等等，过得不好的会请求帮忙，我在一旁看的啧啧称奇</p><p>E先生惊了一下，说道：来了</p><p>然后默不作声，用他自己的声音说道：你家先人路过此地，很忙，让我代话问你有何事</p><p>我完全懵了，支支吾吾说了一句：求先人保佑</p><p>E先生道：接好了，药一瓶</p><p>然后E先生说：附身符一道</p><p>接着E先生说道：他走了</p><p>然后窗外雨停了，风停了，大太阳出来了</p><p>F女士马上就说道，他们从来没有遇到这种情况，这就是祖先显灵了，这就是E先生法事的实力，也是我有福报的体现</p><p>经历此事，我更加对E先生佩服不已，日后大小事问其原因</p><p>E先生都会告诉我只管做，别管结果，发心正，上天会给应得的结果</p><p>于是，E先生形象更加高大，导致未来他一直拿但行好事莫问前程来忽悠我，我都没发现</p><p>在微信聊天中，E先生时不时会感叹一下，我家风水不好，但是做风水代价大，要看自己决心，收费是五位数</p><p>刚开始我没在意，后来家中各种事情突然加速，不好的事情一件接着一件，平静的生活突然就起了波澜，我突然想起这句话，但是碍于价格，也没有想好做不做</p><p>本来的价格以前E先生告诉过我，但是F女士突然说，还要加个宝石，价格要翻倍，旁边的E先生翻了个白眼</p><p>我当即就把E先生两口子事迹告诉了他</p><p>他让我一定要帮他给E先生说说他的事，帮帮他</p><p>我回答一定，但是E先生那种上达天庭的人不一定能有空帮他</p><p>见面后E先生可以说是长叹息以掩涕兮，把q哥一顿点评和可怜，然后说到，你这必须要把风水调了，以后你就多跟着我，我带你多走动，改变你的命运，解决你的负债，解决你的问题</p><p>从此以后你要正心正念做事，踏踏实实做人，戒骄戒躁，好好修行，不能白费你的天赋，只要你相信我们，保证你从此越来越好</p><p>q哥毕竟进入社会多年，虽然激动，此时在私下依旧告诉我要多观察（正是q哥和其他师兄们不迷信，信自己的精神最后解救了我们）</p><p>于是后来与E先生更加熟络，经常交流</p><p>E先生告诉我们各种人生道理，让我们不要有分别心，要多学习，多认识其他人，不管什么门派，都要尊重别人，学习别人长处</p><p>并且E先生常常显示他的慈悲心，什么吃不起饭的有缘人，不收钱给别人处理，网络上给别人处理，别人反馈也很好</p><p>我们很疑惑为什么E先生会选择F女士，E先生却说，是自己累生累世欠F女士的，他这辈子有个任务是渡F女士（我看现在确实是快超度了），他使命是让更多人觉醒，就不应该有分别心，所以这里面也包括F女士，E先生在我心里再次高大</p><p>q哥和E先生两口子一起久了，也放下了戒备心</p><p>E先生时不时教一些原理，比如九星、八字、数字等（说实话跟三合老师比差远了），神通也教我们（其实教的都是旁门左道，还说的是赐予我们的能力，本自具足的东西赐什么赐），当时我们视若珍宝，经常讨论E先生道行到底有多高</p><p>神通这种本自具足无法说就不说了，单说他教我们的九星、八字、数字，只讲结果不讲原理，原因是他说他结果早就知道了，过程他不知道怎么得出来的（这不扯淡吗）</p><p>因为如果有人给你在酒杯里面下毒，你把酒杯和酒扔了就是，但是有人在粮仓里面洒了一把毒米，你根本无法排除哪些是好哪些是坏，轻则病重则死，要不你就扛着饿死风险前功尽弃重新来过</p><p>E先生召唤上面神仙上身训话、各种知名神话人物上身等</p><p>E先生说他来自哪里，是某位超级大能之后，甚至告诉我们上面小朋友怎么来的，怎么生活的，事实证明假假真真是真能骗人</p><p>当时E先生常常挂在嘴边的就是，都是你心性的问题，你越缺什么上天就考验你什么（真道理但是架不住他用来pUA人），你稳定了就好了，你看某某，本来不好的，给他说了他就改了就好了，你还差点</p><p>并且，E先生的能力也是时而好时而坏，问他上一世我们干嘛的，他有时能回答有时说这种事情别纠结，要靠自己修，诸如此类</p><p>E先生对于有的常识自己也不知道，更别说带着F女士这个小人，连道家山医命相卜都能把山解释成看风水的人，更别提有多没水平了</p><p>过了年中，每个人家中的事情都在加剧往不好的地方发展，比如，绝症、横祸、家庭破裂等等，并且E先生完全不知情，一问就是我都知道，但是这是你必须过的关（pUA大师）</p><p>我们渐渐发现E先生两口子组织的各种活动出差错，F女士甚至去跟酒店老板哭闹，说此次活动亏了，她不能给酒店之前的价格了，不承认自己谈的价格，我真xxxxxxxx（快板骂人）</p><p>不止如此，她经常因为E先生没有给她钱而发脾气，哪怕在某大家的豪宅中，我们在谈事，她在一边外放某音平台发泄不满，我真xxxxxxxx（快板骂人）</p><p>这么一合计，E先生也同意了，并且给我们也分了工，然后没有让F女士参与</p><p>新的场地渐渐开始建设，E先生说我们几个经济不行，干脆场地里面也教我们做各种事吧，大家把比例说好，不要忌讳谈钱，大家都要缓解经济问题，只有自己过好了才能更好修行</p><p>我们感动得就差叫爹了，从心里面发誓，一定要听师父的话，好好修行，降妖除魔</p><p>就在场地快修好时，从不开车的E先生有一天一反常态的开车出门了，我们都隐隐觉得不对劲，结果，他去把F女士接到新场地来了</p><p>我整个人身体机能开始急速下降，像是被人开肠破肚，胃痛到无法吃饭，每天只能吃下一个小饭团，并且不想吃肉，不想进食</p><p>莫名其妙开始肺炎，然后医院也仅仅只能查出一个肺炎，我卧床半个月，从此一年间上二楼都要扶楼梯</p><p>呼吸困难，只能呼吸到肺一半的位置</p><p>头晕头痛，每天晚上做梦，记不得任何内容，只知道难受</p><p>我一度以为我快死了，依旧去问E先生，E先生居然告诉我，一切都是正常的，这是我的劫，可能是我平时居住地偏远，吸收太多阴气了，更离谱的是我居然信了</p><p>我更加勤勉的服侍E先生，恨不得把这位高人捧上南天门</p><p>离谱的是E先生居然一言不发，任由她闹</p><p>一气之下她合计我们要不要退出不管了，反正仁至义尽，也给师父找到新地方了</p><p>你们现在心性不稳，不能出来，时机也未到，回去自己好好找个事情做吧</p><p>我们一商量马上同意，去跟E先生说我们管不下来，E先生居然真真不痛不痒的说好，还说我们能力不行等等（几个高管还比不上一个满地打滚的吗），然后他终于说出了那句话</p><p>事已至此，我们也陆续离开，气头上也没多想什么叫做，不过我们依旧只是以为分歧源于F女士，以及E先生不会在人间处事</p><p>q哥出奇的愤怒也出奇的清醒，他说：经历了这么多事，你们没发现哪里有些不对吗</p><p>他是说过F女士就是他的劫，但是这也太离谱了吧</p><p>对于这些人，每个人感应都不一样，但是至少我们自己能有点感应了，有时候遇到坏的，就是不想去（也有类似吉月姐姐章节中的下高速一样，去不了）</p><p>（我也是服了，要有时间，当时这我也真敢去）我说我走不开，她说，那先视频</p><p>我同意了，于是q师兄，h师姐，我，和对方开了视频，结果对方一阵弯弯绕绕，又是送h师妹保护的，又是说我们应该带一个无事牌，加上这位神人的助理酷似F女士，开口就是暗示钱钱钱（不是说提钱不好，我的观点和三合老师一致，有的规矩必须遵守，对大家都好，但是过分了就不叫规矩了），瞬间就让我犯恶心了</p><p>期间E先生还经常跟我们联系，让我们要相信自己能变好，要防止被骗，现在太乱了，战争不止，外面的坏人太多了，我对于他的话虽然认同，但是有种感觉让我别告诉他任何事</p><p>我心一沉，一个感觉上来，我说：不会是E先生干的吧</p><p>此行遇见0女士，本来以为也是什么江湖骗子，结果她开口便问，你几人有师父找我来干嘛</p><p>q师兄率先反应过来，说道：我们应该是出什么事情了，想来求证一下，看来是真的了</p><p>话音未落，一眼线瞬间陨落，接着漫天兵马执命而出</p><p>q师兄眼中的另外一个自己，我姑且称为小q吧，小q浑身都是鞭痕，被吊在一个房梁上，胸口插刀，肋骨外翻，双眼灌满黑水，腹中充满黑气，奄奄一息</p><p>更让q师兄震惊的是，此刻，E先生竟然刚好从旁边走了过来，双眼一对视，E先生转头就跑，双手一挥，漫天黑气冲天而起向q师兄而来</p><p>随着小q被解救，0女士也越来越愤怒，原来关押于此处的灵（不知如何解释），是何其的多（哎，也不知我造的孽有多少），怒气也化为行动，一纸诉状冲天起，不知升入云中高何处</p><p>0女士都给气笑了，给每个人都讲了很多事，包括世界背景、基本常识等，并告诫我们不要请先生东看西看的，别人是怎么借我们的运的，怎么用八字来害我们的</p><p>受伤方面以我为例，受伤程度堪称博物馆级别，保护被扣虽然有点直接原因感觉，但跟麻烦程度来说都算小事</p><p>小我被关押以后，腹部一长刀伤痕，对应胃痛</p><p>五官被封住，对应感觉降低</p><p>脱离我太久，对应浑浑噩噩，不清晰不清醒</p><p>眼灌黑水，对应视线模糊，看不清东西</p><p>五脏六腑错位，对应胃胀吃不下饭，浑身不舒服</p><p>骨根被毁，对应运势不佳，做不出正确判断，没有灵感</p><p>（后面对应不准确，最终结果大差不差）</p><p>运势方面以h师妹为例（对应不准确，同上），本来是行业顶尖公司和人才，财库空，对应公司工资都发不上了</p><p>财神失色，对应没有进账</p><p>法器尽失，对应技能全失，没有灵感</p><p>没错，去E先生那里去了</p><p>F女士作为他的好炉鼎当然也是要物尽其用，先享受再说</p><p>于是在清醒后我们才发现，很多所谓的缘主，在E先生嘴里，仿佛是自己认识多年的朋友与客户，而我们则被E先生宣传成了招牌菜</p><p>别人以为我们认识多年，家族是因为E先生才有今天</p><p>实际是E先生才刚入行不久，借助我们的运一步步发展，不断借助他人力量向上爬（这一过程三合老师书中也写到了类似的），直到他发现了一些我们的秘密，直到他控制不住，最后走向极端</p><p>回想当初，真是感慨，究其原因，在外求，在对个人不负责，在贪，归于欲</p><p>我贪求名利，贪求一劳永逸的享受，贪求不管不顾的轻松，贪求对未知世界的无止境索取，贪求别人眼中的惊叹羡慕......</p><p>q师兄贪求术，贪求征服的快感，贪求高人一等的傲然......欲壑难填，最终我们都被欲望遮蔽了双眼</p><p>E先生对我们的判断越来越离谱，E先生和F女士多次表现出的金钱欲望，E先生人前人后的表里不一，E先生知识上的漏洞，E先生和F女士的畸形关系......</p><p>因为那时候迷信E先生的一切，否定了自己的一切</p><p>我们很幸运，遇见了以0女士为代表的各位前辈，敢于斗，敢于为公理不怕无休止的斗</p><p>0女士最让我敬佩的一点是，对于我们这样的疑难杂症，抛开基础的要求，她很看重我们自己能不能看见过程</p><p>如果不能看见，她大部分都是会拒绝的</p><p>我们深知彼此的破坏力，我很清楚，假设有一天，我偏了，0女士一定第一个灭了我</p><p>同时我也很清楚，0女士要是偏了，我们一定第一个去送死</p><p>谁也不能保证谁永远不会成为E先生</p><p>或许我讲的太过虚幻，但是一切都是有规律可循</p><p>不管骗子怎么骗，有个基本事实不会改变，那就是你现实中过得好不好，有没有过得更好</p><p>生活就是一场修行，修行就是为了更好的生活（这就是E先生狗嘴里吐出的象牙）</p><p>的欲望，不断给我们偷换概念，让我们</p><p>我们师兄弟几人被忽悠这么久，就是E先生抓住了我们急于的欲望，不断给我们偷换概念，让我们自己过得更好了</p><p>这些与现实生活根本无关，当时q师兄依旧欠债大几十万，家庭破裂，重病缠身，还在不断全职学神通，全职服侍E先生，月入几十万的E先生还的每个月给q师兄发1000元工资......</p><p>我们还算幸运的，后面认识一位朋友，加入了魔的传销组织（姑且这么称呼吧），打着慈善旗号四处做超度法事，面对这种形成闭环的组织严密的团体，一般钦天监能发挥的毁灭性作用都不大，更别提我们了，他遭受的苦难我们也爱莫能助......</p><p>我浊气重，便不再执着一劳永逸的变好和依赖，先从改变自己习性开始，结果发现自然而然会的东西更多了</p><p>q师兄天赋异禀，人生路也到了该奋发图强的时间，出来独当一面，慢慢帮助别人，欠债也在迅速减少......</p><p>有时候开玩笑说是不是还得感谢E先生，没有他，我们都不会进入这个圈子，都不会有这些奇遇</p><p>我们与E先生缘分已尽，E先生还在做他的积德行善</p><p>我第一次在书中感受到了直白的善意，也在评论区感受到了思想的碰撞和温柔以待，启发了我度过一些瓶颈</p><p>最后，归去来兮，田园将芜胡不归，愿所有人早日回家</p><h3 id="s-735" tabindex="-1">【篇外：不迷信任何人】 <a class="header-anchor" href="#s-735" aria-label="Permalink to &quot;【篇外：不迷信任何人】 {#s-735}&quot;">​</a></h3><p>相似程度甚至让我感觉就是同一个人（或者说同一个灵的分身）</p><p>男的讲慈悲和大爱，女的贪财找各种借口收钱（也卖过宝石）</p><p>很多人不能理解，为什么当时有那么多搞玄学的老师父能被一个天干地支都写不对的给骗了</p><p>对于搞五行八卦的人来说，大家用的是推理，我们那时并不明白仙界或灵界是怎么回事儿</p><p>企图用推理去对抗法术</p><p>不论刘老师能不能写对天干地支，人家能在短短一年的时间里忽悠到几万人给他掏钱，这份能力都是毋庸置疑的</p><p>在我接触了更多的使命者后才搞明白，哪怕他们走上了邪路（入魔了），但对于没有觉醒的人来说那也算是降维打击</p><p>只要人有贪念，不论贪图了神通还是贪图了升官发财，被人家降维拿捏简直不要太容易</p><p>就算是我们能很清楚的收到感应，也一定要秉持正念，注意辨别正邪</p><p>（这也是一种考验，不能通过考验的人会被刷下去</p><p>心先定下来，再说的问题</p><p>仙家们也不好主动现身……再给孩子吓得把自己当成精神病了，那可就不好了</p><p>仙家就是无形的，所以每个的脾气都不一样</p><p>可能就是有些急性子的会主动现身，也不好说</p><p>就算是有感应，我们也不容易去判断是正是邪</p><p>我们只需要修好自己的心，自己是正的就行，不要起贪念</p><p>有啥想法大家商量着来呗</p><p>随着进入觉醒的大时代，有感知的人会越来越多，大家不要太当回事儿</p><p>先把人做好，其他机缘到了自然会有清晰的指引，不必瞎琢磨</p><p>注意随时问问自己：我贪了吗</p><p>（包括钱、包括术、包括法等等，各种可能贪的东西或者执着的点都时常反思一下</p><p>胡思乱想本身就代表了贪，大家再品一下</p><p>再比如下面这位友友的情况</p><p>这位友友说他家立了3次堂口，最后</p><p>立3次在这个里都算少的</p><p>别贪图捷径，就不会入魔</p><p>它们可能修行了很多年，比我们的记忆更久一些</p><p>80岁的老爷爷比我们见过的事情多一些，他们的意见有可能会考虑的更全面一些，但也不一定他们就是全对的</p><p>150岁的老爷爷也不能保证自己说的都是对的吧</p><p>这就是前一章的友友说的</p><p>不要迷信任何人，尤其是有法力的</p><p>迷信仙都算是迷，何况是人呢</p><p>谁也不能保证谁永远不会成为E先生</p><p>因为就算他们对我好，也不能保证他们就不会骗你们</p><p>或者说，就算他们现在一心向善，也不代表他们以后不会起贪念</p><p>重点内容给大家再唠叨一遍</p><p>不管骗子怎么骗，有个基本事实不会改变，那就是你现实中过得好不好，有没有过得更好</p><p>（刘老师嘴里吐出来的也都是象牙，他也是还在继续传播他的，跟E先生一样</p><p>最后把那位友友的经历再截图一遍，给大家一个深刻地警醒</p><p>这也是为什么建议刚有感应的人，在正邪不辨的时候不要随便给人做超度</p><p>如果给你感应的是魔，那么你做的那些超度，就是在帮魔抓婴灵做它们的养料（或者被炼化）</p><p>人家缘主本来是要忏悔，想把堕胎婴灵送到好地方才去超度，结果你给人抓了送给魔鬼了，你这算是干了个啥事儿</p><p>所有有使命的人、有感应的人、能跟仙家联系上的人，一定一定先把人修好，反复内省自己有没有贪</p><p>先别管什么光啊影的，把心修正了再说其他事儿</p><p>如果在帮着魔不断地婴灵，这种业力怎么帮</p><p>一旦出偏，产生的业力也会非常大</p><p>不要相信别说了什么，也不要相信，只以事实为依据，看看自己有没有过得更好</p><p>这个更好，是指内心的祥和与喜乐，而不是指变得多么有钱</p><p>也不能把债务越背越多</p><p>（不执着于有钱，也不排斥金钱的意思</p><p>还是打着的旗号，做着满足自己贪念的事儿</p><p>戒贪，尤其注意不要贪图神通和功德</p><h3 id="s-736" tabindex="-1">【篇外：互动】 <a class="header-anchor" href="#s-736" aria-label="Permalink to &quot;【篇外：互动】 {#s-736}&quot;">​</a></h3><p>前面的章节里请友友们帮忙在本书的开头给新粉提个醒，看完书后再调整，别东一头西一头的扰乱自己的心</p><p>二刷的人倒回来给大家提个醒，书看一半时别着急上网去买摆件，等整本书看完之后再做决定效果会更好</p><p>比如，一个考30分的人向你请教：他努力学习能不能考上清华</p><p>不一定人人都要考清华呀，也许你往xx方向努力会更容易发挥你的天分呢</p><p>新书里面会写到，跟修行高的人可以直话直说，但你跟普通人说这么重的词，他不一定受得住</p><p>因为我们找到了自己需要修行的那个点</p><p>我们平时是很难看到自己的缺点的，如果不起情绪，我们很多时候修都不知道从哪里去修</p><p>一旦生气就好办了，我们就找到那个点了</p><p>假设有人说某人长得丑，如果对方生气了，那就说明他是真的丑</p><p>再假设说有人嘲笑某个人穷，如果那个人感觉自己的心灵受到伤害了，那他可能是真的穷</p><p>严格来说，他是从内心里认为自己穷（或者丑），不一定是客观上的穷，而是一种心理上的认知</p><p>放在自己身上的话，如果别人的某句话让我们生气了，那我们就要欣喜地意识到：哦，原来我在意自己的形象</p><p>大家勇敢大胆地表达，才有机会挖掘到更多自己需要修行的地方</p><p>我们不起情绪，不是因为对方很完美</p><h3 id="s-737" tabindex="-1">【篇外：万事问问心】 <a class="header-anchor" href="#s-737" aria-label="Permalink to &quot;【篇外：万事问问心】 {#s-737}&quot;">​</a></h3><p>友友考虑到自己的经济状况，还算什么修行</p><p>本来分析的挺客观的，但紧接着又开始质疑自己是不是放弃了的路</p><p>大家有时候就是把看的太大了</p><p>我不是说拜师不应该收钱，我的意思是，主动开口要帮助别人的人，会收钱吗</p><p>反过来，老奶奶生活不方便，她不得不请人帮自己做家务，她要不要付钱呢</p><p>你去追求女神，反过来还要求女神给你洗衣服做饭，给你钱花、给你提供情绪价值，这是个正常人能干出来的事儿</p><p>不要把玄学看的太玄，就当个正常人看，是不是就好理解了</p><p>都已经怀疑了，就别去探了</p><p>注意力就是生命力，如果四处好奇，那么生命力都在外面，很难提升到自己</p><p>那些上赶着要你出钱的人，不论他是以带你赚钱为借口，还是说能带你上天带你成神，都建议大家慎重再慎重</p><p>术，就是技术，或者说算术</p><p>学个算术而已，能偏到哪里去</p><p>对与不对，自己多验证就是了</p><p>最可能出偏的情况，大概就是遇到了满嘴胡说八道要帮你的人，哈哈哈哈</p><p>分享牙痛的也不少，下面这位友友分享的是自己组建的象数</p><p>这位友友还问到了八星</p><p>八星很简单，这本书里写的就挺详细的了，不用再单独看什么书</p><p>就是实战的案例不多，争取下本书多加一些</p><p>还有反馈耳鸣象数的友友</p><p>也有人反馈了飞蚊症、老花眼、口腔溃疡等象数</p><p>这位友友还问到了补角的问题</p><p>补角是可以放在室外的，但是大家一定要注意安全隐患的问题，避免意外掉落等情况</p>',3797)])])}const u=a(h,[["render",o]]);export{q as __pageData,u as default};
